            traineeName={traineeName}
            tasks={tasks}
            onClose={() => setShowTraineeBadge(false)}
          />
        )}

        {scannedTraineeData && (
          <TraineeReportModal 
            data={scannedTraineeData}
            onClose={() => setScannedTraineeData(null)}
