        {(scanningTaskId || scanningSectionId || isSupervisorScanning) && (
          <ScannerModal 
            onScanSuccess={handleScanSuccess} 
            onClose={closeScanner} 
          />
        )}

      </div>
    </>
  );
};

export default App;

import { TaskState, Section } from './types';

const STORAGE_KEY = 'pelastaja_perehdytys_data_v1';

export interface AppData {
  traineeName: string;
  tasks: Record<string, TaskState>;
  customSections?: Section[]; // New field for storing modified structure
  lastUpdated: string;
}

const defaultData: AppData = {
  traineeName: '',
  tasks: {},
  lastUpdated: new Date().toISOString()
};

export const storageService = {
  save: (data: AppData) => {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
    } catch (e) {
      console.error("Tallennus epäonnistui", e);
    }
  },

  load: (): AppData => {
    try {
      const data = localStorage.getItem(STORAGE_KEY);
      return data ? { ...defaultData, ...JSON.parse(data) } : defaultData;
    } catch (e) {
      console.error("Lataus epäonnistui", e);
      return defaultData;
    }
  },

  clear: () => {
    localStorage.removeItem(STORAGE_KEY);
  }
};

import React, { useState } from 'react';
import { Section, TaskItem } from '../types';
import { X, Trash2, Plus, Save, RotateCcw, ChevronRight, ChevronDown } from 'lucide-react';

interface ContentEditorModalProps {
  initialSections: Section[];
  onSave: (newSections: Section[]) => void;
  onReset: () => void;
  onClose: () => void;
}

export const ContentEditorModal: React.FC<ContentEditorModalProps> = ({ initialSections, onSave, onReset, onClose }) => {
  const [sections, setSections] = useState<Section[]>(JSON.parse(JSON.stringify(initialSections)));
  const [expandedSection, setExpandedSection] = useState<string | null>(null);
  const [newItemText, setNewItemText] = useState<string>('');
  const [activeAddSectionId, setActiveAddSectionId] = useState<string | null>(null);

  const toggleSection = (id: string) => {
    setExpandedSection(expandedSection === id ? null : id);
  };

  const handleDeleteItem = (sectionId: string, itemId: string) => {
    if (!confirm("Haluatko varmasti poistaa tämän kohdan?")) return;

    setSections(prev => prev.map(sec => {
      if (sec.id !== sectionId) return sec;
      return {
        ...sec,
        items: sec.items.filter(item => item.id !== itemId)
      };
    }));
  };

  const handleAddItem = (sectionId: string) => {
    if (!newItemText.trim()) return;

    const newItem: TaskItem = {
      id: `custom_${Date.now()}_${Math.floor(Math.random() * 1000)}`,
      label: newItemText.trim()
    };

    setSections(prev => prev.map(sec => {
      if (sec.id !== sectionId) return sec;
      return {
        ...sec,
        items: [...sec.items, newItem]
      };
    }));

    setNewItemText('');
    setActiveAddSectionId(null);
  };

  const handleSave = () => {
    onSave(sections);
    onClose();
  };

  const handleReset = () => {
    if (confirm("Tämä palauttaa lomakkeen alkuperäiseen tilaan ja poistaa kaikki itse lisäämäsi kohdat. Oletko varma?")) {
      onReset();
      onClose();
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl w-full max-w-2xl overflow-hidden shadow-2xl flex flex-col max-h-[90vh] animate-in fade-in zoom-in duration-200">

        {/* Header */}
        <div className="bg-slate-800 p-4 flex justify-between items-center text-white shrink-0">
          <h3 className="font-bold text-lg">Muokkaa lomakkeen sisältöä</h3>
          <button onClick={onClose} className="p-1 hover:bg-slate-700 rounded-full transition-colors">
            <X className="w-6 h-6" />
          </button>
        </div>

        {/* Info Banner */}
        <div className="bg-yellow-50 p-4 border-b border-yellow-100 text-sm text-yellow-800 shrink-0">
          Voit lisätä uusia perehdytyskohtia tai poistaa turhia. Muutokset tallentuvat tälle laitteelle.
        </div>

        {/* Content List */}
        <div className="flex-1 overflow-y-auto p-4 space-y-3 bg-gray-50">
          {sections.map(section => (
            <div key={section.id} className="bg-white rounded-lg border border-gray-200 shadow-sm overflow-hidden">

              {/* Section Header */}
              <button 
                onClick={() => toggleSection(section.id)}
                className="w-full px-4 py-3 flex items-center justify-between hover:bg-gray-50 text-left"
              >
                <div>
                  <span className="font-bold text-slate-800">{section.title}</span>
                  <span className="ml-2 text-xs text-gray-400 bg-gray-100 px-2 py-0.5 rounded-full">
                    {section.items.length} kohtaa
                  </span>
                </div>
                {expandedSection === section.id ? <ChevronDown className="w-5 h-5 text-gray-400" /> : <ChevronRight className="w-5 h-5 text-gray-400" />}
              </button>

              {/* Items List */}
              {expandedSection === section.id && (
                <div className="border-t border-gray-100 divide-y divide-gray-50">
                  {section.items.map(item => (
                    <div key={item.id} className="px-4 py-3 flex items-center justify-between group hover:bg-slate-50">
                      <span className="text-sm text-slate-700">{item.label}</span>
                      <button 
                        onClick={() => handleDeleteItem(section.id, item.id)}
                        className="p-1.5 text-red-300 hover:text-red-600 hover:bg-red-50 rounded transition-colors"
                        title="Poista kohta"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>
                  ))}

                  {/* Add New Item Input */}
                  <div className="p-3 bg-gray-50">
                    {activeAddSectionId === section.id ? (
                      <div className="flex gap-2">
                        <input
                          type="text"
                          value={newItemText}
                          onChange={(e) => setNewItemText(e.target.value)}
                          placeholder="Kirjoita uuden kohdan nimi..."
                          className="flex-1 px-3 py-2 text-sm border rounded focus:ring-2 focus:ring-accent outline-none"
                          autoFocus
                          onKeyDown={(e) => e.key === 'Enter' && handleAddItem(section.id)}
                        />
                        <button 
                          onClick={() => handleAddItem(section.id)}
                          className="px-3 py-2 bg-green-600 text-white rounded text-sm font-bold hover:bg-green-700"
                        >
                          Lisää
                        </button>
                        <button 
                          onClick={() => setActiveAddSectionId(null)}
                          className="px-3 py-2 bg-gray-200 text-gray-600 rounded text-sm hover:bg-gray-300"
                        >
                          Peru
                        </button>
                      </div>
                    ) : (
                      <button 
                        onClick={() => {
                          setActiveAddSectionId(section.id);
                          setNewItemText('');
                        }}
                        className="w-full py-2 border-2 border-dashed border-gray-300 rounded text-gray-500 text-sm font-bold hover:border-accent hover:text-accent hover:bg-white transition-all flex items-center justify-center gap-2"
                      >
                        <Plus className="w-4 h-4" />
                        Lisää uusi kohta
                      </button>
                    )}
                  </div>
                </div>
              )}
            </div>
          ))}
        </div>

        {/* Footer Actions */}
        <div className="p-4 bg-white border-t border-gray-200 flex justify-between items-center shrink-0">
          <button 
            onClick={handleReset}
            className="flex items-center gap-2 text-red-600 hover:text-red-700 text-sm font-bold px-4 py-2 hover:bg-red-50 rounded-lg transition-colors"
          >
            <RotateCcw className="w-4 h-4" />
            Palauta oletukset
          </button>

          <div className="flex gap-3">
            <button 
              onClick={onClose}
              className="px-4 py-2 text-slate-600 hover:bg-gray-100 rounded-lg font-bold transition-colors"
            >
              Peruuta
            </button>
            <button 
              onClick={handleSave}
              className="px-6 py-2 bg-slate-800 text-white rounded-lg font-bold hover:bg-slate-700 shadow-lg flex items-center gap-2"
            >
              <Save className="w-4 h-4" />
              Tallenna muutokset
            </button>
          </div>
        </div>

      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import QRCode from 'qrcode';
import { X, ShieldCheck, UserPen, Lock, KeyRound, Download, ScanLine, Edit, FilePenLine } from 'lucide-react';

interface SupervisorBadgeProps {
  onClose: () => void;
  onScanRequest: () => void;
  onEditContent: () => void;
}

export const SupervisorBadge: React.FC<SupervisorBadgeProps> = ({ onClose, onScanRequest, onEditContent }) => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [error, setError] = useState(false);

  const [name, setName] = useState('');
  const [qrUrl, setQrUrl] = useState<string>('');

  useEffect(() => {
    if (!name.trim()) {
      setQrUrl('');
      return;
    }

    const signaturePayload = JSON.stringify({
      type: 'SUPERVISOR_SIGNATURE',
      name: name.trim(),
      timestamp: Date.now()
    });

    QRCode.toDataURL(signaturePayload, { width: 400, margin: 2 })
      .then((url) => {
        setQrUrl(url);
      })
      .catch((err) => {
        console.error("QR Generation failed", err);
      });
  }, [name]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === '112') {
        setIsAuthenticated(true);
        setError(false);
    } else {
        setError(true);
        setPasswordInput('');
    }
  };

  const handleDownload = () => {
    if (!qrUrl) return;

    // Create a temporary link element
    const link = document.createElement('a');
    link.href = qrUrl;

    // Create a safe filename from the name
    const safeName = name.replace(/[^a-z0-9]/gi, '_').toLowerCase();
    link.download = `perehdytys-qr-${safeName}.png`;

    // Trigger download
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleStartScan = () => {
    onClose();
    onScanRequest();
  };

  const handleStartEdit = () => {
    onClose();
    onEditContent();
  };

  if (!isAuthenticated) {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
        <div className="bg-white rounded-2xl w-full max-w-sm overflow-hidden shadow-2xl animate-in fade-in zoom-in duration-200">
          <div className="bg-slate-800 p-4 flex justify-between items-center text-white">
            <div className="flex items-center gap-2">
              <Lock className="w-5 h-5 text-orange-400" />
              <h3 className="font-bold">Esimieskirjautuminen</h3>
            </div>
            <button onClick={onClose} className="p-1 hover:bg-slate-700 rounded-full transition-colors">
              <X className="w-5 h-5" />
            </button>
          </div>

          <form onSubmit={handleLogin} className="p-6 space-y-4">
            <div>
              <label className="block text-xs font-bold uppercase text-gray-500 mb-2">
                Salasana
              </label>
              <div className="relative">
                <input 
                  type="password" 
                  value={passwordInput}
                  onChange={(e) => setPasswordInput(e.target.value)}
                  className={`w-full pl-10 pr-4 py-2 border-2 rounded-lg outline-none transition-colors ${error ? 'border-red-300 focus:border-red-500' : 'border-slate-200 focus:border-slate-800'}`}
                  autoFocus
                  placeholder="Syötä salasana"
                />
                <KeyRound className="w-5 h-5 text-gray-400 absolute left-3 top-2.5" />
              </div>
              {error && (
                <p className="text-red-500 text-xs mt-2 font-medium">
                  Väärä salasana. Yritä uudelleen.
                </p>
              )}
            </div>

            <button 
              type="submit"
              className="w-full py-3 bg-slate-800 text-white rounded-lg font-bold hover:bg-slate-700 transition-colors shadow-lg shadow-slate-900/20"
            >
              Kirjaudu
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl w-full max-w-sm overflow-hidden shadow-2xl animate-in fade-in zoom-in duration-200">

        <div className="bg-slate-800 p-4 flex justify-between items-center text-white">
          <div className="flex items-center gap-2">
            <ShieldCheck className="w-5 h-5 text-green-400" />
            <h3 className="font-bold">Esimiehen Työkalut</h3>
