          </div>

          {/* Section 2: Scan Trainee */}
          <div className="space-y-4">
             <h4 className="text-sm font-bold uppercase text-slate-500 border-b pb-1">2. Tarkista Pelastaja</h4>
             <button
               onClick={handleStartScan}
               className="w-full py-3 bg-accent hover:bg-sky-600 text-white rounded-xl font-bold transition-colors flex items-center justify-center gap-3 shadow-lg shadow-sky-500/20"
             >
                <ScanLine className="w-5 h-5" />
                Tarkista Pelastajan Passi
             </button>
          </div>

          {/* Section 3: Edit Form */}
          <div className="space-y-4">
             <h4 className="text-sm font-bold uppercase text-slate-500 border-b pb-1">3. Hallinta</h4>
             <button
               onClick={handleStartEdit}
               className="w-full py-3 bg-white border-2 border-slate-200 hover:border-slate-400 text-slate-700 rounded-xl font-bold transition-colors flex items-center justify-center gap-3"
             >
                <FilePenLine className="w-5 h-5" />
                Muokkaa lomakkeen sisältöä
             </button>
          </div>

        </div>

        <button 
          onClick={onClose}
          className="w-full py-4 bg-gray-50 border-t border-gray-100 font-semibold text-slate-600 hover:bg-gray-100 transition-colors"
        >
          Sulje
        </button>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { SECTIONS } from './constants';
import { TaskState, TraineeQrData, Section } from './types';
import { SectionGroup } from './components/SectionGroup';
import { storageService, AppData } from './storage';
import { SupervisorBadge } from './components/SupervisorBadge';
import { ScannerModal } from './components/ScannerModal';
import { TraineeBadge } from './components/TraineeBadge';
import { TraineeReportModal } from './components/TraineeReportModal';
import { CompletionModal } from './components/CompletionModal';
import { CertificateView } from './components/CertificateView';
import { ContentEditorModal } from './components/ContentEditorModal';
import { Printer, Flame, CheckCircle, QrCode, Trash2, UserCheck, Trophy } from 'lucide-react';

const App: React.FC = () => {
  // Data State
  const [traineeName, setTraineeName] = useState('');
  const [tasks, setTasks] = useState<Record<string, TaskState>>({});
  const [sections, setSections] = useState<Section[]>(SECTIONS);

  // UI State
  const [showSupervisorBadge, setShowSupervisorBadge] = useState(false);
  const [showTraineeBadge, setShowTraineeBadge] = useState(false);
  const [showCompletionModal, setShowCompletionModal] = useState(false);
  const [showEditor, setShowEditor] = useState(false);
  const [isPrintingCertificate, setIsPrintingCertificate] = useState(false);

  // Keep track if we've already shown the celebration once per session to avoid annoyance
  const [hasCelebrated, setHasCelebrated] = useState(false);

  // Scan States
  const [scanningTaskId, setScanningTaskId] = useState<string | null>(null);
  const [scanningSectionId, setScanningSectionId] = useState<string | null>(null);
  const [isSupervisorScanning, setIsSupervisorScanning] = useState(false);

  const [scannedTraineeData, setScannedTraineeData] = useState<TraineeQrData | null>(null);

  // Load data on mount
  useEffect(() => {
    const data = storageService.load();
    setTraineeName(data.traineeName);
    setTasks(data.tasks);
    if (data.customSections && data.customSections.length > 0) {
      setSections(data.customSections);
    }
  }, []);

  // Save data on change
  const saveData = (newName: string, newTasks: Record<string, TaskState>, newSections?: Section[]) => {
    const data: AppData = {
      traineeName: newName,
      tasks: newTasks,
      customSections: newSections || sections,
      lastUpdated: new Date().toISOString()
    };
    storageService.save(data);
  };

  const handleNameChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newName = e.target.value;
    setTraineeName(newName);
    saveData(newName, tasks);
  };

  const handleTaskChange = (taskId: string, updates: Partial<TaskState>) => {
    const newTasks = {
      ...tasks,
      [taskId]: {
        ...(tasks[taskId] || { date: '', traineeSigned: false, trainerSigned: false }),
        ...updates
      }
    };
    setTasks(newTasks);
    saveData(traineeName, newTasks);
  };

  const handleUpdateSections = (newSections: Section[]) => {
    setSections(newSections);
    saveData(traineeName, tasks, newSections);
  };

  const handleResetSections = () => {
    setSections(SECTIONS);
    saveData(traineeName, tasks, SECTIONS);
  };

  const handleScanRequest = (taskId: string) => {
    setScanningTaskId(taskId);
  };

  const handleSectionScanRequest = (sectionId: string) => {
    setScanningSectionId(sectionId);
  };

  const handleSupervisorScanRequest = () => {
    setIsSupervisorScanning(true);
  };

  const handleScanSuccess = (data: any) => {
    const today = new Date().toISOString().split('T')[0];

    // Scenario 1: Trainee scanning Supervisor Signature for a SINGLE TASK
    if (scanningTaskId && data.type === 'SUPERVISOR_SIGNATURE' && data.name) {
       handleTaskChange(scanningTaskId, {
         trainerSigned: true,
         trainerName: data.name,
         date: today
       });
       setScanningTaskId(null);
    }
    // Scenario 2: Trainee scanning Supervisor Signature for a WHOLE SECTION
    else if (scanningSectionId && data.type === 'SUPERVISOR_SIGNATURE' && data.name) {
       const section = sections.find(s => s.id === scanningSectionId);
       if (section) {
         const newTasks = { ...tasks };
         section.items.forEach(item => {
           // Update each task in the section
           newTasks[item.id] = {
             ...(newTasks[item.id] || { date: '', traineeSigned: false, trainerSigned: false }),
             trainerSigned: true,
             trainerName: data.name,
             date: today
           };
         });
         setTasks(newTasks);
         saveData(traineeName, newTasks);
       }
       setScanningSectionId(null);
    }
    // Scenario 3: Supervisor scanning Trainee Progress
    else if (isSupervisorScanning && data.type === 'TRAINEE_PROGRESS') {
      setIsSupervisorScanning(false);
      setScannedTraineeData(data);
    }
    // Error / Mismatch handling
    else {
      if ((scanningTaskId || scanningSectionId) && data.type !== 'SUPERVISOR_SIGNATURE') {
         alert("Virhe: Skannasit pelastajan passin. Skannaa esimiehen kuittauskoodi.");
      }
      else if (isSupervisorScanning && data.type !== 'TRAINEE_PROGRESS') {
         alert("Virhe: Skannasit esimiehen koodin. Skannaa pelastajan passi.");
      }
    }
  };

  const closeScanner = () => {
    setScanningTaskId(null);
    setScanningSectionId(null);
    setIsSupervisorScanning(false);
  };

  const handleClearAll = () => {
    if (confirm("Haluatko varmasti tyhjentää koko lomakkeen? Kaikki merkinnät poistetaan. Lomakkeen muokattu rakenne säilyy.")) {
      // Clear storage but keep structure if needed? 
      // User asked to clear form data, usually implies progress.
      // But storageService.clear() wipes everything including customSections.
      // Let's implement a soft clear for data only, or re-save sections.

      const currentSections = sections;
      storageService.clear();

      // Reset state
      setTraineeName('');
      setTasks({});
      setHasCelebrated(false);

      // Restore structure
      setSections(currentSections);
      // Immediately save the structure back so it persists
      const freshData: AppData = {
          traineeName: '',
          tasks: {},
          customSections: currentSections,
          lastUpdated: new Date().toISOString()
      };
      storageService.save(freshData);
    }
  };

  // Standard print (checklist)
  const printForm = () => {
    setIsPrintingCertificate(false);
    // Allow React to update state before printing
    setTimeout(() => window.print(), 100);
  };

  // Certificate print (diploma)
  const printCertificate = () => {
    setIsPrintingCertificate(true);
    setTimeout(() => {
      window.print();
      // Reset after print dialog closes (approximate) or let user switch back manually
      const cleanup = () => setIsPrintingCertificate(false);
      window.addEventListener('afterprint', cleanup, { once: true });
      setTimeout(cleanup, 5000); 
    }, 100);
  };

  // Calculate stats
  const stats = useMemo(() => {
    let total = 0;
    let completed = 0;
    sections.forEach(section => {
      section.items.forEach(item => {
        total++;
        const s = tasks[item.id];
        if (s && s.traineeSigned && s.trainerSigned) {
          completed++;
        }
      });
    });
    return { total, completed, percentage: total === 0 ? 0 : Math.round((completed/total) * 100) };
  }, [tasks, sections]);

  // Check for completion
  useEffect(() => {
    if (stats.percentage === 100 && !hasCelebrated && stats.total > 0) {
      setShowCompletionModal(true);
      setHasCelebrated(true);
    }
  }, [stats.percentage, hasCelebrated, stats.total]);

  // Determine date to show on certificate (today)
  const todayDate = new Date().toLocaleDateString('fi-FI');

  return (
    <>
      {/* CERTIFICATE VIEW (Only visible when printing certificate) */}
      {isPrintingCertificate && (
         <CertificateView traineeName={traineeName} completionDate={todayDate} />
      )}

      {/* MAIN APP VIEW (Hidden when printing certificate) */}
      <div className={`min-h-screen bg-gray-100 print:bg-white pb-12 ${isPrintingCertificate ? 'hidden' : 'block'}`}>

        {/* Header Bar */}
        <header className="bg-primary text-white shadow-md sticky top-0 z-20 print:static print:shadow-none print:bg-white print:text-black">
          <div className="max-w-4xl mx-auto px-4 py-3 flex flex-col sm:flex-row items-center justify-between gap-4">

            {/* Logo & Title */}
            <div className="flex items-center gap-3 w-full sm:w-auto">
              <div className="bg-orange-500 p-2 rounded-lg print:hidden">
                <Flame className="w-6 h-6 text-white" />
              </div>
              <div>
                <h1 className="text-lg font-bold leading-tight">Pelastajan Perehdytys</h1>
                <p className="text-xs text-slate-300 print:hidden">Sähköinen seurantalomake</p>
              </div>
            </div>

            {/* Controls */}
            <div className="flex items-center gap-2 w-full sm:w-auto justify-end no-print overflow-x-auto pb-1 sm:pb-0">

              {stats.percentage === 100 && (
                <button
                  onClick={() => setShowCompletionModal(true)}
                  className="flex items-center gap-1.5 sm:gap-2 bg-yellow-500 hover:bg-yellow-600 text-white px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors shadow-lg animate-pulse font-bold whitespace-nowrap"
                >
                  <Trophy className="w-4 h-4" />
                  <span>Valmis!</span>
                </button>
              )}

              <button
                onClick={() => setShowTraineeBadge(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-800 hover:bg-slate-700 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-700 whitespace-nowrap"
              >
                <UserCheck className="w-4 h-4 text-accent" />
                <span className="sm:hidden">Passi</span>
                <span className="hidden sm:inline">Oma Passi</span>
              </button>

              <div className="w-px h-6 bg-slate-700 mx-0.5 sm:mx-1"></div>

              <button 
                onClick={() => setShowSupervisorBadge(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-800 hover:bg-slate-700 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-700 whitespace-nowrap"
              >
                <QrCode className="w-4 h-4 text-green-400" />
                <span className="sm:hidden">Esimies</span>
                <span className="hidden sm:inline">Esimiestyökalut</span>
              </button>

              <button 
                onClick={printForm}
                className="p-2 bg-slate-800 hover:bg-slate-700 rounded-lg transition-colors text-slate-200"
                title="Tulosta PDF (Lista)"
              >
                <Printer className="w-5 h-5" />
              </button>

              <button 
                onClick={handleClearAll}
                className="p-2 bg-red-900/50 hover:bg-red-900 rounded-lg transition-colors text-red-200 ml-1 sm:ml-2"
                title="Tyhjennä lomake (säilyttää rakenteen)"
              >
                <Trash2 className="w-5 h-5" />
              </button>
            </div>
          </div>
        </header>

        <main className="max-w-4xl mx-auto px-4 py-8 print:py-0 print:px-0">

          {/* Name Input & Intro */}
          <div className="bg-white rounded-lg p-6 shadow-sm border border-gray-200 mb-6 print:border-none print:shadow-none print:p-0">

            <div className="mb-6 no-print">
              <label className="block text-xs font-bold uppercase text-slate-500 mb-2">
                Pelastajan Nimi
              </label>
              <div className="relative">
                <input
                  type="text"
                  value={traineeName}
                  onChange={handleNameChange}
                  placeholder="Kirjoita nimesi tähän..."
                  className="w-full text-lg font-bold text-slate-800 border-b-2 border-slate-200 focus:border-accent outline-none py-2 pl-9 bg-transparent transition-colors placeholder:font-normal placeholder:text-gray-300"
                />
                <UserCheck className="w-6 h-6 text-gray-400 absolute left-0 top-2" />
              </div>
            </div>

            <div className="prose prose-sm max-w-none text-slate-600 mb-2 print:text-xs">
              <p>
                Pelastajan perehdytys alkaa yleistyöajassa viiden päivän ajan. Kaksi työvuoroa (24h) pilkotaan tunneiksi seuraavasti: 
                3 pv x 8h ja 2 pv x 12h, jonka jälkeen pelastaja siirtyy omaan työvuoroonsa ja perehdytys jatkuu siellä seuraavan 
                kahden kuukauden ajan.
              </p>
            </div>

            {/* Print Header */}
            <div className="hidden print:block mb-8 border-b-2 border-black pb-4">
                <span className="text-sm text-gray-500 uppercase">Pelastaja</span>
                <div className="text-2xl font-bold">{traineeName}</div>
            </div>
          </div>

          {/* Sticky Progress Bar */}
          <div className="bg-white/95 backdrop-blur rounded-lg p-4 shadow-sm border border-gray-200 mb-8 flex items-center gap-4 no-print sticky top-20 z-10 transition-shadow">
            <div className={`p-2 rounded-full ${stats.percentage === 100 ? 'bg-green-100' : 'bg-gray-100'}`}>
              <CheckCircle className={`w-6 h-6 ${stats.percentage === 100 ? 'text-green-600' : 'text-gray-400'}`} />
            </div>
            <div className="flex-1">
              <div className="flex justify-between items-end mb-1">
                <span className="font-bold text-slate-700">Edistyminen</span>
                <span className="text-sm font-medium text-accent">{stats.completed} / {stats.total} ({stats.percentage}%)</span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2.5">
                <div 
                  className={`h-2.5 rounded-full transition-all duration-700 ${stats.percentage === 100 ? 'bg-green-500' : 'bg-accent'}`}
                  style={{ width: `${stats.percentage}%` }}
                ></div>
              </div>
            </div>
          </div>

          {/* Form Sections (Using state 'sections' instead of constant 'SECTIONS') */}
          <div className="space-y-4">
            {sections.map(section => (
              <SectionGroup 
                key={section.id} 
                section={section} 
                tasks={tasks} 
                traineeName={traineeName}
                onTaskChange={handleTaskChange}
                onScanRequest={handleScanRequest}
                onSectionScanRequest={handleSectionScanRequest}
              />
            ))}
          </div>

          {/* Print Signature Box (Only for list view) */}
          <div className="hidden print:block mt-8 pt-8 border-t-2 border-black page-break">
            {/* Signatures removed per request for the checklist printout, kept simple */}
            <div className="text-center text-xs text-gray-500">
              Tulostettu: {todayDate}
            </div>
          </div>

        </main>

        {/* Modals */}
        {showSupervisorBadge && (
          <SupervisorBadge 
            onClose={() => setShowSupervisorBadge(false)} 
            onScanRequest={handleSupervisorScanRequest}
            onEditContent={() => setShowEditor(true)}
          />
        )}

        {showEditor && (
          <ContentEditorModal 
            initialSections={sections}
            onSave={handleUpdateSections}
            onReset={handleResetSections}
            onClose={() => setShowEditor(false)}
          />
        )}

        {showTraineeBadge && (
          <TraineeBadge 
            traineeName={traineeName}
            tasks={tasks}
            onClose={() => setShowTraineeBadge(false)}
          />
        )}

        {scannedTraineeData && (
          <TraineeReportModal 
            data={scannedTraineeData}
            onClose={() => setScannedTraineeData(null)}
          />
        )}

        {showCompletionModal && (
          <CompletionModal
            traineeName={traineeName}
            onClose={() => setShowCompletionModal(false)}
            onPrint={printCertificate} 
          />
        )}

        {(scanningTaskId || scanningSectionId || isSupervisorScanning) && (
          <ScannerModal 
            onScanSuccess={handleScanSuccess} 
            onClose={closeScanner} 
          />
        )}

      </div>
    </>
  );
};

export default App;

import React, { useState } from 'react';
import { Section, TaskItem } from '../types';
import { X, Trash2, Plus, Save, RotateCcw, ChevronRight, ChevronDown } from 'lucide-react';

interface ContentEditorModalProps {
  initialSections: Section[];
  onSave: (newSections: Section[]) => void;
  onReset: () => void;
  onClose: () => void;
}

export const ContentEditorModal: React.FC<ContentEditorModalProps> = ({ initialSections, onSave, onReset, onClose }) => {
  const [sections, setSections] = useState<Section[]>(JSON.parse(JSON.stringify(initialSections)));
  const [expandedSection, setExpandedSection] = useState<string | null>(null);
  const [newItemText, setNewItemText] = useState<string>('');
  const [activeAddSectionId, setActiveAddSectionId] = useState<string | null>(null);

  const toggleSection = (id: string) => {
    setExpandedSection(expandedSection === id ? null : id);
  };

  const handleDeleteSection = (sectionId: string) => {
    if (confirm("Haluatko varmasti poistaa koko kategorian ja kaikki sen sisältämät kohdat?")) {
      setSections(prev => prev.filter(s => s.id !== sectionId));
    }
  };

  const handleDeleteItem = (sectionId: string, itemId: string) => {
    if (!confirm("Haluatko varmasti poistaa tämän kohdan?")) return;

    setSections(prev => prev.map(sec => {
      if (sec.id !== sectionId) return sec;
      return {
        ...sec,
        items: sec.items.filter(item => item.id !== itemId)
      };
    }));
  };

  const handleAddItem = (sectionId: string) => {
    if (!newItemText.trim()) return;

    const newItem: TaskItem = {
      id: `custom_${Date.now()}_${Math.floor(Math.random() * 1000)}`,
      label: newItemText.trim()
    };

    setSections(prev => prev.map(sec => {
      if (sec.id !== sectionId) return sec;
      return {
        ...sec,
        items: [...sec.items, newItem]
      };
    }));

    setNewItemText('');
    setActiveAddSectionId(null);
  };

  const handleSave = () => {
    onSave(sections);
    onClose();
  };

  const handleReset = () => {
    if (confirm("Tämä palauttaa lomakkeen alkuperäiseen tilaan ja poistaa kaikki itse lisäämäsi kohdat. Oletko varma?")) {
      onReset();
      onClose();
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl w-full max-w-2xl overflow-hidden shadow-2xl flex flex-col max-h-[90vh] animate-in fade-in zoom-in duration-200">

        {/* Header */}
        <div className="bg-slate-800 p-4 flex justify-between items-center text-white shrink-0">
          <h3 className="font-bold text-lg">Muokkaa lomakkeen sisältöä</h3>
          <button onClick={onClose} className="p-1 hover:bg-slate-700 rounded-full transition-colors">
            <X className="w-6 h-6" />
          </button>
        </div>

        {/* Info Banner */}
        <div className="bg-yellow-50 p-4 border-b border-yellow-100 text-sm text-yellow-800 shrink-0">
          Voit lisätä uusia perehdytyskohtia tai poistaa turhia. Muutokset tallentuvat tälle laitteelle.
        </div>

        {/* Content List */}
        <div className="flex-1 overflow-y-auto p-4 space-y-3 bg-gray-50">
          {sections.length === 0 && (
            <div className="text-center p-8 text-gray-400 italic border-2 border-dashed border-gray-200 rounded-lg">
              Kaikki osiot on poistettu. Palauta oletukset alhaalta.
            </div>
          )}

          {sections.map(section => (
            <div key={section.id} className="bg-white rounded-lg border border-gray-200 shadow-sm overflow-hidden">

              {/* Section Header Row */}
              <div className="flex items-stretch bg-white hover:bg-gray-50 transition-colors border-b border-gray-100 last:border-0">
                <button 
                  onClick={() => toggleSection(section.id)}
                  className="flex-1 px-4 py-3 flex items-center justify-between text-left"
                >
                  <div>
                    <span className="font-bold text-slate-800">{section.title}</span>
                    <span className="ml-2 text-xs text-gray-400 bg-gray-100 px-2 py-0.5 rounded-full">
                      {section.items.length} kohtaa
                    </span>
                  </div>
                  {expandedSection === section.id ? <ChevronDown className="w-5 h-5 text-gray-400" /> : <ChevronRight className="w-5 h-5 text-gray-400" />}
                </button>

                {/* Delete Section Button */}
                <button 
                  onClick={() => handleDeleteSection(section.id)}
                  className="px-4 flex items-center justify-center text-gray-400 hover:text-red-600 hover:bg-red-50 border-l border-gray-100 transition-colors"
                  title="Poista koko kategoria"
                >
                  <Trash2 className="w-5 h-5" />
                </button>
              </div>

              {/* Items List */}
              {expandedSection === section.id && (
                <div className="border-t border-gray-100 divide-y divide-gray-50 bg-gray-50/50">
                  {section.items.map(item => (
                    <div key={item.id} className="px-4 py-3 flex items-center justify-between group hover:bg-slate-50 pl-8 border-l-4 border-l-transparent hover:border-l-accent transition-all">
                      <span className="text-sm text-slate-700">{item.label}</span>
                      <button 
