                  <div className="p-3 bg-gray-50 pl-8">
                    {activeAddSectionId === section.id ? (
                      <div className="flex gap-2">
                        <input
                          type="text"
                          value={newItemText}
                          onChange={(e) => setNewItemText(e.target.value)}
