import React, { useState } from 'react';
import { Section, TaskItem } from '../types';
import { X, Trash2, Plus, Save, RotateCcw, ChevronRight, ChevronDown, Pencil, Check, AlignLeft } from 'lucide-react';
import { DEFAULT_INTRO_TEXT } from '../constants';

interface ContentEditorModalProps {
  initialSections: Section[];
  initialIntroText: string;
  onSave: (newSections: Section[], newIntroText: string) => void;
  onReset: () => void;
  onClose: () => void;
}

// Helper type to track what is being edited
type EditTarget = 
  | { type: 'section_title'; id: string }
  | { type: 'item_label'; sectionId: string; itemId: string }
  | null;

export const ContentEditorModal: React.FC<ContentEditorModalProps> = ({ initialSections, initialIntroText, onSave, onReset, onClose }) => {
  const [sections, setSections] = useState<Section[]>(JSON.parse(JSON.stringify(initialSections)));
  const [introText, setIntroText] = useState(initialIntroText);

  const [expandedSection, setExpandedSection] = useState<string | null>(null);

  // State for adding new items
  const [newItemText, setNewItemText] = useState<string>('');
  const [activeAddSectionId, setActiveAddSectionId] = useState<string | null>(null);

  // State for adding new sections
  const [isAddingSection, setIsAddingSection] = useState(false);
  const [newSectionTitle, setNewSectionTitle] = useState('');

  // State for editing existing text
  const [editTarget, setEditTarget] = useState<EditTarget>(null);
  const [editText, setEditText] = useState('');

  const toggleSection = (id: string) => {
    // Don't toggle if we are editing the title
    if (editTarget?.type === 'section_title' && editTarget.id === id) return;
    setExpandedSection(expandedSection === id ? null : id);
  };

  // --- DELETE LOGIC ---

  const handleDeleteSection = (sectionId: string) => {
    if (confirm("Haluatko varmasti poistaa koko kategorian ja kaikki sen sisältämät kohdat?")) {
      setSections(prev => prev.filter(s => s.id !== sectionId));
    }
  };

  const handleDeleteItem = (sectionId: string, itemId: string) => {
    if (!confirm("Haluatko varmasti poistaa tämän kohdan?")) return;

    setSections(prev => prev.map(sec => {
      if (sec.id !== sectionId) return sec;
      return {
        ...sec,
        items: sec.items.filter(item => item.id !== itemId)
      };
    }));
  };

  // --- ADD LOGIC ---

  const handleAddItem = (sectionId: string) => {
    if (!newItemText.trim()) return;

    const newItem: TaskItem = {
      id: `custom_item_${Date.now()}_${Math.floor(Math.random() * 1000)}`,
      label: newItemText.trim()
    };

    setSections(prev => prev.map(sec => {
      if (sec.id !== sectionId) return sec;
      return {
        ...sec,
        items: [...sec.items, newItem]
      };
    }));

    setNewItemText('');
    setActiveAddSectionId(null);
  };

  const handleAddSection = () => {
    if (!newSectionTitle.trim()) return;

    const newSection: Section = {
      id: `custom_section_${Date.now()}`,
      title: newSectionTitle.trim(),
      items: []
    };

    setSections(prev => [...prev, newSection]);
    setNewSectionTitle('');
    setIsAddingSection(false);
    // Automatically expand the new section
    setExpandedSection(newSection.id);
  };

  // --- EDIT LOGIC ---

  const startEdit = (target: EditTarget, currentText: string) => {
    setEditTarget(target);
    setEditText(currentText);
  };

  const saveEdit = () => {
    if (!editTarget || !editText.trim()) {
      setEditTarget(null);
      return;
    }

    if (editTarget.type === 'section_title') {
      setSections(prev => prev.map(sec => 
        sec.id === editTarget.id ? { ...sec, title: editText.trim() } : sec
      ));
    } else if (editTarget.type === 'item_label') {
      setSections(prev => prev.map(sec => {
        if (sec.id !== editTarget.sectionId) return sec;
        return {
          ...sec,
          items: sec.items.map(item => 
            item.id === editTarget.itemId ? { ...item, label: editText.trim() } : item
          )
        };
      }));
    }

    setEditTarget(null);
    setEditText('');
  };

  const cancelEdit = () => {
    setEditTarget(null);
    setEditText('');
  };

  // --- GENERAL ---

  const handleSave = () => {
    onSave(sections, introText);
    onClose();
  };

  const handleReset = () => {
    if (confirm("Tämä palauttaa lomakkeen alkuperäiseen tilaan (sisältö ja tekstit). Oletko varma?")) {
      setIntroText(DEFAULT_INTRO_TEXT);
      onReset();
      onClose();
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl w-full max-w-2xl overflow-hidden shadow-2xl flex flex-col max-h-[90vh] animate-in fade-in zoom-in duration-200">

        {/* Header */}
        <div className="bg-slate-800 p-4 flex justify-between items-center text-white shrink-0">
          <h3 className="font-bold text-lg">Muokkaa lomakkeen sisältöä</h3>
          <button onClick={onClose} className="p-1 hover:bg-slate-700 rounded-full transition-colors">
            <X className="w-6 h-6" />
          </button>
        </div>

        {/* Info Banner */}
        <div className="bg-yellow-50 p-4 border-b border-yellow-100 text-sm text-yellow-800 shrink-0">
          Voit muokata johdantotekstiä ja perehdytyskohtia. Muutokset tallentuvat tälle laitteelle.
        </div>

        {/* Content List */}
        <div className="flex-1 overflow-y-auto p-4 space-y-6 bg-gray-50">

          {/* Intro Text Editor */}
          <div className="bg-white rounded-lg border border-gray-200 shadow-sm p-4">
            <h4 className="flex items-center gap-2 font-bold text-slate-700 mb-2">
              <AlignLeft className="w-4 h-4" />
              Yleinen esittelyteksti (nimen alla)
            </h4>
            <textarea 
              value={introText}
              onChange={(e) => setIntroText(e.target.value)}
              className="w-full h-32 p-3 text-sm border border-gray-300 rounded focus:ring-2 focus:ring-accent outline-none resize-y"
              placeholder="Kirjoita ohjeistus tähän..."
            />
            <div className="text-xs text-gray-400 mt-1">Tämä teksti näkyy pelastajan nimen alla heti lomakkeen alussa.</div>
          </div>

          <hr className="border-gray-200" />

          <div>
            <h4 className="font-bold text-slate-700 mb-3 px-1">Lomakkeen osiot</h4>
            {sections.length === 0 && (
              <div className="text-center p-8 text-gray-400 italic border-2 border-dashed border-gray-200 rounded-lg">
                Ei kategorioita. Lisää uusi kategoria alta tai palauta oletukset.
              </div>
            )}

            <div className="space-y-3">
              {sections.map(section => (
                <div key={section.id} className="bg-white rounded-lg border border-gray-200 shadow-sm overflow-hidden">

                  {/* Section Header Row */}
                  <div className="flex items-stretch bg-white hover:bg-gray-50 transition-colors border-b border-gray-100 last:border-0 min-h-[50px]">

                    {/* Editing Title Mode */}
                    {editTarget?.type === 'section_title' && editTarget.id === section.id ? (
                      <div className="flex-1 px-4 py-2 flex items-center gap-2 bg-blue-50">
                        <input 
                          type="text" 
                          value={editText}
                          onChange={(e) => setEditText(e.target.value)}
                          className="flex-1 px-2 py-1 text-sm border border-blue-300 rounded focus:outline-none focus:ring-2 focus:ring-blue-500"
                          autoFocus
                          onKeyDown={(e) => {
                            if (e.key === 'Enter') saveEdit();
                            if (e.key === 'Escape') cancelEdit();
                          }}
                        />
                        <button onClick={saveEdit} className="p-1 bg-green-500 text-white rounded hover:bg-green-600"><Check className="w-4 h-4" /></button>
                        <button onClick={cancelEdit} className="p-1 bg-gray-400 text-white rounded hover:bg-gray-500"><X className="w-4 h-4" /></button>
                      </div>
                    ) : (
                      // Display Title Mode
                      <button 
                        onClick={() => toggleSection(section.id)}
                        className="flex-1 px-4 py-3 flex items-center justify-between text-left group"
                      >
                        <div className="flex items-center gap-3">
                          <div>
                            <span className="font-bold text-slate-800">{section.title}</span>
                            <span className="ml-2 text-xs text-gray-400 bg-gray-100 px-2 py-0.5 rounded-full">
                              {section.items.length}
                            </span>
                          </div>
                          <div 
                            onClick={(e) => {
                              e.stopPropagation();
                              startEdit({ type: 'section_title', id: section.id }, section.title);
                            }}
                            className="p-1.5 text-gray-300 hover:text-blue-500 hover:bg-blue-50 rounded opacity-0 group-hover:opacity-100 transition-all"
                            title="Muokkaa otsikkoa"
                          >
                            <Pencil className="w-3.5 h-3.5" />
                          </div>
                        </div>
                        {expandedSection === section.id ? <ChevronDown className="w-5 h-5 text-gray-400" /> : <ChevronRight className="w-5 h-5 text-gray-400" />}
                      </button>
                    )}

                    {/* Delete Section Button */}
                    {(!editTarget || editTarget.type !== 'section_title' || editTarget.id !== section.id) && (
                      <button 
                        onClick={() => handleDeleteSection(section.id)}
                        className="px-4 flex items-center justify-center text-gray-400 hover:text-red-600 hover:bg-red-50 border-l border-gray-100 transition-colors"
                        title="Poista koko kategoria"
                      >
                        <Trash2 className="w-5 h-5" />
                      </button>
                    )}
                  </div>

                  {/* Items List */}
                  {expandedSection === section.id && (
                    <div className="border-t border-gray-100 divide-y divide-gray-50 bg-gray-50/50">
                      {section.items.map(item => (
                        <div key={item.id} className="px-4 py-3 flex items-center justify-between group hover:bg-slate-50 pl-8 border-l-4 border-l-transparent hover:border-l-accent transition-all min-h-[44px]">

                          {/* Editing Item Mode */}
                          {editTarget?.type === 'item_label' && editTarget.itemId === item.id ? (
                            <div className="flex-1 flex items-center gap-2">
                              <input 
                                type="text" 
                                value={editText}
                                onChange={(e) => setEditText(e.target.value)}
                                className="flex-1 px-2 py-1 text-sm border border-blue-300 rounded focus:outline-none focus:ring-2 focus:ring-blue-500"
                                autoFocus
                                onKeyDown={(e) => {
                                  if (e.key === 'Enter') saveEdit();
                                  if (e.key === 'Escape') cancelEdit();
                                }}
                              />
                              <button onClick={saveEdit} className="p-1 bg-green-500 text-white rounded hover:bg-green-600"><Check className="w-4 h-4" /></button>
                              <button onClick={cancelEdit} className="p-1 bg-gray-400 text-white rounded hover:bg-gray-500"><X className="w-4 h-4" /></button>
                            </div>
                          ) : (
                            // Display Item Mode
                            <>
                              <div className="flex items-center gap-2 flex-1">
                                <span className="text-sm text-slate-700">{item.label}</span>
                                <button 
                                  onClick={() => startEdit({ type: 'item_label', sectionId: section.id, itemId: item.id }, item.label)}
                                  className="p-1 text-gray-300 hover:text-blue-500 hover:bg-blue-50 rounded opacity-0 group-hover:opacity-100 transition-all"
                                  title="Muokkaa tekstiä"
                                >
                                  <Pencil className="w-3 h-3" />
                                </button>
                              </div>

                              <button 
                                onClick={() => handleDeleteItem(section.id, item.id)}
                                className="p-1.5 text-red-300 hover:text-red-600 hover:bg-red-50 rounded transition-colors ml-2"
                                title="Poista kohta"
                              >
                                <Trash2 className="w-4 h-4" />
                              </button>
                            </>
                          )}
                        </div>
                      ))}

                      {/* Add New Item Input */}
                      <div className="p-3 bg-gray-50 pl-8">
                        {activeAddSectionId === section.id ? (
                          <div className="flex gap-2">
                            <input
                              type="text"
                              value={newItemText}
                              onChange={(e) => setNewItemText(e.target.value)}
                              placeholder="Kirjoita uuden kohdan nimi..."
                              className="flex-1 px-3 py-2 text-sm border rounded focus:ring-2 focus:ring-accent outline-none"
                              autoFocus
                              onKeyDown={(e) => e.key === 'Enter' && handleAddItem(section.id)}
                            />
                            <button 
                              onClick={() => handleAddItem(section.id)}
                              className="px-3 py-2 bg-green-600 text-white rounded text-sm font-bold hover:bg-green-700"
                            >
                              Lisää
                            </button>
                            <button 
                              onClick={() => setActiveAddSectionId(null)}
                              className="px-3 py-2 bg-gray-200 text-gray-600 rounded text-sm hover:bg-gray-300"
                            >
                              Peru
                            </button>
                          </div>
                        ) : (
                          <button 
                            onClick={() => {
                              setActiveAddSectionId(section.id);
                              setNewItemText('');
                            }}
                            className="w-full py-2 border-2 border-dashed border-gray-300 rounded text-gray-500 text-sm font-bold hover:border-accent hover:text-accent hover:bg-white transition-all flex items-center justify-center gap-2"
                          >
                            <Plus className="w-4 h-4" />
                            Lisää uusi kohta
                          </button>
                        )}
                      </div>
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>

          {/* ADD NEW SECTION BLOCK */}
          <div className="mt-6 border-t pt-4">
             {isAddingSection ? (
               <div className="bg-white p-4 rounded-lg border-2 border-accent shadow-sm">
                  <h4 className="text-sm font-bold text-slate-700 mb-2">Uusi Kategoria</h4>
                  <div className="flex gap-2">
                    <input
                      type="text"
                      value={newSectionTitle}
                      onChange={(e) => setNewSectionTitle(e.target.value)}
                      placeholder="Esim. Erikoiskalusto..."
                      className="flex-1 px-3 py-2 border rounded focus:ring-2 focus:ring-accent outline-none"
                      autoFocus
                      onKeyDown={(e) => e.key === 'Enter' && handleAddSection()}
                    />
                    <button 
                      onClick={handleAddSection}
                      className="px-4 py-2 bg-accent text-white rounded font-bold hover:bg-sky-600"
                    >
                      Luo
                    </button>
                    <button 
                      onClick={() => setIsAddingSection(false)}
                      className="px-4 py-2 bg-gray-200 text-gray-600 rounded font-bold hover:bg-gray-300"
                    >
                      Peru
                    </button>
                  </div>
               </div>
             ) : (
                <button
                  onClick={() => {
                    setIsAddingSection(true);
                    setNewSectionTitle('');
                  }}
                  className="w-full py-3 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-lg border border-slate-300 border-dashed font-bold flex items-center justify-center gap-2 transition-colors"
                >
                  <Plus className="w-5 h-5" />
                  Lisää uusi kategoria
                </button>
             )}
          </div>

        </div>

        {/* Footer Actions */}
        <div className="p-4 bg-white border-t border-gray-200 flex justify-between items-center shrink-0">
          <button 
            onClick={handleReset}
            className="flex items-center gap-2 text-red-600 hover:text-red-700 text-sm font-bold px-4 py-2 hover:bg-red-50 rounded-lg transition-colors"
          >
            <RotateCcw className="w-4 h-4" />
            Palauta oletukset
          </button>

          <div className="flex gap-3">
            <button 
              onClick={onClose}
              className="px-4 py-2 text-slate-600 hover:bg-gray-100 rounded-lg font-bold transition-colors"
            >
              Peruuta
            </button>
            <button 
              onClick={handleSave}
              className="px-6 py-2 bg-slate-800 text-white rounded-lg font-bold hover:bg-slate-700 shadow-lg flex items-center gap-2"
            >
              <Save className="w-4 h-4" />
              Tallenna muutokset
            </button>
          </div>
        </div>

      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { SECTIONS, DEFAULT_INTRO_TEXT, DEFAULT_ORG_SETTINGS } from './constants';
import { TaskState, TraineeQrData, Section, OrganizationSettings } from './types';
import { SectionGroup } from './components/SectionGroup';
import { storageService, AppData } from './storage';
import { SupervisorBadge } from './components/SupervisorBadge';
import { ScannerModal } from './components/ScannerModal';
import { TraineeBadge } from './components/TraineeBadge';
import { TraineeReportModal } from './components/TraineeReportModal';
import { CompletionModal } from './components/CompletionModal';
import { CertificateView } from './components/CertificateView';
import { ContentEditorModal } from './components/ContentEditorModal';
import { UserGuideModal } from './components/UserGuideModal';
import { Printer, Flame, CheckCircle, QrCode, Trash2, UserCheck, Trophy, CircleHelp, Building2, MapPin, FileText } from 'lucide-react';

const App: React.FC = () => {
  // Data State
  const [traineeName, setTraineeName] = useState('');
  const [tasks, setTasks] = useState<Record<string, TaskState>>({});
  const [sections, setSections] = useState<Section[]>(SECTIONS);
  const [introText, setIntroText] = useState(DEFAULT_INTRO_TEXT);
  const [orgSettings, setOrgSettings] = useState<OrganizationSettings>(DEFAULT_ORG_SETTINGS);

  // UI State
  const [showSupervisorBadge, setShowSupervisorBadge] = useState(false);
  const [showTraineeBadge, setShowTraineeBadge] = useState(false);
  const [showCompletionModal, setShowCompletionModal] = useState(false);
  const [showEditor, setShowEditor] = useState(false);
  const [showUserGuide, setShowUserGuide] = useState(false);
  const [isPrintingCertificate, setIsPrintingCertificate] = useState(false);

  // Keep track if we've already shown the celebration once per session to avoid annoyance
  const [hasCelebrated, setHasCelebrated] = useState(false);

  // Scan States
  const [scanningTaskId, setScanningTaskId] = useState<string | null>(null);
  const [scanningSectionId, setScanningSectionId] = useState<string | null>(null);
  const [isSupervisorScanning, setIsSupervisorScanning] = useState(false);

  const [scannedTraineeData, setScannedTraineeData] = useState<TraineeQrData | null>(null);

  // Load data on mount
  useEffect(() => {
    const data = storageService.load();
    setTraineeName(data.traineeName);
    setTasks(data.tasks);
    if (data.customSections && data.customSections.length > 0) {
      setSections(data.customSections);
    }
    if (data.introText) {
      setIntroText(data.introText);
    }
    if (data.organizationSettings) {
      setOrgSettings(data.organizationSettings);
    }
  }, []);

  // Save data on change
  const saveData = (
    newName: string, 
    newTasks: Record<string, TaskState>, 
    newSections?: Section[], 
    newIntroText?: string,
    newOrgSettings?: OrganizationSettings
  ) => {
    const data: AppData = {
      traineeName: newName,
      tasks: newTasks,
      customSections: newSections || sections,
      introText: newIntroText || introText,
      organizationSettings: newOrgSettings || orgSettings,
      lastUpdated: new Date().toISOString()
    };
    storageService.save(data);
  };

  const handleNameChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newName = e.target.value;
    setTraineeName(newName);
    saveData(newName, tasks);
  };

  const handleOrgSettingChange = (field: keyof OrganizationSettings, value: string) => {
    const newSettings = { ...orgSettings, [field]: value };
    setOrgSettings(newSettings);
    saveData(traineeName, tasks, sections, introText, newSettings);
  };

  const handleTaskChange = (taskId: string, updates: Partial<TaskState>) => {
    const newTasks = {
      ...tasks,
      [taskId]: {
        ...(tasks[taskId] || { date: '', traineeSigned: false, trainerSigned: false }),
        ...updates
      }
    };
    setTasks(newTasks);
    saveData(traineeName, newTasks);
  };

  const handleUpdateContent = (newSections: Section[], newIntroText: string) => {
    setSections(newSections);
    setIntroText(newIntroText);
    // Don't update orgSettings here, as they are now handled by the trainee in the main view
    saveData(traineeName, tasks, newSections, newIntroText, orgSettings);
  };

  const handleResetContent = () => {
    setSections(SECTIONS);
    setIntroText(DEFAULT_INTRO_TEXT);
    setOrgSettings(DEFAULT_ORG_SETTINGS);
    saveData(traineeName, tasks, SECTIONS, DEFAULT_INTRO_TEXT, DEFAULT_ORG_SETTINGS);
  };

  const handleScanRequest = (taskId: string) => {
    setScanningTaskId(taskId);
  };

  const handleSectionScanRequest = (sectionId: string) => {
    setScanningSectionId(sectionId);
  };

  const handleSupervisorScanRequest = () => {
    setIsSupervisorScanning(true);
  };

  const handleScanSuccess = (data: any) => {
    const today = new Date().toISOString().split('T')[0];

    // Scenario 1: Trainee scanning Supervisor Signature for a SINGLE TASK
    if (scanningTaskId && data.type === 'SUPERVISOR_SIGNATURE' && data.name) {
       handleTaskChange(scanningTaskId, {
         trainerSigned: true,
         trainerName: data.name,
         date: today
       });
       setScanningTaskId(null);
    }
    // Scenario 2: Trainee scanning Supervisor Signature for a WHOLE SECTION
    else if (scanningSectionId && data.type === 'SUPERVISOR_SIGNATURE' && data.name) {
       const section = sections.find(s => s.id === scanningSectionId);
       if (section) {
         const newTasks = { ...tasks };
         section.items.forEach(item => {
           // Update each task in the section
           newTasks[item.id] = {
             ...(newTasks[item.id] || { date: '', traineeSigned: false, trainerSigned: false }),
             trainerSigned: true,
             trainerName: data.name,
             date: today
           };
         });
         setTasks(newTasks);
         saveData(traineeName, newTasks);
       }
       setScanningSectionId(null);
    }
    // Scenario 3: Supervisor scanning Trainee Progress
    else if (isSupervisorScanning && data.type === 'TRAINEE_PROGRESS') {
      setIsSupervisorScanning(false);
      setScannedTraineeData(data);
    }
    // Error / Mismatch handling
    else {
      if ((scanningTaskId || scanningSectionId) && data.type !== 'SUPERVISOR_SIGNATURE') {
         alert("Virhe: Skannasit pelastajan passin. Skannaa esimiehen kuittauskoodi.");
      }
      else if (isSupervisorScanning && data.type !== 'TRAINEE_PROGRESS') {
         alert("Virhe: Skannasit esimiehen koodin. Skannaa pelastajan passi.");
      }
    }
  };

  const closeScanner = () => {
    setScanningTaskId(null);
    setScanningSectionId(null);
    setIsSupervisorScanning(false);
  };

  const handleClearAll = () => {
    if (confirm("Haluatko varmasti tyhjentää koko lomakkeen? Kaikki merkinnät poistetaan. Lomakkeen muokattu rakenne säilyy.")) {
      const currentSections = sections;
      const currentIntro = introText;
      const currentOrg = orgSettings;
      storageService.clear();

      // Reset state
      setTraineeName('');
      setTasks({});
      setHasCelebrated(false);

      // Restore structure
      setSections(currentSections);
      setIntroText(currentIntro);
      setOrgSettings(currentOrg);

      // Immediately save the structure back so it persists
      const freshData: AppData = {
          traineeName: '',
          tasks: {},
          customSections: currentSections,
          introText: currentIntro,
          organizationSettings: currentOrg,
          lastUpdated: new Date().toISOString()
      };
      storageService.save(freshData);
    }
  };

  // Standard print (checklist)
  const printForm = () => {
    setIsPrintingCertificate(false);
    // Allow React to update state before printing
    setTimeout(() => window.print(), 100);
  };

  // Certificate print (diploma)
  const printCertificate = () => {
    setIsPrintingCertificate(true);
    setTimeout(() => {
      window.print();
      // Reset after print dialog closes (approximate) or let user switch back manually
      const cleanup = () => setIsPrintingCertificate(false);
      window.addEventListener('afterprint', cleanup, { once: true });
      setTimeout(cleanup, 5000); 
    }, 100);
  };

  // Calculate stats
  const stats = useMemo(() => {
    let total = 0;
    let completed = 0;
    sections.forEach(section => {
      section.items.forEach(item => {
        total++;
        const s = tasks[item.id];
        if (s && s.traineeSigned && s.trainerSigned) {
          completed++;
        }
      });
    });
    return { total, completed, percentage: total === 0 ? 0 : Math.round((completed/total) * 100) };
  }, [tasks, sections]);

  // Check for completion
  useEffect(() => {
    if (stats.percentage === 100 && !hasCelebrated && stats.total > 0) {
      setShowCompletionModal(true);
      setHasCelebrated(true);
    }
  }, [stats.percentage, hasCelebrated, stats.total]);

  // Determine date to show on certificate (today)
  const todayDate = new Date().toLocaleDateString('fi-FI');

  return (
    <>
      {/* CERTIFICATE VIEW (Only visible when printing certificate) */}
      {isPrintingCertificate && (
         <CertificateView 
           traineeName={traineeName} 
           completionDate={todayDate}
           orgSettings={orgSettings} 
         />
      )}

      {/* MAIN APP VIEW (Hidden when printing certificate) */}
      <div className={`min-h-screen bg-gray-100 print:bg-white pb-12 ${isPrintingCertificate ? 'hidden' : 'block'}`}>

        {/* Header Bar */}
        <header className="bg-primary text-white shadow-md sticky top-0 z-20 print:static print:shadow-none print:bg-white print:text-black">
          <div className="max-w-4xl mx-auto px-4 py-3 flex flex-col sm:flex-row items-center justify-between gap-4">

            {/* Logo & Title */}
            <div className="flex items-center gap-3 w-full sm:w-auto">
              <div className="bg-orange-500 p-2 rounded-lg print:hidden">
                <Flame className="w-6 h-6 text-white" />
              </div>
              <div>
                <h1 className="text-lg font-bold leading-tight">Pelastajan Perehdytys</h1>
                <p className="text-xs text-slate-300 print:hidden">Sähköinen seurantalomake</p>
              </div>
            </div>

            {/* Controls */}
            <div className="flex items-center gap-2 w-full sm:w-auto justify-end no-print overflow-x-auto pb-1 sm:pb-0">

              <button
                onClick={() => setShowUserGuide(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-700 hover:bg-slate-600 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-600 whitespace-nowrap mr-2"
                title="Käyttöohjeet"
              >
                <CircleHelp className="w-4 h-4 text-sky-300" />
                <span className="hidden sm:inline">Ohjeet</span>
              </button>

              {stats.percentage === 100 && (
                <button
                  onClick={() => setShowCompletionModal(true)}
                  className="flex items-center gap-1.5 sm:gap-2 bg-yellow-500 hover:bg-yellow-600 text-white px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors shadow-lg animate-pulse font-bold whitespace-nowrap"
                >
                  <Trophy className="w-4 h-4" />
                  <span>Valmis!</span>
                </button>
              )}

              <button
                onClick={() => setShowTraineeBadge(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-800 hover:bg-slate-700 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-700 whitespace-nowrap"
              >
                <UserCheck className="w-4 h-4 text-accent" />
                <span className="sm:hidden">Passi</span>
                <span className="hidden sm:inline">Oma Passi</span>
              </button>

              <div className="w-px h-6 bg-slate-700 mx-0.5 sm:mx-1"></div>

              <button 
                onClick={() => setShowSupervisorBadge(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-800 hover:bg-slate-700 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-700 whitespace-nowrap"
              >
                <QrCode className="w-4 h-4 text-green-400" />
                <span className="sm:hidden">Esimies</span>
                <span className="hidden sm:inline">Esimiestyökalut</span>
              </button>

              <button 
                onClick={printForm}
                className="p-2 bg-slate-800 hover:bg-slate-700 rounded-lg transition-colors text-slate-200"
                title="Tulosta PDF (Lista)"
              >
                <Printer className="w-5 h-5" />
              </button>

              <button 
                onClick={handleClearAll}
                className="p-2 bg-red-900/50 hover:bg-red-900 rounded-lg transition-colors text-red-200 ml-1 sm:ml-2"
                title="Tyhjennä lomake (säilyttää rakenteen)"
              >
                <Trash2 className="w-5 h-5" />
              </button>
            </div>
          </div>
        </header>

        <main className="max-w-4xl mx-auto px-4 py-8 print:py-0 print:px-0">

          {/* Name Input & Intro */}
          <div className="bg-white rounded-lg p-6 shadow-sm border border-gray-200 mb-6 print:border-none print:shadow-none print:p-0">

            <div className="mb-6 no-print">
              <label className="block text-xs font-bold uppercase text-slate-500 mb-2">
                Pelastajan Nimi
              </label>
              <div className="relative">
                <input
                  type="text"
                  value={traineeName}
                  onChange={handleNameChange}
                  placeholder="Kirjoita nimesi tähän..."
                  className="w-full text-lg font-bold text-slate-800 border-b-2 border-slate-200 focus:border-accent outline-none py-2 pl-9 bg-transparent transition-colors placeholder:font-normal placeholder:text-gray-300"
                />
                <UserCheck className="w-6 h-6 text-gray-400 absolute left-0 top-2" />
              </div>
            </div>

            {/* Organization Settings Input for Trainee */}
            <div className="mt-4 p-4 bg-gray-50 rounded-lg border border-gray-200 no-print mb-6">
              <h3 className="text-sm font-bold text-gray-500 uppercase mb-3 flex items-center gap-2">
                <FileText className="w-4 h-4" />
                Todistuksen tiedot
              </h3>
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                <div>
                   <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Organisaatio</label>
                   <div className="relative">
                     <input 
                       type="text" 
                       value={orgSettings.name}
                       onChange={(e) => handleOrgSettingChange('name', e.target.value)}
                       className="w-full pl-7 px-3 py-2 text-sm border border-gray-300 rounded focus:ring-1 focus:ring-accent outline-none bg-white"
                       placeholder="Esim. Hyvinvointialue"
                     />
                     <Building2 className="w-3.5 h-3.5 text-gray-400 absolute left-2.5 top-2.5" />
                   </div>
                </div>
                <div>
                   <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Yksikkö</label>
                   <input 
                     type="text" 
                     value={orgSettings.subtitle}
                     onChange={(e) => handleOrgSettingChange('subtitle', e.target.value)}
                     className="w-full px-3 py-2 text-sm border border-gray-300 rounded focus:ring-1 focus:ring-accent outline-none bg-white"
                     placeholder="Esim. Pelastustoimi"
                   />
                </div>
                <div>
                   <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Paikkakunta</label>
                   <div className="relative">
                     <input 
                       type="text" 
                       value={orgSettings.city}
                       onChange={(e) => handleOrgSettingChange('city', e.target.value)}
                       className="w-full pl-7 px-3 py-2 text-sm border border-gray-300 rounded focus:ring-1 focus:ring-accent outline-none bg-white"
                       placeholder="Esim. Helsinki"
                     />
                     <MapPin className="w-3.5 h-3.5 text-gray-400 absolute left-2.5 top-2.5" />
                   </div>
                </div>
              </div>
            </div>

            <div className="prose prose-sm max-w-none text-slate-600 mb-2 print:text-xs whitespace-pre-line">
              {introText}
            </div>

            {/* Print Header */}
            <div className="hidden print:block mb-8 border-b-2 border-black pb-4">
                <span className="text-sm text-gray-500 uppercase">Pelastaja</span>
                <div className="text-2xl font-bold">{traineeName}</div>
                <div className="mt-2 text-xs text-gray-500">
                  {orgSettings.name} - {orgSettings.subtitle}
                </div>
            </div>
          </div>

          {/* Sticky Progress Bar */}
          <div className="bg-white/95 backdrop-blur rounded-lg p-4 shadow-sm border border-gray-200 mb-8 flex items-center gap-4 no-print sticky top-20 z-10 transition-shadow">
            <div className={`p-2 rounded-full ${stats.percentage === 100 ? 'bg-green-100' : 'bg-gray-100'}`}>
              <CheckCircle className={`w-6 h-6 ${stats.percentage === 100 ? 'text-green-600' : 'text-gray-400'}`} />
            </div>
            <div className="flex-1">
              <div className="flex justify-between items-end mb-1">
                <span className="font-bold text-slate-700">Edistyminen</span>
                <span className="text-sm font-medium text-accent">{stats.completed} / {stats.total} ({stats.percentage}%)</span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2.5">
                <div 
                  className={`h-2.5 rounded-full transition-all duration-700 ${stats.percentage === 100 ? 'bg-green-500' : 'bg-accent'}`}
                  style={{ width: `${stats.percentage}%` }}
                ></div>
              </div>
            </div>
          </div>

          {/* Form Sections (Using state 'sections' instead of constant 'SECTIONS') */}
          <div className="space-y-4">
            {sections.map(section => (
              <SectionGroup 
                key={section.id} 
                section={section} 
                tasks={tasks} 
                traineeName={traineeName}
                onTaskChange={handleTaskChange}
                onScanRequest={handleScanRequest}
                onSectionScanRequest={handleSectionScanRequest}
              />
            ))}
          </div>

          {/* Print Signature Box (Only for list view) */}
          <div className="hidden print:block mt-8 pt-8 border-t-2 border-black page-break">
            {/* Signatures removed per request for the checklist printout, kept simple */}
            <div className="text-center text-xs text-gray-500">
              Tulostettu: {todayDate} - {orgSettings.city}
            </div>
          </div>

        </main>

        {/* Modals */}
        {showSupervisorBadge && (
          <SupervisorBadge 
            onClose={() => setShowSupervisorBadge(false)} 
            onScanRequest={handleSupervisorScanRequest}
            onEditContent={() => setShowEditor(true)}
          />
        )}

        {showEditor && (
          <ContentEditorModal 
            initialSections={sections}
            initialIntroText={introText}
            onSave={handleUpdateContent}
            onReset={handleResetContent}
            onClose={() => setShowEditor(false)}
          />
        )}

        {showUserGuide && (
          <UserGuideModal onClose={() => setShowUserGuide(false)} />
        )}

        {showTraineeBadge && (
          <TraineeBadge 
            traineeName={traineeName}
            tasks={tasks}
            onClose={() => setShowTraineeBadge(false)}
          />
        )}

        {scannedTraineeData && (
          <TraineeReportModal 
            data={scannedTraineeData}
            onClose={() => setScannedTraineeData(null)}
          />
        )}

        {showCompletionModal && (
          <CompletionModal
            traineeName={traineeName}
            onClose={() => setShowCompletionModal(false)}
            onPrint={printCertificate} 
          />
        )}

        {(scanningTaskId || scanningSectionId || isSupervisorScanning) && (
          <ScannerModal 
            onScanSuccess={handleScanSuccess} 
            onClose={closeScanner} 
          />
        )}

      </div>
    </>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { SECTIONS, DEFAULT_INTRO_TEXT, DEFAULT_ORG_SETTINGS } from './constants';
import { TaskState, TraineeQrData, Section, OrganizationSettings } from './types';
import { SectionGroup } from './components/SectionGroup';
import { storageService, AppData } from './storage';
import { SupervisorBadge } from './components/SupervisorBadge';
import { ScannerModal } from './components/ScannerModal';
import { TraineeBadge } from './components/TraineeBadge';
import { TraineeReportModal } from './components/TraineeReportModal';
import { CompletionModal } from './components/CompletionModal';
import { CertificateView } from './components/CertificateView';
import { ContentEditorModal } from './components/ContentEditorModal';
import { UserGuideModal } from './components/UserGuideModal';
import { Printer, Flame, CheckCircle, QrCode, Trash2, UserCheck, Trophy, CircleHelp, Building2, MapPin, FileText } from 'lucide-react';

const App: React.FC = () => {
  // Data State
  const [traineeName, setTraineeName] = useState('');
  const [tasks, setTasks] = useState<Record<string, TaskState>>({});
  const [sections, setSections] = useState<Section[]>(SECTIONS);
  const [introText, setIntroText] = useState(DEFAULT_INTRO_TEXT);
  const [orgSettings, setOrgSettings] = useState<OrganizationSettings>(DEFAULT_ORG_SETTINGS);

  // UI State
  const [showSupervisorBadge, setShowSupervisorBadge] = useState(false);
  const [showTraineeBadge, setShowTraineeBadge] = useState(false);
  const [showCompletionModal, setShowCompletionModal] = useState(false);
  const [showEditor, setShowEditor] = useState(false);
  const [showUserGuide, setShowUserGuide] = useState(false);
  const [isPrintingCertificate, setIsPrintingCertificate] = useState(false);

  // Keep track if we've already shown the celebration once per session to avoid annoyance
  const [hasCelebrated, setHasCelebrated] = useState(false);

  // Scan States
  const [scanningTaskId, setScanningTaskId] = useState<string | null>(null);
  const [scanningSectionId, setScanningSectionId] = useState<string | null>(null);
  const [isSupervisorScanning, setIsSupervisorScanning] = useState(false);

  const [scannedTraineeData, setScannedTraineeData] = useState<TraineeQrData | null>(null);

  // Load data on mount
  useEffect(() => {
    const data = storageService.load();
    setTraineeName(data.traineeName);
    setTasks(data.tasks);
    if (data.customSections && data.customSections.length > 0) {
      setSections(data.customSections);
    }
    if (data.introText) {
      setIntroText(data.introText);
    }
    if (data.organizationSettings) {
      setOrgSettings(data.organizationSettings);
    }
  }, []);

  // Save data on change
  const saveData = (
    newName: string, 
    newTasks: Record<string, TaskState>, 
    newSections?: Section[], 
    newIntroText?: string,
    newOrgSettings?: OrganizationSettings
  ) => {
    const data: AppData = {
      traineeName: newName,
      tasks: newTasks,
      customSections: newSections || sections,
      introText: newIntroText || introText,
      organizationSettings: newOrgSettings || orgSettings,
      lastUpdated: new Date().toISOString()
    };
    storageService.save(data);
  };

  const handleNameChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newName = e.target.value;
    setTraineeName(newName);
    saveData(newName, tasks);
  };

  const handleOrgSettingChange = (field: keyof OrganizationSettings, value: string) => {
    const newSettings = { ...orgSettings, [field]: value };
    setOrgSettings(newSettings);
    saveData(traineeName, tasks, sections, introText, newSettings);
  };

  const handleTaskChange = (taskId: string, updates: Partial<TaskState>) => {
    const newTasks = {
      ...tasks,
      [taskId]: {
        ...(tasks[taskId] || { date: '', traineeSigned: false, trainerSigned: false }),
        ...updates
      }
    };
    setTasks(newTasks);
    saveData(traineeName, newTasks);
  };

  const handleUpdateContent = (newSections: Section[], newIntroText: string) => {
    setSections(newSections);
    setIntroText(newIntroText);
    // Don't update orgSettings here, as they are now handled by the trainee in the main view
    saveData(traineeName, tasks, newSections, newIntroText, orgSettings);
  };

  const handleResetContent = () => {
    setSections(SECTIONS);
    setIntroText(DEFAULT_INTRO_TEXT);
    setOrgSettings(DEFAULT_ORG_SETTINGS);
    saveData(traineeName, tasks, SECTIONS, DEFAULT_INTRO_TEXT, DEFAULT_ORG_SETTINGS);
  };

  const handleScanRequest = (taskId: string) => {
    setScanningTaskId(taskId);
  };

  const handleSectionScanRequest = (sectionId: string) => {
    setScanningSectionId(sectionId);
  };

  const handleSupervisorScanRequest = () => {
    setIsSupervisorScanning(true);
  };

  const handleScanSuccess = (data: any) => {
    const today = new Date().toISOString().split('T')[0];

    // Scenario 1: Trainee scanning Supervisor Signature for a SINGLE TASK
    if (scanningTaskId && data.type === 'SUPERVISOR_SIGNATURE' && data.name) {
       handleTaskChange(scanningTaskId, {
         trainerSigned: true,
         trainerName: data.name,
         date: today
       });
       setScanningTaskId(null);
    }
    // Scenario 2: Trainee scanning Supervisor Signature for a WHOLE SECTION
    else if (scanningSectionId && data.type === 'SUPERVISOR_SIGNATURE' && data.name) {
       const section = sections.find(s => s.id === scanningSectionId);
       if (section) {
         const newTasks = { ...tasks };
         section.items.forEach(item => {
           // Update each task in the section
           newTasks[item.id] = {
             ...(newTasks[item.id] || { date: '', traineeSigned: false, trainerSigned: false }),
             trainerSigned: true,
             trainerName: data.name,
             date: today
           };
         });
         setTasks(newTasks);
         saveData(traineeName, newTasks);
       }
       setScanningSectionId(null);
    }
    // Scenario 3: Supervisor scanning Trainee Progress
    else if (isSupervisorScanning && data.type === 'TRAINEE_PROGRESS') {
      setIsSupervisorScanning(false);
      setScannedTraineeData(data);
    }
    // Error / Mismatch handling
    else {
      if ((scanningTaskId || scanningSectionId) && data.type !== 'SUPERVISOR_SIGNATURE') {
         alert("Virhe: Skannasit pelastajan passin. Skannaa esimiehen kuittauskoodi.");
      }
      else if (isSupervisorScanning && data.type !== 'TRAINEE_PROGRESS') {
         alert("Virhe: Skannasit esimiehen koodin. Skannaa pelastajan passi.");
      }
    }
  };

  const closeScanner = () => {
    setScanningTaskId(null);
    setScanningSectionId(null);
    setIsSupervisorScanning(false);
  };

  const handleClearAll = () => {
    if (confirm("Haluatko varmasti tyhjentää koko lomakkeen? Kaikki merkinnät poistetaan. Lomakkeen muokattu rakenne säilyy.")) {
      const currentSections = sections;
      const currentIntro = introText;
      const currentOrg = orgSettings;
      storageService.clear();

      // Reset state
      setTraineeName('');
      setTasks({});
      setHasCelebrated(false);

      // Restore structure
      setSections(currentSections);
      setIntroText(currentIntro);
      setOrgSettings(currentOrg);

      // Immediately save the structure back so it persists
      const freshData: AppData = {
          traineeName: '',
          tasks: {},
          customSections: currentSections,
          introText: currentIntro,
          organizationSettings: currentOrg,
          lastUpdated: new Date().toISOString()
      };
      storageService.save(freshData);
    }
  };

  // Standard print (checklist)
  const printForm = () => {
    setIsPrintingCertificate(false);
    // Allow React to update state before printing
    setTimeout(() => window.print(), 100);
  };

  // Certificate print (diploma)
  const printCertificate = () => {
    setIsPrintingCertificate(true);
    setTimeout(() => {
      window.print();
      // Reset after print dialog closes (approximate) or let user switch back manually
      const cleanup = () => setIsPrintingCertificate(false);
      window.addEventListener('afterprint', cleanup, { once: true });
      setTimeout(cleanup, 5000); 
    }, 100);
  };

  // Calculate stats
  const stats = useMemo(() => {
    let total = 0;
    let completed = 0;
    sections.forEach(section => {
      section.items.forEach(item => {
        total++;
        const s = tasks[item.id];
        if (s && s.traineeSigned && s.trainerSigned) {
          completed++;
        }
      });
    });
    return { total, completed, percentage: total === 0 ? 0 : Math.round((completed/total) * 100) };
  }, [tasks, sections]);

  // Check for completion
  useEffect(() => {
    if (stats.percentage === 100 && !hasCelebrated && stats.total > 0) {
      setShowCompletionModal(true);
      setHasCelebrated(true);
    }
  }, [stats.percentage, hasCelebrated, stats.total]);

  // Determine date to show on certificate (today)
  const todayDate = new Date().toLocaleDateString('fi-FI');

  return (
    <>
      {/* CERTIFICATE VIEW (Only visible when printing certificate) */}
      {isPrintingCertificate && (
         <CertificateView 
           traineeName={traineeName} 
           completionDate={todayDate}
           orgSettings={orgSettings} 
         />
      )}

      {/* MAIN APP VIEW (Hidden when printing certificate) */}
      <div className={`min-h-screen bg-gray-100 print:bg-white pb-12 ${isPrintingCertificate ? 'hidden' : 'block'}`}>

        {/* Header Bar */}
        <header className="bg-primary text-white shadow-md sticky top-0 z-20 print:static print:shadow-none print:bg-white print:text-black">
          <div className="max-w-4xl mx-auto px-4 py-3 flex flex-col sm:flex-row items-center justify-between gap-4">

            {/* Logo & Title */}
            <div className="flex items-center gap-3 w-full sm:w-auto">
              <div className="bg-orange-500 p-2 rounded-lg print:hidden">
                <Flame className="w-6 h-6 text-white" />
              </div>
              <div>
                <h1 className="text-lg font-bold leading-tight">Pelastajan Perehdytys</h1>
                <p className="text-xs text-slate-300 print:hidden">Sähköinen seurantalomake</p>
              </div>
            </div>

            {/* Controls */}
            <div className="flex items-center gap-2 w-full sm:w-auto justify-end no-print overflow-x-auto pb-1 sm:pb-0">

              <button
                onClick={() => setShowUserGuide(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-700 hover:bg-slate-600 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-600 whitespace-nowrap mr-2"
                title="Käyttöohjeet"
              >
                <CircleHelp className="w-4 h-4 text-sky-300" />
                <span className="hidden sm:inline">Ohjeet</span>
              </button>

              {stats.percentage === 100 && (
                <button
                  onClick={() => setShowCompletionModal(true)}
                  className="flex items-center gap-1.5 sm:gap-2 bg-yellow-500 hover:bg-yellow-600 text-white px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors shadow-lg animate-pulse font-bold whitespace-nowrap"
                >
                  <Trophy className="w-4 h-4" />
                  <span>Valmis!</span>
                </button>
              )}

              <button
                onClick={() => setShowTraineeBadge(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-800 hover:bg-slate-700 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-700 whitespace-nowrap"
              >
                <UserCheck className="w-4 h-4 text-accent" />
                <span className="sm:hidden">Passi</span>
                <span className="hidden sm:inline">Oma Passi</span>
              </button>

              <div className="w-px h-6 bg-slate-700 mx-0.5 sm:mx-1"></div>

              <button 
                onClick={() => setShowSupervisorBadge(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-800 hover:bg-slate-700 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-700 whitespace-nowrap"
              >
                <QrCode className="w-4 h-4 text-green-400" />
                <span className="sm:hidden">Esimies</span>
                <span className="hidden sm:inline">Esimiestyökalut</span>
              </button>

              <button 
                onClick={printForm}
                className="p-2 bg-slate-800 hover:bg-slate-700 rounded-lg transition-colors text-slate-200"
                title="Tulosta PDF (Lista)"
              >
                <Printer className="w-5 h-5" />
              </button>

              <button 
                onClick={handleClearAll}
                className="p-2 bg-red-900/50 hover:bg-red-900 rounded-lg transition-colors text-red-200 ml-1 sm:ml-2"
                title="Tyhjennä lomake (säilyttää rakenteen)"
              >
                <Trash2 className="w-5 h-5" />
              </button>
            </div>
          </div>
        </header>

        <main className="max-w-4xl mx-auto px-4 py-8 print:py-0 print:px-0">

          {/* Name Input & Intro */}
          <div className="bg-white rounded-lg p-6 shadow-sm border border-gray-200 mb-6 print:border-none print:shadow-none print:p-0">

            <div className="mb-6 no-print">
              <label className="block text-xs font-bold uppercase text-slate-500 mb-2">
                Pelastajan Nimi
              </label>
              <div className="relative">
                <input
                  type="text"
                  value={traineeName}
                  onChange={handleNameChange}
                  placeholder="Kirjoita nimesi tähän..."
                  className="w-full text-lg font-bold text-slate-800 border-b-2 border-slate-200 focus:border-accent outline-none py-2 pl-9 bg-transparent transition-colors placeholder:font-normal placeholder:text-gray-300"
                />
                <UserCheck className="w-6 h-6 text-gray-400 absolute left-0 top-2" />
              </div>
            </div>

            {/* Organization Settings Input for Trainee */}
            <div className="mt-4 p-4 bg-gray-50 rounded-lg border border-gray-200 no-print mb-6">
              <h3 className="text-sm font-bold text-gray-500 uppercase mb-3 flex items-center gap-2">
                <FileText className="w-4 h-4" />
                Tiedot
              </h3>
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                <div>
                   <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Organisaatio</label>
                   <div className="relative">
                     <input 
                       type="text" 
                       value={orgSettings.name}
                       onChange={(e) => handleOrgSettingChange('name', e.target.value)}
                       className="w-full pl-7 px-3 py-2 text-sm border border-gray-300 rounded focus:ring-1 focus:ring-accent outline-none bg-white"
                       placeholder="Esim. Hyvinvointialue"
                     />
                     <Building2 className="w-3.5 h-3.5 text-gray-400 absolute left-2.5 top-2.5" />
                   </div>
                </div>
                <div>
                   <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Yksikkö</label>
                   <input 
                     type="text" 
                     value={orgSettings.subtitle}
                     onChange={(e) => handleOrgSettingChange('subtitle', e.target.value)}
                     className="w-full px-3 py-2 text-sm border border-gray-300 rounded focus:ring-1 focus:ring-accent outline-none bg-white"
                     placeholder="Esim. Pelastustoimi"
                   />
                </div>
                <div>
                   <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Paikkakunta</label>
                   <div className="relative">
                     <input 
                       type="text" 
                       value={orgSettings.city}
                       onChange={(e) => handleOrgSettingChange('city', e.target.value)}
                       className="w-full pl-7 px-3 py-2 text-sm border border-gray-300 rounded focus:ring-1 focus:ring-accent outline-none bg-white"
                       placeholder="Esim. Helsinki"
                     />
                     <MapPin className="w-3.5 h-3.5 text-gray-400 absolute left-2.5 top-2.5" />
                   </div>
                </div>
              </div>
            </div>

            <div className="prose prose-sm max-w-none text-slate-600 mb-2 print:text-xs whitespace-pre-line">
              {introText}
            </div>

            {/* Print Header */}
            <div className="hidden print:block mb-8 border-b-2 border-black pb-4">
                <span className="text-sm text-gray-500 uppercase">Pelastaja</span>
                <div className="text-2xl font-bold">{traineeName}</div>
                <div className="mt-2 text-xs text-gray-500">
                  {orgSettings.name} - {orgSettings.subtitle}
                </div>
            </div>
          </div>

          {/* Sticky Progress Bar */}
          <div className="bg-white/95 backdrop-blur rounded-lg p-4 shadow-sm border border-gray-200 mb-8 flex items-center gap-4 no-print sticky top-20 z-10 transition-shadow">
            <div className={`p-2 rounded-full ${stats.percentage === 100 ? 'bg-green-100' : 'bg-gray-100'}`}>
              <CheckCircle className={`w-6 h-6 ${stats.percentage === 100 ? 'text-green-600' : 'text-gray-400'}`} />
            </div>
            <div className="flex-1">
              <div className="flex justify-between items-end mb-1">
                <span className="font-bold text-slate-700">Edistyminen</span>
                <span className="text-sm font-medium text-accent">{stats.completed} / {stats.total} ({stats.percentage}%)</span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2.5">
                <div 
                  className={`h-2.5 rounded-full transition-all duration-700 ${stats.percentage === 100 ? 'bg-green-500' : 'bg-accent'}`}
                  style={{ width: `${stats.percentage}%` }}
                ></div>
              </div>
            </div>
          </div>

          {/* Form Sections (Using state 'sections' instead of constant 'SECTIONS') */}
          <div className="space-y-4">
            {sections.map(section => (
              <SectionGroup 
                key={section.id} 
                section={section} 
                tasks={tasks} 
                traineeName={traineeName}
                onTaskChange={handleTaskChange}
                onScanRequest={handleScanRequest}
                onSectionScanRequest={handleSectionScanRequest}
              />
            ))}
          </div>

          {/* Print Signature Box (Only for list view) */}
          <div className="hidden print:block mt-8 pt-8 border-t-2 border-black page-break">
            {/* Signatures removed per request for the checklist printout, kept simple */}
            <div className="text-center text-xs text-gray-500">
              Tulostettu: {todayDate} - {orgSettings.city}
            </div>
          </div>

        </main>

        {/* Modals */}
        {showSupervisorBadge && (
          <SupervisorBadge 
            onClose={() => setShowSupervisorBadge(false)} 
            onScanRequest={handleSupervisorScanRequest}
            onEditContent={() => setShowEditor(true)}
          />
        )}

        {showEditor && (
          <ContentEditorModal 
            initialSections={sections}
            initialIntroText={introText}
            onSave={handleUpdateContent}
            onReset={handleResetContent}
            onClose={() => setShowEditor(false)}
          />
        )}

        {showUserGuide && (
          <UserGuideModal onClose={() => setShowUserGuide(false)} />
        )}

        {showTraineeBadge && (
          <TraineeBadge 
            traineeName={traineeName}
            tasks={tasks}
            onClose={() => setShowTraineeBadge(false)}
          />
        )}

        {scannedTraineeData && (
          <TraineeReportModal 
            data={scannedTraineeData}
            onClose={() => setScannedTraineeData(null)}
          />
        )}

        {showCompletionModal && (
          <CompletionModal
            traineeName={traineeName}
            onClose={() => setShowCompletionModal(false)}
            onPrint={printCertificate} 
          />
        )}

        {(scanningTaskId || scanningSectionId || isSupervisorScanning) && (
          <ScannerModal 
            onScanSuccess={handleScanSuccess} 
            onClose={closeScanner} 
          />
        )}

      </div>
    </>
  );
};

export default App;

