import React, { useEffect, useState } from 'react';
import QRCode from 'qrcode';
import { X, ShieldCheck, UserPen, Lock, KeyRound, Download, ScanLine, FilePenLine, Share2 } from 'lucide-react';
import { Section, TemplateQrData } from '../types';

interface SupervisorBadgeProps {
  onClose: () => void;
  onScanRequest: () => void;
  onEditContent: () => void;
  // New props for sharing content
  currentSections: Section[];
  currentIntroText: string;
}

export const SupervisorBadge: React.FC<SupervisorBadgeProps> = ({ 
  onClose, 
  onScanRequest, 
  onEditContent,
  currentSections,
  currentIntroText 
}) => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [error, setError] = useState(false);

  const [name, setName] = useState('');
  const [qrUrl, setQrUrl] = useState<string>('');

  // State for Template QR
  const [showTemplateQr, setShowTemplateQr] = useState(false);
  const [templateQrUrl, setTemplateQrUrl] = useState<string>('');

  // Effect for Supervisor Signature QR
  useEffect(() => {
    if (!name.trim()) {
      setQrUrl('');
      return;
    }

    const signaturePayload = JSON.stringify({
      type: 'SUPERVISOR_SIGNATURE',
      name: name.trim(),
      timestamp: Date.now()
    });

    QRCode.toDataURL(signaturePayload, { width: 400, margin: 2 })
      .then((url) => {
        setQrUrl(url);
      })
      .catch((err) => {
        console.error("QR Generation failed", err);
      });
  }, [name]);

  // Effect for Template Sharing QR
  useEffect(() => {
    if (showTemplateQr) {
      // 1. Minify data to fit in QR
      const minifiedSections = currentSections.map(sec => ({
        i: sec.id,
        t: sec.title,
        s: sec.subtitle,
        it: sec.items.map(item => ({
          i: item.id,
          l: item.label
        }))
      }));

      const payload: TemplateQrData = {
        type: 'TEMPLATE_CONFIG',
        intro: currentIntroText,
        s: minifiedSections
      };

      const jsonString = JSON.stringify(payload);

      // Generate QR
      QRCode.toDataURL(jsonString, { width: 500, margin: 2, errorCorrectionLevel: 'L' })
        .then((url) => {
          setTemplateQrUrl(url);
        })
        .catch((err) => {
          console.error("Template QR Generation failed", err);
          alert("Sisältö on liian laaja QR-koodiksi. Vähennä tekstin määrää.");
          setShowTemplateQr(false);
        });
    }
  }, [showTemplateQr, currentSections, currentIntroText]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === '112') {
        setIsAuthenticated(true);
        setError(false);
    } else {
        setError(true);
        setPasswordInput('');
    }
  };

  const handleDownload = (url: string, filenamePrefix: string) => {
    if (!url) return;
    const link = document.createElement('a');
    link.href = url;
    const safeName = name.replace(/[^a-z0-9]/gi, '_').toLowerCase() || 'template';
    link.download = `perehdytys-${filenamePrefix}-${safeName}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleStartScan = () => {
    onClose();
    onScanRequest();
  };

  const handleStartEdit = () => {
    onClose();
    onEditContent();
  };

  if (!isAuthenticated) {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
        <div className="bg-white rounded-2xl w-full max-w-sm overflow-hidden shadow-2xl animate-in fade-in zoom-in duration-200">
          <div className="bg-slate-800 p-4 flex justify-between items-center text-white">
            <div className="flex items-center gap-2">
              <Lock className="w-5 h-5 text-orange-400" />
              <h3 className="font-bold">Esimieskirjautuminen</h3>
            </div>
            <button onClick={onClose} className="p-1 hover:bg-slate-700 rounded-full transition-colors">
              <X className="w-5 h-5" />
            </button>
          </div>

          <form onSubmit={handleLogin} className="p-6 space-y-4">
            <div>
              <label className="block text-xs font-bold uppercase text-gray-500 mb-2">
                Salasana
              </label>
              <div className="relative">
                <input 
                  type="password" 
                  value={passwordInput}
                  onChange={(e) => setPasswordInput(e.target.value)}
                  className={`w-full pl-10 pr-4 py-2 border-2 rounded-lg outline-none transition-colors ${error ? 'border-red-300 focus:border-red-500' : 'border-slate-200 focus:border-slate-800'}`}
                  autoFocus
                  placeholder="Syötä salasana"
                />
                <KeyRound className="w-5 h-5 text-gray-400 absolute left-3 top-2.5" />
              </div>
              {error && (
                <p className="text-red-500 text-xs mt-2 font-medium">
                  Väärä salasana. Yritä uudelleen.
                </p>
              )}
            </div>

            <button 
              type="submit"
              className="w-full py-3 bg-slate-800 text-white rounded-lg font-bold hover:bg-slate-700 transition-colors shadow-lg shadow-slate-900/20"
            >
              Kirjaudu
            </button>
          </form>
        </div>
      </div>
    );
  }

  // --- TEMPLATE QR VIEW ---
  if (showTemplateQr) {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
        <div className="bg-white rounded-2xl w-full max-w-md overflow-hidden shadow-2xl animate-in fade-in zoom-in duration-200 flex flex-col max-h-[90vh]">
          <div className="bg-slate-800 p-4 flex justify-between items-center text-white shrink-0">
            <div className="flex items-center gap-2">
              <Share2 className="w-5 h-5 text-accent" />
              <h3 className="font-bold">Jaa perehdytysrunko</h3>
            </div>
            <button onClick={() => setShowTemplateQr(false)} className="p-1 hover:bg-slate-700 rounded-full transition-colors">
              <X className="w-5 h-5" />
            </button>
          </div>

          <div className="p-6 overflow-y-auto flex flex-col items-center gap-4">
             <p className="text-sm text-center text-gray-600">
               Pyydä pelastajaa skannaamaan tämä koodi aktivoimaan juuri luomasi perehdytyspohja.
             </p>

             <div className="bg-white p-2 border-2 border-slate-200 rounded-xl">
               {templateQrUrl ? (
                 <img src={templateQrUrl} alt="Template QR" className="w-64 h-64" />
               ) : (
                 <div className="w-64 h-64 flex items-center justify-center text-gray-400">Luodaan koodia...</div>
               )}
             </div>

             <div className="text-xs text-gray-400 max-w-xs text-center">
               Tämä siirtää nykyisen tehtävärakenteen ja alkutekstit pelastajan laitteelle.
             </div>
          </div>

          <div className="p-4 border-t border-gray-100 bg-gray-50 flex gap-3">
            <button 
              onClick={() => handleDownload(templateQrUrl, 'runko')}
              className="flex-1 py-3 bg-white border border-gray-300 rounded-lg font-bold text-slate-700 hover:bg-gray-50"
            >
              Tallenna kuva
            </button>
            <button 
              onClick={() => setShowTemplateQr(false)}
              className="flex-1 py-3 bg-slate-800 text-white rounded-lg font-bold hover:bg-slate-700"
            >
              Sulje
            </button>
          </div>
        </div>
      </div>
    );
  }

  // --- MAIN MENU VIEW ---
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl w-full max-w-sm overflow-hidden shadow-2xl animate-in fade-in zoom-in duration-200">

        <div className="bg-slate-800 p-4 flex justify-between items-center text-white">
          <div className="flex items-center gap-2">
            <ShieldCheck className="w-5 h-5 text-green-400" />
            <h3 className="font-bold">Esimiehen Työkalut</h3>
          </div>
          <button onClick={onClose} className="p-1 hover:bg-slate-700 rounded-full transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="p-6 space-y-8 max-h-[80vh] overflow-y-auto">

          {/* Section 1: Generate Supervisor ID */}
          <div className="space-y-4">
            <h4 className="text-sm font-bold uppercase text-slate-500 border-b pb-1">1. Esimiehen Tunniste</h4>

            <div className="w-full">
              <label className="block text-xs font-bold text-gray-400 mb-2">
                Esimiehen Nimi
              </label>
              <div className="relative">
                <input 
                  type="text" 
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  placeholder="Esim. Matti Meikäläinen"
                  className="w-full pl-10 pr-4 py-2 border-2 border-slate-200 rounded-lg focus:border-slate-800 outline-none transition-colors"
                />
                <UserPen className="w-5 h-5 text-gray-400 absolute left-3 top-2.5" />
              </div>
            </div>

            <div className={`p-4 bg-white border-2 rounded-xl flex items-center justify-center transition-all duration-300 ${qrUrl ? 'border-green-500 shadow-sm' : 'border-gray-100 bg-gray-50'}`}>
              {qrUrl ? (
                <div className="text-center space-y-2">
                    <img src={qrUrl} alt="Esimiehen QR-koodi" className="w-32 h-32 mx-auto" />
                    <button 
                        onClick={() => handleDownload(qrUrl, 'esimies')}
                        className="text-xs flex items-center justify-center gap-1 text-slate-500 hover:text-slate-800 mx-auto"
                    >
                        <Download className="w-3 h-3" /> Tallenna kuva
                    </button>
                </div>
              ) : (
                <div className="w-32 h-32 flex items-center justify-center text-gray-300 text-xs italic">
                  Kirjoita nimi...
                </div>
              )}
            </div>
          </div>

          {/* Section 2: Scan Trainee */}
          <div className="space-y-4">
             <h4 className="text-sm font-bold uppercase text-slate-500 border-b pb-1">2. Tarkista Pelastaja</h4>
             <button
               onClick={handleStartScan}
               className="w-full py-3 bg-accent hover:bg-sky-600 text-white rounded-xl font-bold transition-colors flex items-center justify-center gap-3 shadow-lg shadow-sky-500/20"
             >
                <ScanLine className="w-5 h-5" />
                Tarkista Pelastajan Passi
             </button>
          </div>

          {/* Section 3: Edit Form */}
          <div className="space-y-4">
             <h4 className="text-sm font-bold uppercase text-slate-500 border-b pb-1">3. Hallinta</h4>
             <div className="bg-gray-50 rounded-xl p-4 border border-gray-100 space-y-3">
               <p className="text-xs text-gray-500 text-center">
                 Muokkaa lomakkeen rakennetta ja jaa se pelastajalle.
               </p>

               <button
                 onClick={handleStartEdit}
                 className="w-full py-3 bg-white border-2 border-slate-200 hover:border-slate-400 text-slate-700 rounded-xl font-bold transition-colors flex items-center justify-center gap-3"
               >
                  <FilePenLine className="w-5 h-5" />
                  Muokkaa runkoa
               </button>

               <button
                 onClick={() => setShowTemplateQr(true)}
                 className="w-full py-3 bg-white border-2 border-slate-200 hover:border-slate-400 text-slate-700 rounded-xl font-bold transition-colors flex items-center justify-center gap-3"
               >
                  <Share2 className="w-5 h-5" />
                  Jaa perehdytysrunko
               </button>
             </div>
          </div>

        </div>

        <button 
          onClick={onClose}
          className="w-full py-4 bg-gray-50 border-t border-gray-100 font-semibold text-slate-600 hover:bg-gray-100 transition-colors"
        >
          Sulje
        </button>
      </div>
    </div>
  );
};

