  const [sections, setSections] = useState<Section[]>(SECTIONS);
  const [introText, setIntroText] = useState(DEFAULT_INTRO_TEXT);
  const [orgSettings, setOrgSettings] = useState<OrganizationSettings>(DEFAULT_ORG_SETTINGS);

  // UI State
  const [showSupervisorBadge, setShowSupervisorBadge] = useState(false);
  const [showTraineeBadge, setShowTraineeBadge] = useState(false);
  const [showCompletionModal, setShowCompletionModal] = useState(false);
  const [showEditor, setShowEditor] = useState(false);
  const [showUserGuide, setShowUserGuide] = useState(false);
  const [showClearConfirm, setShowClearConfirm] = useState(false);
  const [isPrintingCertificate, setIsPrintingCertificate] = useState(false);

  // Keep track if we've already shown the celebration once per session to avoid annoyance
  const [hasCelebrated, setHasCelebrated] = useState(false);

  // Scan States
  const [scanningTaskId, setScanningTaskId] = useState<string | null>(null);
  const [scanningSectionId, setScanningSectionId] = useState<string | null>(null);
  const [isSupervisorScanning, setIsSupervisorScanning] = useState(false);

  const [scannedTraineeData, setScannedTraineeData] = useState<TraineeQrData | null>(null);

  // Load data on mount
  useEffect(() => {
    const data = storageService.load();
    setTraineeName(data.traineeName);
    setTasks(data.tasks);
    if (data.customSections && data.customSections.length > 0) {
      setSections(data.customSections);
    }
    if (data.introText) {
      setIntroText(data.introText);
    }
    if (data.organizationSettings) {
      setOrgSettings(data.organizationSettings);
    }
  }, []);

  // Save data on change
  const saveData = (
    newName: string, 
    newTasks: Record<string, TaskState>, 
    newSections?: Section[], 
    newIntroText?: string,
    newOrgSettings?: OrganizationSettings
  ) => {
    const data: AppData = {
      traineeName: newName,
      tasks: newTasks,
      customSections: newSections || sections,
      introText: newIntroText || introText,
      organizationSettings: newOrgSettings || orgSettings,
      lastUpdated: new Date().toISOString()
    };
    storageService.save(data);
  };

  const handleNameChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newName = e.target.value;
    setTraineeName(newName);
    saveData(newName, tasks);
  };

  const handleOrgSettingChange = (field: keyof OrganizationSettings, value: string) => {
    const newSettings = { ...orgSettings, [field]: value };
    setOrgSettings(newSettings);
    saveData(traineeName, tasks, sections, introText, newSettings);
  };

  const handleTaskChange = (taskId: string, updates: Partial<TaskState>) => {
    const newTasks = {
      ...tasks,
      [taskId]: {
        ...(tasks[taskId] || { date: '', traineeSigned: false, trainerSigned: false }),
        ...updates
      }
    };
    setTasks(newTasks);
    saveData(traineeName, newTasks);
  };

  const handleUpdateContent = (newSections: Section[], newIntroText: string) => {
    setSections(newSections);
    setIntroText(newIntroText);
    // Don't update orgSettings here, as they are now handled by the trainee in the main view
    saveData(traineeName, tasks, newSections, newIntroText, orgSettings);
  };

  const handleResetContent = () => {
    setSections(SECTIONS);
    setIntroText(DEFAULT_INTRO_TEXT);
    setOrgSettings(DEFAULT_ORG_SETTINGS);
    saveData(traineeName, tasks, SECTIONS, DEFAULT_INTRO_TEXT, DEFAULT_ORG_SETTINGS);
  };

  const handleScanRequest = (taskId: string) => {
    setScanningTaskId(taskId);
  };

  const handleSectionScanRequest = (sectionId: string) => {
    setScanningSectionId(sectionId);
  };

  const handleSupervisorScanRequest = () => {
    setIsSupervisorScanning(true);
  };

  const handleScanSuccess = (data: any) => {
    const today = new Date().toISOString().split('T')[0];

    // Scenario 0: Template Config (Activation of new induction plan)
    if (data.type === 'TEMPLATE_CONFIG' && data.s) {
       const templateData = data as TemplateQrData;
       if (confirm('Haluatko ottaa käyttöön uuden perehdytysrungon ja -ohjeistuksen? Tämä päivittää nykyisen lomakkeen rakenteen.')) {
         // Un-minify sections
         const newSections: Section[] = templateData.s.map(minSec => ({
           id: minSec.i,
           title: minSec.t,
           subtitle: minSec.s,
           items: minSec.it.map(minItem => ({
             id: minItem.i,
             label: minItem.l
           }))
         }));

         handleUpdateContent(newSections, templateData.intro);
         alert('Uusi perehdytysrunko aktivoitu onnistuneesti!');

         // Close scanner
         closeScanner();
       }
       return;
    }

    // Scenario 1: Trainee scanning Supervisor Signature for a SINGLE TASK
    if (scanningTaskId && data.type === 'SUPERVISOR_SIGNATURE' && data.name) {
       handleTaskChange(scanningTaskId, {
         trainerSigned: true,
         trainerName: data.name,
         date: today
       });
       setScanningTaskId(null);
    }
    // Scenario 2: Trainee scanning Supervisor Signature for a WHOLE SECTION
    else if (scanningSectionId && data.type === 'SUPERVISOR_SIGNATURE' && data.name) {
       const section = sections.find(s => s.id === scanningSectionId);
       if (section) {
         const newTasks = { ...tasks };
         section.items.forEach(item => {
           // Update each task in the section
           newTasks[item.id] = {
             ...(newTasks[item.id] || { date: '', traineeSigned: false, trainerSigned: false }),
             trainerSigned: true,
             trainerName: data.name,
             date: today
           };
         });
         setTasks(newTasks);
         saveData(traineeName, newTasks);
       }
       setScanningSectionId(null);
    }
    // Scenario 3: Supervisor scanning Trainee Progress
    else if (isSupervisorScanning && data.type === 'TRAINEE_PROGRESS') {
      setIsSupervisorScanning(false);
      setScannedTraineeData(data);
    }
    // Error / Mismatch handling
    else {
      if ((scanningTaskId || scanningSectionId) && data.type !== 'SUPERVISOR_SIGNATURE') {
         alert("Virhe: Skannasit pelastajan passin. Skannaa esimiehen kuittauskoodi.");
      }
      else if (isSupervisorScanning && data.type !== 'TRAINEE_PROGRESS') {
         alert("Virhe: Skannasit esimiehen koodin. Skannaa pelastajan passi.");
      }
    }
  };

  const closeScanner = () => {
    setScanningTaskId(null);
    setScanningSectionId(null);
    setIsSupervisorScanning(false);
  };

  // Logic to actually wipe data (called by modal)
  const performClearAll = () => {
    const currentSections = sections;
    const currentIntro = introText;
    const currentOrg = orgSettings;

    storageService.clear();

    // Reset state
    setTraineeName('');
    setTasks({});
    setHasCelebrated(false);

    // Restore structure settings (user doesn't want to lose the layout, just the data)
    setSections(currentSections);
    setIntroText(currentIntro);
    setOrgSettings(currentOrg);

    // Immediately save the structure back so it persists
    const freshData: AppData = {
        traineeName: '',
        tasks: {},
        customSections: currentSections,
        introText: currentIntro,
        organizationSettings: currentOrg,
        lastUpdated: new Date().toISOString()
    };
    storageService.save(freshData);

    setShowClearConfirm(false);
  };

  // Standard print (checklist)
  const printForm = () => {
    setIsPrintingCertificate(false);
    // Allow React to update state before printing
    setTimeout(() => window.print(), 100);
  };

  // Certificate print (diploma)
  const printCertificate = () => {
    setIsPrintingCertificate(true);
    setTimeout(() => {
      window.print();
      // Reset after print dialog closes (approximate) or let user switch back manually
      const cleanup = () => setIsPrintingCertificate(false);
      window.addEventListener('afterprint', cleanup, { once: true });
      setTimeout(cleanup, 5000); 
    }, 100);
  };

  // Calculate stats
  const stats = useMemo(() => {
    let total = 0;
    let completed = 0;
    sections.forEach(section => {
      section.items.forEach(item => {
        total++;
        const s = tasks[item.id];
        if (s && s.traineeSigned && s.trainerSigned) {
          completed++;
        }
      });
    });
    return { total, completed, percentage: total === 0 ? 0 : Math.round((completed/total) * 100) };
  }, [tasks, sections]);

  // Check for completion
  useEffect(() => {
    if (stats.percentage === 100 && !hasCelebrated && stats.total > 0) {
      setShowCompletionModal(true);
      setHasCelebrated(true);
    }
  }, [stats.percentage, hasCelebrated, stats.total]);

  // Determine date to show on certificate (today)
  const todayDate = new Date().toLocaleDateString('fi-FI');

  return (
    <>
      {/* CERTIFICATE VIEW (Only visible when printing certificate) */}
      {isPrintingCertificate && (
         <CertificateView 
           traineeName={traineeName} 
           completionDate={todayDate}
           orgSettings={orgSettings} 
         />
      )}

      {/* MAIN APP VIEW (Hidden when printing certificate) */}
      <div className={`min-h-screen bg-gray-100 print:bg-white pb-12 ${isPrintingCertificate ? 'hidden' : 'block'}`}>

        {/* Header Bar */}
        <header className="bg-primary text-white shadow-md sticky top-0 z-20 print:static print:shadow-none print:bg-white print:text-black">
          <div className="max-w-4xl mx-auto px-4 py-3 flex flex-col sm:flex-row items-center justify-between gap-4">

            {/* Logo & Title */}
            <div className="flex items-center gap-3 w-full sm:w-auto">
              <div className="bg-orange-500 p-2 rounded-lg print:hidden">
                <Flame className="w-6 h-6 text-white" />
              </div>
              <div>
                <h1 className="text-lg font-bold leading-tight">Pelastajan Perehdytys</h1>
                <p className="text-xs text-slate-300 print:hidden">Sähköinen seurantalomake</p>
              </div>
            </div>

            {/* Controls */}
            <div className="flex items-center gap-2 w-full sm:w-auto justify-end no-print overflow-x-auto pb-1 sm:pb-0">

              <button
                onClick={() => setShowUserGuide(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-700 hover:bg-slate-600 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-600 whitespace-nowrap mr-2"
                title="Käyttöohjeet"
              >
                <CircleHelp className="w-4 h-4 text-sky-300" />
                <span className="hidden sm:inline">Ohjeet</span>
              </button>

              {stats.percentage === 100 && (
                <button
                  onClick={() => setShowCompletionModal(true)}
                  className="flex items-center gap-1.5 sm:gap-2 bg-yellow-500 hover:bg-yellow-600 text-white px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors shadow-lg animate-pulse font-bold whitespace-nowrap"
                >
                  <Trophy className="w-4 h-4" />
                  <span>Valmis!</span>
                </button>
              )}

              <button
                onClick={() => setShowTraineeBadge(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-800 hover:bg-slate-700 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-700 whitespace-nowrap"
              >
                <UserCheck className="w-4 h-4 text-accent" />
                <span className="sm:hidden">Passi</span>
                <span className="hidden sm:inline">Oma Passi</span>
              </button>

              <div className="w-px h-6 bg-slate-700 mx-0.5 sm:mx-1"></div>

              <button 
                onClick={() => setShowSupervisorBadge(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-800 hover:bg-slate-700 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-700 whitespace-nowrap"
              >
                <QrCode className="w-4 h-4 text-green-400" />
                <span className="sm:hidden">Esimies</span>
                <span className="hidden sm:inline">Esimiestyökalut</span>
              </button>

              <button 
                onClick={printForm}
                className="p-2 bg-slate-800 hover:bg-slate-700 rounded-lg transition-colors text-slate-200"
                title="Tulosta PDF (Lista)"
              >
                <Printer className="w-5 h-5" />
              </button>

              <button 
                onClick={() => setShowClearConfirm(true)}
                className="p-2 bg-red-900/50 hover:bg-red-900 rounded-lg transition-colors text-red-200 ml-1 sm:ml-2"
                title="Tyhjennä lomake (säilyttää rakenteen)"
              >
                <Trash2 className="w-5 h-5" />
              </button>
            </div>
          </div>
        </header>

        <main className="max-w-4xl mx-auto px-4 py-8 print:py-0 print:px-0">

          {/* Name Input & Intro */}
          <div className="bg-white rounded-lg p-6 shadow-sm border border-gray-200 mb-6 print:border-none print:shadow-none print:p-0">

            <div className="mb-6 no-print">
              <label className="block text-xs font-bold uppercase text-slate-500 mb-2">
                Pelastajan Nimi
              </label>
              <div className="relative">
                <input
                  type="text"
                  value={traineeName}
                  onChange={handleNameChange}
                  placeholder="Kirjoita nimesi tähän..."
                  className="w-full text-lg font-bold text-slate-800 border-b-2 border-slate-200 focus:border-accent outline-none py-2 pl-9 bg-transparent transition-colors placeholder:font-normal placeholder:text-gray-300"
                />
                <UserCheck className="w-6 h-6 text-gray-400 absolute left-0 top-2" />
              </div>
            </div>

            {/* Organization Settings Input for Trainee */}
            <div className="mt-4 p-4 bg-gray-50 rounded-lg border border-gray-200 no-print mb-6">
              <h3 className="text-sm font-bold text-gray-500 uppercase mb-3 flex items-center gap-2">
                <FileText className="w-4 h-4" />
                Tiedot
              </h3>
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                <div>
                   <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Organisaatio</label>
                   <div className="relative">
                     <input 
                       type="text" 
                       value={orgSettings.name}
                       onChange={(e) => handleOrgSettingChange('name', e.target.value)}
                       className="w-full pl-7 px-3 py-2 text-sm border border-gray-300 rounded focus:ring-1 focus:ring-accent outline-none bg-white"
                       placeholder="Esim. Hyvinvointialue"
                     />
                     <Building2 className="w-3.5 h-3.5 text-gray-400 absolute left-2.5 top-2.5" />
                   </div>
                </div>
                <div>
                   <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Yksikkö</label>
                   <input 
                     type="text" 
                     value={orgSettings.subtitle}
                     onChange={(e) => handleOrgSettingChange('subtitle', e.target.value)}
                     className="w-full px-3 py-2 text-sm border border-gray-300 rounded focus:ring-1 focus:ring-accent outline-none bg-white"
                     placeholder="Esim. Pelastustoimi"
                   />
                </div>
                <div>
                   <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Paikkakunta</label>
                   <div className="relative">
                     <input 
                       type="text" 
                       value={orgSettings.city}
                       onChange={(e) => handleOrgSettingChange('city', e.target.value)}
                       className="w-full pl-7 px-3 py-2 text-sm border border-gray-300 rounded focus:ring-1 focus:ring-accent outline-none bg-white"
                       placeholder="Esim. Helsinki"
                     />
                     <MapPin className="w-3.5 h-3.5 text-gray-400 absolute left-2.5 top-2.5" />
                   </div>
                </div>
              </div>
            </div>

            <div className="prose prose-sm max-w-none text-slate-600 mb-2 print:text-xs whitespace-pre-line">
              {introText}
            </div>

            {/* Print Header */}
            <div className="hidden print:block mb-8 border-b-2 border-black pb-4">
                <span className="text-sm text-gray-500 uppercase">Pelastaja</span>
                <div className="text-2xl font-bold">{traineeName}</div>
                <div className="mt-2 text-xs text-gray-500">
                  {orgSettings.name} - {orgSettings.subtitle}
                </div>
            </div>
          </div>

          {/* Sticky Progress Bar */}
          <div className="bg-white/95 backdrop-blur rounded-lg p-4 shadow-sm border border-gray-200 mb-8 flex items-center gap-4 no-print sticky top-20 z-10 transition-shadow">
            <div className={`p-2 rounded-full ${stats.percentage === 100 ? 'bg-green-100' : 'bg-gray-100'}`}>
              <CheckCircle className={`w-6 h-6 ${stats.percentage === 100 ? 'text-green-600' : 'text-gray-400'}`} />
            </div>
            <div className="flex-1">
              <div className="flex justify-between items-end mb-1">
                <span className="font-bold text-slate-700">Edistyminen</span>
                <span className="text-sm font-medium text-accent">{stats.completed} / {stats.total} ({stats.percentage}%)</span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2.5">
                <div 
                  className={`h-2.5 rounded-full transition-all duration-700 ${stats.percentage === 100 ? 'bg-green-500' : 'bg-accent'}`}
                  style={{ width: `${stats.percentage}%` }}
                ></div>
              </div>
            </div>
          </div>

          {/* Form Sections (Using state 'sections' instead of constant 'SECTIONS') */}
          <div className="space-y-4">
            {sections.map(section => (
              <SectionGroup 
                key={section.id} 
                section={section} 
                tasks={tasks} 
                traineeName={traineeName}
                onTaskChange={handleTaskChange}
                onScanRequest={handleScanRequest}
                onSectionScanRequest={handleSectionScanRequest}
              />
            ))}
          </div>

          {/* Print Signature Box (Only for list view) */}
          <div className="hidden print:block mt-8 pt-8 border-t-2 border-black page-break">
            {/* Signatures removed per request for the checklist printout, kept simple */}
            <div className="text-center text-xs text-gray-500">
              Tulostettu: {todayDate} - {orgSettings.city}
            </div>
          </div>

        </main>

        {/* Modals */}
        {showClearConfirm && (
          <ClearConfirmationModal 
            onConfirm={performClearAll} 
            onClose={() => setShowClearConfirm(false)} 
          />
        )}

        {showSupervisorBadge && (
          <SupervisorBadge 
            onClose={() => setShowSupervisorBadge(false)} 
            onScanRequest={handleSupervisorScanRequest}
            onEditContent={() => setShowEditor(true)}
            currentSections={sections}
            currentIntroText={introText}
          />
        )}

        {showEditor && (
          <ContentEditorModal 
            initialSections={sections}
            initialIntroText={introText}
            onSave={handleUpdateContent}
            onReset={handleResetContent}
            onClose={() => setShowEditor(false)}
          />
        )}

        {showUserGuide && (
          <UserGuideModal onClose={() => setShowUserGuide(false)} />
        )}

        {showTraineeBadge && (
          <TraineeBadge 
            traineeName={traineeName}
            tasks={tasks}
            onClose={() => setShowTraineeBadge(false)}
          />
        )}

        {scannedTraineeData && (
          <TraineeReportModal 
            data={scannedTraineeData}
            onClose={() => setScannedTraineeData(null)}
          />
        )}

        {showCompletionModal && (
          <CompletionModal
            traineeName={traineeName}
            onClose={() => setShowCompletionModal(false)}
            onPrint={printCertificate} 
          />
        )}

        {(scanningTaskId || scanningSectionId || isSupervisorScanning) && (
          <ScannerModal 
            onScanSuccess={handleScanSuccess} 
            onClose={closeScanner} 
          />
        )}

      </div>
    </>
  );
};

export default App;

export interface TaskItem {
  id: string;
  label: string;
}

export interface Section {
  id: string;
  title: string;
  subtitle?: string;
  items: TaskItem[];
}

export interface TaskState {
  date: string;
  traineeSigned: boolean;
  trainerSigned: boolean;
  traineeName?: string;
  trainerName?: string;
}

export type UserRole = 'trainee' | 'supervisor';

export interface UserProgress {
  userId: string;
  userName: string;
  tasks: Record<string, TaskState>;
  lastUpdated: string;
}

export interface TraineeQrData {
  type: 'TRAINEE_PROGRESS';
  name: string;
  completedTaskIds: string[];
  timestamp: number;
}

// Internal structure before compression
export interface TemplateRawData {
  intro: string;
  s: {
    i: string; // id
    t: string; // title
    s?: string; // subtitle
    it: {      // items
      i: string; // id
      l: string; // label
    }[];
  }[];
}

export interface TemplateQrData {
  type?: 'TEMPLATE_CONFIG'; // Optional because compressed version relies on 'z' key
  z?: string; // Compressed data (lz-string encodedURIComponent)
  // Legacy uncompressed fallback (optional)
  intro?: string;
  s?: any[];
}

export interface OrganizationSettings {
  name: string;      // e.g. "Satakunnan hyvinvointialue"
  subtitle: string;  // e.g. "Pelastustoimi"
  city: string;      // e.g. "Porissa" (used in signature line)
}

// Global declaration for the loaded script
declare global {
  class Html5QrcodeScanner {
    constructor(elementId: string, config: any, verbose?: boolean);
    render(onSuccess: (decodedText: string, decodedResult: any) => void, onError?: (errorMessage: string) => void): void;
    clear(): Promise<void>;
  }

  class Html5Qrcode {
    constructor(elementId: string, verbose?: boolean);
    start(
      cameraIdOrConfig: string | { facingMode: string } | { deviceId: string }, 
      config: { fps: number; qrbox?: number | { width: number; height: number }; aspectRatio?: number }, 
      onSuccess: (decodedText: string, decodedResult: any) => void, 
      onError?: (errorMessage: string) => void
    ): Promise<void>;
    stop(): Promise<void>;
    clear(): Promise<void>;
  }
}

import React, { useEffect, useState } from 'react';
import QRCode from 'qrcode';
import LZString from 'lz-string';
import { X, ShieldCheck, UserPen, Lock, KeyRound, Download, ScanLine, FilePenLine, Share2 } from 'lucide-react';
import { Section, TemplateQrData, TemplateRawData } from '../types';

interface SupervisorBadgeProps {
  onClose: () => void;
  onScanRequest: () => void;
  onEditContent: () => void;
  // New props for sharing content
  currentSections: Section[];
  currentIntroText: string;
}

export const SupervisorBadge: React.FC<SupervisorBadgeProps> = ({ 
  onClose, 
  onScanRequest, 
  onEditContent,
  currentSections,
  currentIntroText 
}) => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [error, setError] = useState(false);

  const [name, setName] = useState('');
  const [qrUrl, setQrUrl] = useState<string>('');

  // State for Template QR
  const [showTemplateQr, setShowTemplateQr] = useState(false);
  const [templateQrUrl, setTemplateQrUrl] = useState<string>('');

  // Effect for Supervisor Signature QR
  useEffect(() => {
    if (!name.trim()) {
      setQrUrl('');
      return;
    }

    const signaturePayload = JSON.stringify({
      type: 'SUPERVISOR_SIGNATURE',
      name: name.trim(),
      timestamp: Date.now()
    });

    QRCode.toDataURL(signaturePayload, { width: 400, margin: 2 })
      .then((url) => {
        setQrUrl(url);
      })
      .catch((err) => {
        console.error("QR Generation failed", err);
      });
  }, [name]);

  // Effect for Template Sharing QR with Compression
  useEffect(() => {
    if (showTemplateQr) {
      try {
        // 1. Minify data structure keys to save space
        const minifiedSections = currentSections.map(sec => ({
          i: sec.id,
          t: sec.title,
          s: sec.subtitle,
          it: sec.items.map(item => ({
            i: item.id,
            l: item.label
          }))
        }));

        const rawData: TemplateRawData = {
          intro: currentIntroText,
          s: minifiedSections
        };

        const jsonString = JSON.stringify(rawData);

        // 2. Compress the JSON string using LZ-String
        // compressToEncodedURIComponent produces URL-safe chars which QR codes handle reasonably well (better than UTF16)
        const compressed = LZString.compressToEncodedURIComponent(jsonString);

        const payload: TemplateQrData = {
          z: compressed
        };

        const payloadString = JSON.stringify(payload);

        // Generate QR
        QRCode.toDataURL(payloadString, { width: 500, margin: 2, errorCorrectionLevel: 'L' })
          .then((url) => {
            setTemplateQrUrl(url);
          })
          .catch((err) => {
            console.error("Template QR Generation failed", err);
            // Fallback error message if even compression fails (unlikely)
            alert("Sisältö on edelleen liian laaja QR-koodiksi pakkauksesta huolimatta. Vähennä tekstin määrää.");
            setShowTemplateQr(false);
          });
      } catch (e) {
        console.error("Compression failed", e);
        alert("Virhe datan pakkauksessa.");
        setShowTemplateQr(false);
      }
    }
  }, [showTemplateQr, currentSections, currentIntroText]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === '112') {
        setIsAuthenticated(true);
        setError(false);
    } else {
        setError(true);
        setPasswordInput('');
    }
  };

  const handleDownload = (url: string, filenamePrefix: string) => {
    if (!url) return;
    const link = document.createElement('a');
    link.href = url;
    const safeName = name.replace(/[^a-z0-9]/gi, '_').toLowerCase() || 'template';
    link.download = `perehdytys-${filenamePrefix}-${safeName}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleStartScan = () => {
    onClose();
    onScanRequest();
  };

  const handleStartEdit = () => {
    onClose();
    onEditContent();
  };

  if (!isAuthenticated) {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
        <div className="bg-white rounded-2xl w-full max-w-sm overflow-hidden shadow-2xl animate-in fade-in zoom-in duration-200">
          <div className="bg-slate-800 p-4 flex justify-between items-center text-white">
            <div className="flex items-center gap-2">
              <Lock className="w-5 h-5 text-orange-400" />
              <h3 className="font-bold">Esimieskirjautuminen</h3>
            </div>
            <button onClick={onClose} className="p-1 hover:bg-slate-700 rounded-full transition-colors">
              <X className="w-5 h-5" />
            </button>
          </div>

          <form onSubmit={handleLogin} className="p-6 space-y-4">
            <div>
              <label className="block text-xs font-bold uppercase text-gray-500 mb-2">
                Salasana
              </label>
              <div className="relative">
                <input 
                  type="password" 
                  value={passwordInput}
                  onChange={(e) => setPasswordInput(e.target.value)}
                  className={`w-full pl-10 pr-4 py-2 border-2 rounded-lg outline-none transition-colors ${error ? 'border-red-300 focus:border-red-500' : 'border-slate-200 focus:border-slate-800'}`}
                  autoFocus
                  placeholder="Syötä salasana"
                />
                <KeyRound className="w-5 h-5 text-gray-400 absolute left-3 top-2.5" />
              </div>
              {error && (
                <p className="text-red-500 text-xs mt-2 font-medium">
                  Väärä salasana. Yritä uudelleen.
                </p>
              )}
            </div>

            <button 
              type="submit"
              className="w-full py-3 bg-slate-800 text-white rounded-lg font-bold hover:bg-slate-700 transition-colors shadow-lg shadow-slate-900/20"
            >
              Kirjaudu
            </button>
          </form>
        </div>
      </div>
    );
  }

  // --- TEMPLATE QR VIEW ---
  if (showTemplateQr) {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
        <div className="bg-white rounded-2xl w-full max-w-md overflow-hidden shadow-2xl animate-in fade-in zoom-in duration-200 flex flex-col max-h-[90vh]">
          <div className="bg-slate-800 p-4 flex justify-between items-center text-white shrink-0">
            <div className="flex items-center gap-2">
              <Share2 className="w-5 h-5 text-accent" />
              <h3 className="font-bold">Jaa perehdytysrunko</h3>
            </div>
            <button onClick={() => setShowTemplateQr(false)} className="p-1 hover:bg-slate-700 rounded-full transition-colors">
              <X className="w-5 h-5" />
            </button>
          </div>

          <div className="p-6 overflow-y-auto flex flex-col items-center gap-4">
             <p className="text-sm text-center text-gray-600">
               Pyydä pelastajaa skannaamaan tämä koodi aktivoimaan juuri luomasi perehdytyspohja.
             </p>

             <div className="bg-white p-2 border-2 border-slate-200 rounded-xl">
               {templateQrUrl ? (
                 <img src={templateQrUrl} alt="Template QR" className="w-64 h-64" />
               ) : (
                 <div className="w-64 h-64 flex items-center justify-center text-gray-400">Pakataan sisältöä...</div>
               )}
             </div>

             <div className="text-xs text-gray-400 max-w-xs text-center">
               Tämä siirtää nykyisen tehtävärakenteen ja alkutekstit pelastajan laitteelle. Data on pakattu QR-koodin koon optimoimiseksi.
             </div>
          </div>

          <div className="p-4 border-t border-gray-100 bg-gray-50 flex gap-3">
            <button 
              onClick={() => handleDownload(templateQrUrl, 'runko')}
              className="flex-1 py-3 bg-white border border-gray-300 rounded-lg font-bold text-slate-700 hover:bg-gray-50"
            >
              Tallenna kuva
            </button>
            <button 
              onClick={() => setShowTemplateQr(false)}
              className="flex-1 py-3 bg-slate-800 text-white rounded-lg font-bold hover:bg-slate-700"
            >
              Sulje
            </button>
          </div>
        </div>
      </div>
    );
  }

  // --- MAIN MENU VIEW ---
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl w-full max-w-sm overflow-hidden shadow-2xl animate-in fade-in zoom-in duration-200">

        <div className="bg-slate-800 p-4 flex justify-between items-center text-white">
          <div className="flex items-center gap-2">
            <ShieldCheck className="w-5 h-5 text-green-400" />
            <h3 className="font-bold">Esimiehen Työkalut</h3>
          </div>
          <button onClick={onClose} className="p-1 hover:bg-slate-700 rounded-full transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="p-6 space-y-8 max-h-[80vh] overflow-y-auto">

          {/* Section 1: Generate Supervisor ID */}
          <div className="space-y-4">
            <h4 className="text-sm font-bold uppercase text-slate-500 border-b pb-1">1. Esimiehen Tunniste</h4>

            <div className="w-full">
              <label className="block text-xs font-bold text-gray-400 mb-2">
                Esimiehen Nimi
              </label>
              <div className="relative">
                <input 
                  type="text" 
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  placeholder="Esim. Matti Meikäläinen"
                  className="w-full pl-10 pr-4 py-2 border-2 border-slate-200 rounded-lg focus:border-slate-800 outline-none transition-colors"
                />
                <UserPen className="w-5 h-5 text-gray-400 absolute left-3 top-2.5" />
              </div>
            </div>

            <div className={`p-4 bg-white border-2 rounded-xl flex items-center justify-center transition-all duration-300 ${qrUrl ? 'border-green-500 shadow-sm' : 'border-gray-100 bg-gray-50'}`}>
              {qrUrl ? (
                <div className="text-center space-y-2">
                    <img src={qrUrl} alt="Esimiehen QR-koodi" className="w-32 h-32 mx-auto" />
                    <button 
                        onClick={() => handleDownload(qrUrl, 'esimies')}
                        className="text-xs flex items-center justify-center gap-1 text-slate-500 hover:text-slate-800 mx-auto"
                    >
                        <Download className="w-3 h-3" /> Tallenna kuva
                    </button>
                </div>
              ) : (
                <div className="w-32 h-32 flex items-center justify-center text-gray-300 text-xs italic">
                  Kirjoita nimi...
                </div>
              )}
            </div>
          </div>

          {/* Section 2: Scan Trainee */}
          <div className="space-y-4">
             <h4 className="text-sm font-bold uppercase text-slate-500 border-b pb-1">2. Tarkista Pelastaja</h4>
             <button
               onClick={handleStartScan}
               className="w-full py-3 bg-accent hover:bg-sky-600 text-white rounded-xl font-bold transition-colors flex items-center justify-center gap-3 shadow-lg shadow-sky-500/20"
             >
                <ScanLine className="w-5 h-5" />
                Tarkista Pelastajan Passi
             </button>
          </div>

          {/* Section 3: Edit Form */}
          <div className="space-y-4">
             <h4 className="text-sm font-bold uppercase text-slate-500 border-b pb-1">3. Hallinta</h4>
             <div className="bg-gray-50 rounded-xl p-4 border border-gray-100 space-y-3">
               <p className="text-xs text-gray-500 text-center">
                 Muokkaa lomakkeen rakennetta ja jaa se pelastajalle.
               </p>

               <button
                 onClick={handleStartEdit}
                 className="w-full py-3 bg-white border-2 border-slate-200 hover:border-slate-400 text-slate-700 rounded-xl font-bold transition-colors flex items-center justify-center gap-3"
               >
                  <FilePenLine className="w-5 h-5" />
                  Muokkaa runkoa
               </button>

               <button
                 onClick={() => setShowTemplateQr(true)}
                 className="w-full py-3 bg-white border-2 border-slate-200 hover:border-slate-400 text-slate-700 rounded-xl font-bold transition-colors flex items-center justify-center gap-3"
               >
                  <Share2 className="w-5 h-5" />
                  Jaa perehdytysrunko
               </button>
             </div>
          </div>

        </div>

        <button 
          onClick={onClose}
          className="w-full py-4 bg-gray-50 border-t border-gray-100 font-semibold text-slate-600 hover:bg-gray-100 transition-colors"
        >
          Sulje
        </button>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import LZString from 'lz-string';
import { SECTIONS, DEFAULT_INTRO_TEXT, DEFAULT_ORG_SETTINGS } from './constants';
import { TaskState, TraineeQrData, Section, OrganizationSettings, TemplateQrData, TemplateRawData } from './types';
import { SectionGroup } from './components/SectionGroup';
import { storageService, AppData } from './storage';
import { SupervisorBadge } from './components/SupervisorBadge';
import { ScannerModal } from './components/ScannerModal';
import { TraineeBadge } from './components/TraineeBadge';
import { TraineeReportModal } from './components/TraineeReportModal';
import { CompletionModal } from './components/CompletionModal';
import { CertificateView } from './components/CertificateView';
import { ContentEditorModal } from './components/ContentEditorModal';
import { UserGuideModal } from './components/UserGuideModal';
import { ClearConfirmationModal } from './components/ClearConfirmationModal';
import { Printer, Flame, CheckCircle, QrCode, Trash2, UserCheck, Trophy, CircleHelp, Building2, MapPin, FileText } from 'lucide-react';

const App: React.FC = () => {
  // Data State
  const [traineeName, setTraineeName] = useState('');
  const [tasks, setTasks] = useState<Record<string, TaskState>>({});
  const [sections, setSections] = useState<Section[]>(SECTIONS);
  const [introText, setIntroText] = useState(DEFAULT_INTRO_TEXT);
  const [orgSettings, setOrgSettings] = useState<OrganizationSettings>(DEFAULT_ORG_SETTINGS);

  // UI State
  const [showSupervisorBadge, setShowSupervisorBadge] = useState(false);
  const [showTraineeBadge, setShowTraineeBadge] = useState(false);
  const [showCompletionModal, setShowCompletionModal] = useState(false);
  const [showEditor, setShowEditor] = useState(false);
  const [showUserGuide, setShowUserGuide] = useState(false);
  const [showClearConfirm, setShowClearConfirm] = useState(false);
  const [isPrintingCertificate, setIsPrintingCertificate] = useState(false);

  // Keep track if we've already shown the celebration once per session to avoid annoyance
  const [hasCelebrated, setHasCelebrated] = useState(false);

  // Scan States
  const [scanningTaskId, setScanningTaskId] = useState<string | null>(null);
  const [scanningSectionId, setScanningSectionId] = useState<string | null>(null);
  const [isSupervisorScanning, setIsSupervisorScanning] = useState(false);

  const [scannedTraineeData, setScannedTraineeData] = useState<TraineeQrData | null>(null);

  // Load data on mount
  useEffect(() => {
    const data = storageService.load();
    setTraineeName(data.traineeName);
    setTasks(data.tasks);
    if (data.customSections && data.customSections.length > 0) {
      setSections(data.customSections);
    }
    if (data.introText) {
      setIntroText(data.introText);
    }
    if (data.organizationSettings) {
      setOrgSettings(data.organizationSettings);
    }
  }, []);

  // Save data on change
  const saveData = (
    newName: string, 
    newTasks: Record<string, TaskState>, 
    newSections?: Section[], 
    newIntroText?: string,
    newOrgSettings?: OrganizationSettings
  ) => {
    const data: AppData = {
      traineeName: newName,
      tasks: newTasks,
      customSections: newSections || sections,
      introText: newIntroText || introText,
      organizationSettings: newOrgSettings || orgSettings,
      lastUpdated: new Date().toISOString()
    };
    storageService.save(data);
  };

  const handleNameChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newName = e.target.value;
    setTraineeName(newName);
    saveData(newName, tasks);
  };

  const handleOrgSettingChange = (field: keyof OrganizationSettings, value: string) => {
    const newSettings = { ...orgSettings, [field]: value };
    setOrgSettings(newSettings);
    saveData(traineeName, tasks, sections, introText, newSettings);
  };

  const handleTaskChange = (taskId: string, updates: Partial<TaskState>) => {
    const newTasks = {
      ...tasks,
      [taskId]: {
        ...(tasks[taskId] || { date: '', traineeSigned: false, trainerSigned: false }),
        ...updates
      }
    };
    setTasks(newTasks);
    saveData(traineeName, newTasks);
  };

  const handleUpdateContent = (newSections: Section[], newIntroText: string) => {
    setSections(newSections);
    setIntroText(newIntroText);
    // Don't update orgSettings here, as they are now handled by the trainee in the main view
    saveData(traineeName, tasks, newSections, newIntroText, orgSettings);
  };

  const handleResetContent = () => {
    setSections(SECTIONS);
    setIntroText(DEFAULT_INTRO_TEXT);
    setOrgSettings(DEFAULT_ORG_SETTINGS);
    saveData(traineeName, tasks, SECTIONS, DEFAULT_INTRO_TEXT, DEFAULT_ORG_SETTINGS);
  };

  const handleScanRequest = (taskId: string) => {
    setScanningTaskId(taskId);
  };

  const handleSectionScanRequest = (sectionId: string) => {
    setScanningSectionId(sectionId);
  };

  const handleSupervisorScanRequest = () => {
    setIsSupervisorScanning(true);
  };

  const handleScanSuccess = (data: any) => {
    const today = new Date().toISOString().split('T')[0];

    // Scenario 0: Template Config (Activation of new induction plan)
    // Handle both Compressed ('z' key) and Uncompressed (legacy 's' key) formats
    if ((data.z) || (data.type === 'TEMPLATE_CONFIG' && data.s)) {
       let rawData: TemplateRawData | null = null;

       // Attempt decompression if 'z' is present
       if (data.z) {
          try {
            const decompressed = LZString.decompressFromEncodedURIComponent(data.z);
            if (decompressed) {
              rawData = JSON.parse(decompressed);
            }
          } catch (e) {
            console.error("Decompression failed", e);
            alert("Virhe luettaessa pakattua koodia.");
            return;
          }
       } else {
         // Fallback to uncompressed
         rawData = data as TemplateRawData;
       }

       if (rawData && rawData.s) {
          if (confirm('Haluatko ottaa käyttöön uuden perehdytysrungon ja -ohjeistuksen? Tämä päivittää nykyisen lomakkeen rakenteen.')) {
            // Un-minify sections
            const newSections: Section[] = rawData.s.map(minSec => ({
              id: minSec.i,
              title: minSec.t,
              subtitle: minSec.s,
              items: minSec.it.map(minItem => ({
                id: minItem.i,
                label: minItem.l
              }))
            }));

            handleUpdateContent(newSections, rawData.intro);
            alert('Uusi perehdytysrunko aktivoitu onnistuneesti!');
            closeScanner();
          }
       }
       return;
    }

    // Scenario 1: Trainee scanning Supervisor Signature for a SINGLE TASK
    if (scanningTaskId && data.type === 'SUPERVISOR_SIGNATURE' && data.name) {
       handleTaskChange(scanningTaskId, {
         trainerSigned: true,
         trainerName: data.name,
         date: today
       });
       setScanningTaskId(null);
    }
    // Scenario 2: Trainee scanning Supervisor Signature for a WHOLE SECTION
    else if (scanningSectionId && data.type === 'SUPERVISOR_SIGNATURE' && data.name) {
       const section = sections.find(s => s.id === scanningSectionId);
       if (section) {
         const newTasks = { ...tasks };
         section.items.forEach(item => {
           // Update each task in the section
           newTasks[item.id] = {
             ...(newTasks[item.id] || { date: '', traineeSigned: false, trainerSigned: false }),
             trainerSigned: true,
             trainerName: data.name,
             date: today
           };
         });
         setTasks(newTasks);
         saveData(traineeName, newTasks);
       }
       setScanningSectionId(null);
    }
    // Scenario 3: Supervisor scanning Trainee Progress
    else if (isSupervisorScanning && data.type === 'TRAINEE_PROGRESS') {
      setIsSupervisorScanning(false);
      setScannedTraineeData(data);
    }
    // Error / Mismatch handling
    else {
      if ((scanningTaskId || scanningSectionId) && data.type !== 'SUPERVISOR_SIGNATURE') {
         alert("Virhe: Skannasit pelastajan passin. Skannaa esimiehen kuittauskoodi.");
      }
      else if (isSupervisorScanning && data.type !== 'TRAINEE_PROGRESS') {
         alert("Virhe: Skannasit esimiehen koodin. Skannaa pelastajan passi.");
      }
    }
  };

  const closeScanner = () => {
    setScanningTaskId(null);
    setScanningSectionId(null);
    setIsSupervisorScanning(false);
  };

  // Logic to actually wipe data (called by modal)
  const performClearAll = () => {
    const currentSections = sections;
    const currentIntro = introText;
    const currentOrg = orgSettings;

    storageService.clear();

    // Reset state
    setTraineeName('');
    setTasks({});
    setHasCelebrated(false);

    // Restore structure settings (user doesn't want to lose the layout, just the data)
    setSections(currentSections);
    setIntroText(currentIntro);
    setOrgSettings(currentOrg);

    // Immediately save the structure back so it persists
    const freshData: AppData = {
        traineeName: '',
        tasks: {},
        customSections: currentSections,
        introText: currentIntro,
        organizationSettings: currentOrg,
        lastUpdated: new Date().toISOString()
    };
    storageService.save(freshData);

    setShowClearConfirm(false);
  };

  // Standard print (checklist)
  const printForm = () => {
    setIsPrintingCertificate(false);
    // Allow React to update state before printing
    setTimeout(() => window.print(), 100);
  };

  // Certificate print (diploma)
  const printCertificate = () => {
    setIsPrintingCertificate(true);
    setTimeout(() => {
      window.print();
      // Reset after print dialog closes (approximate) or let user switch back manually
      const cleanup = () => setIsPrintingCertificate(false);
      window.addEventListener('afterprint', cleanup, { once: true });
      setTimeout(cleanup, 5000); 
    }, 100);
  };

  // Calculate stats
  const stats = useMemo(() => {
    let total = 0;
    let completed = 0;
    sections.forEach(section => {
      section.items.forEach(item => {
        total++;
        const s = tasks[item.id];
        if (s && s.traineeSigned && s.trainerSigned) {
          completed++;
        }
      });
    });
    return { total, completed, percentage: total === 0 ? 0 : Math.round((completed/total) * 100) };
  }, [tasks, sections]);

  // Check for completion
  useEffect(() => {
    if (stats.percentage === 100 && !hasCelebrated && stats.total > 0) {
      setShowCompletionModal(true);
      setHasCelebrated(true);
    }
  }, [stats.percentage, hasCelebrated, stats.total]);

  // Determine date to show on certificate (today)
  const todayDate = new Date().toLocaleDateString('fi-FI');

  return (
    <>
      {/* CERTIFICATE VIEW (Only visible when printing certificate) */}
      {isPrintingCertificate && (
         <CertificateView 
           traineeName={traineeName} 
           completionDate={todayDate}
           orgSettings={orgSettings} 
         />
      )}

      {/* MAIN APP VIEW (Hidden when printing certificate) */}
      <div className={`min-h-screen bg-gray-100 print:bg-white pb-12 ${isPrintingCertificate ? 'hidden' : 'block'}`}>

        {/* Header Bar */}
        <header className="bg-primary text-white shadow-md sticky top-0 z-20 print:static print:shadow-none print:bg-white print:text-black">
          <div className="max-w-4xl mx-auto px-4 py-3 flex flex-col sm:flex-row items-center justify-between gap-4">

            {/* Logo & Title */}
            <div className="flex items-center gap-3 w-full sm:w-auto">
              <div className="bg-orange-500 p-2 rounded-lg print:hidden">
                <Flame className="w-6 h-6 text-white" />
              </div>
              <div>
                <h1 className="text-lg font-bold leading-tight">Pelastajan Perehdytys</h1>
                <p className="text-xs text-slate-300 print:hidden">Sähköinen seurantalomake</p>
              </div>
            </div>

            {/* Controls */}
            <div className="flex items-center gap-2 w-full sm:w-auto justify-end no-print overflow-x-auto pb-1 sm:pb-0">

              <button
                onClick={() => setShowUserGuide(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-700 hover:bg-slate-600 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-600 whitespace-nowrap mr-2"
                title="Käyttöohjeet"
              >
                <CircleHelp className="w-4 h-4 text-sky-300" />
                <span className="hidden sm:inline">Ohjeet</span>
              </button>

              {stats.percentage === 100 && (
                <button
                  onClick={() => setShowCompletionModal(true)}
                  className="flex items-center gap-1.5 sm:gap-2 bg-yellow-500 hover:bg-yellow-600 text-white px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors shadow-lg animate-pulse font-bold whitespace-nowrap"
                >
                  <Trophy className="w-4 h-4" />
                  <span>Valmis!</span>
                </button>
              )}

              <button
                onClick={() => setShowTraineeBadge(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-800 hover:bg-slate-700 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-700 whitespace-nowrap"
              >
                <UserCheck className="w-4 h-4 text-accent" />
                <span className="sm:hidden">Passi</span>
                <span className="hidden sm:inline">Oma Passi</span>
              </button>

              <div className="w-px h-6 bg-slate-700 mx-0.5 sm:mx-1"></div>

              <button 
                onClick={() => setShowSupervisorBadge(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-800 hover:bg-slate-700 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-700 whitespace-nowrap"
              >
                <QrCode className="w-4 h-4 text-green-400" />
                <span className="sm:hidden">Esimies</span>
                <span className="hidden sm:inline">Esimiestyökalut</span>
              </button>

              <button 
                onClick={printForm}
                className="p-2 bg-slate-800 hover:bg-slate-700 rounded-lg transition-colors text-slate-200"
                title="Tulosta PDF (Lista)"
              >
                <Printer className="w-5 h-5" />
              </button>

              <button 
                onClick={() => setShowClearConfirm(true)}
                className="p-2 bg-red-900/50 hover:bg-red-900 rounded-lg transition-colors text-red-200 ml-1 sm:ml-2"
