  const [isPrintingCertificate, setIsPrintingCertificate] = useState(false);

  // Keep track if we've already shown the celebration once per session to avoid annoyance
  const [hasCelebrated, setHasCelebrated] = useState(false);

  // Scan States
  const [scanningTaskId, setScanningTaskId] = useState<string | null>(null);
  const [scanningSectionId, setScanningSectionId] = useState<string | null>(null);
  const [isSupervisorScanning, setIsSupervisorScanning] = useState(false);

  const [scannedTraineeData, setScannedTraineeData] = useState<TraineeQrData | null>(null);

  // Load data on mount
  useEffect(() => {
    const data = storageService.load();
    setTraineeName(data.traineeName);
    setTasks(data.tasks);
    if (data.customSections && data.customSections.length > 0) {
      setSections(data.customSections);
    }
    if (data.introText) {
      setIntroText(data.introText);
    }
    if (data.organizationSettings) {
      setOrgSettings(data.organizationSettings);
    }
  }, []);

  // Save data on change
  const saveData = (
    newName: string, 
    newTasks: Record<string, TaskState>, 
    newSections?: Section[], 
    newIntroText?: string,
    newOrgSettings?: OrganizationSettings
  ) => {
    const data: AppData = {
      traineeName: newName,
      tasks: newTasks,
      customSections: newSections || sections,
      introText: newIntroText || introText,
      organizationSettings: newOrgSettings || orgSettings,
      lastUpdated: new Date().toISOString()
    };
    storageService.save(data);
  };

  const handleNameChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newName = e.target.value;
    setTraineeName(newName);
    saveData(newName, tasks);
  };

  const handleOrgSettingChange = (field: keyof OrganizationSettings, value: string) => {
    const newSettings = { ...orgSettings, [field]: value };
    setOrgSettings(newSettings);
    saveData(traineeName, tasks, sections, introText, newSettings);
  };

  const handleTaskChange = (taskId: string, updates: Partial<TaskState>) => {
    const newTasks = {
      ...tasks,
      [taskId]: {
        ...(tasks[taskId] || { date: '', traineeSigned: false, trainerSigned: false }),
        ...updates
      }
    };
    setTasks(newTasks);
    saveData(traineeName, newTasks);
  };

  const handleUpdateContent = (newSections: Section[], newIntroText: string) => {
    setSections(newSections);
    setIntroText(newIntroText);
    // Don't update orgSettings here, as they are now handled by the trainee in the main view
    saveData(traineeName, tasks, newSections, newIntroText, orgSettings);
  };

  const handleResetContent = () => {
    setSections(SECTIONS);
    setIntroText(DEFAULT_INTRO_TEXT);
    setOrgSettings(DEFAULT_ORG_SETTINGS);
    saveData(traineeName, tasks, SECTIONS, DEFAULT_INTRO_TEXT, DEFAULT_ORG_SETTINGS);
  };

  const handleScanRequest = (taskId: string) => {
    setScanningTaskId(taskId);
  };

  const handleSectionScanRequest = (sectionId: string) => {
    setScanningSectionId(sectionId);
  };

  const handleSupervisorScanRequest = () => {
    setIsSupervisorScanning(true);
  };

  // Helper to generate IDs for imported content
  const generateSlugId = (text: string, prefix: string) => {
    const slug = text.toLowerCase()
      .replace(/ä/g, 'a').replace(/ö/g, 'o').replace(/å/g, 'a')
      .replace(/[^a-z0-9]/g, '_')
      .replace(/_+/g, '_');
    return `${prefix}_${slug.substring(0, 15)}_${Math.floor(Math.random() * 1000)}`;
  };

  const handleScanSuccess = (data: any) => {
    const today = new Date().toISOString().split('T')[0];

    // Scenario 0: Template Config (Activation of new induction plan)
    // Handle both Compressed ('z' key) and Uncompressed (legacy 's' key) formats
    if ((data.z) || (data.type === 'TEMPLATE_CONFIG' && data.s)) {
       let rawData: TemplateRawData | null = null;

       // Attempt decompression if 'z' is present
       if (data.z) {
          try {
            // First try Base64 (new optimized format)
            let decompressed = LZString.decompressFromBase64(data.z);

            // Fallback to encodedURIComponent (old format) if base64 yields null
            if (!decompressed) {
              decompressed = LZString.decompressFromEncodedURIComponent(data.z);
            }

            if (decompressed) {
              rawData = JSON.parse(decompressed);
            }
          } catch (e) {
            console.error("Decompression failed", e);
            alert("Virhe luettaessa pakattua koodia.");
            return;
          }
       } else {
         // Fallback to uncompressed
         rawData = data as TemplateRawData;
       }

       if (rawData && rawData.s) {
          if (confirm('Haluatko ottaa käyttöön uuden perehdytysrungon ja -ohjeistuksen? Tämä päivittää nykyisen lomakkeen rakenteen.')) {
            // Un-minify sections and regenerate IDs if missing
            const newSections: Section[] = rawData.s.map((minSec, idx) => ({
              id: minSec.i || generateSlugId(minSec.t, `s${idx}`),
              title: minSec.t,
              subtitle: minSec.s,
              items: minSec.it.map((minItem, iIdx) => ({
                id: minItem.i || generateSlugId(minItem.l, `i${idx}_${iIdx}`),
                label: minItem.l
              }))
            }));

            handleUpdateContent(newSections, rawData.intro);
            alert('Uusi perehdytysrunko aktivoitu onnistuneesti!');
            closeScanner();
          }
       }
       return;
    }

    // Scenario 1: Trainee scanning Supervisor Signature for a SINGLE TASK
    if (scanningTaskId && data.type === 'SUPERVISOR_SIGNATURE' && data.name) {
       handleTaskChange(scanningTaskId, {
         trainerSigned: true,
         trainerName: data.name,
         date: today
       });
       setScanningTaskId(null);
    }
    // Scenario 2: Trainee scanning Supervisor Signature for a WHOLE SECTION
    else if (scanningSectionId && data.type === 'SUPERVISOR_SIGNATURE' && data.name) {
       const section = sections.find(s => s.id === scanningSectionId);
       if (section) {
         const newTasks = { ...tasks };
         section.items.forEach(item => {
           // Update each task in the section
           newTasks[item.id] = {
             ...(newTasks[item.id] || { date: '', traineeSigned: false, trainerSigned: false }),
             trainerSigned: true,
             trainerName: data.name,
             date: today
           };
         });
         setTasks(newTasks);
         saveData(traineeName, newTasks);
       }
       setScanningSectionId(null);
    }
    // Scenario 3: Supervisor scanning Trainee Progress
    else if (isSupervisorScanning && data.type === 'TRAINEE_PROGRESS') {
      setIsSupervisorScanning(false);
      setScannedTraineeData(data);
    }
    // Error / Mismatch handling
    else {
      if ((scanningTaskId || scanningSectionId) && data.type !== 'SUPERVISOR_SIGNATURE') {
         alert("Virhe: Skannasit pelastajan passin. Skannaa esimiehen kuittauskoodi.");
      }
      else if (isSupervisorScanning && data.type !== 'TRAINEE_PROGRESS') {
         alert("Virhe: Skannasit esimiehen koodin. Skannaa pelastajan passi.");
      }
    }
  };

  const closeScanner = () => {
    setScanningTaskId(null);
    setScanningSectionId(null);
    setIsSupervisorScanning(false);
  };

  // Logic to actually wipe data (called by modal)
  const performClearAll = () => {
    const currentSections = sections;
    const currentIntro = introText;
    const currentOrg = orgSettings;

    storageService.clear();

    // Reset state
    setTraineeName('');
    setTasks({});
    setHasCelebrated(false);

    // Restore structure settings (user doesn't want to lose the layout, just the data)
    setSections(currentSections);
    setIntroText(currentIntro);
    setOrgSettings(currentOrg);

    // Immediately save the structure back so it persists
    const freshData: AppData = {
        traineeName: '',
        tasks: {},
        customSections: currentSections,
        introText: currentIntro,
        organizationSettings: currentOrg,
        lastUpdated: new Date().toISOString()
    };
    storageService.save(freshData);

    setShowClearConfirm(false);
  };

  // Standard print (checklist)
  const printForm = () => {
    setIsPrintingCertificate(false);
    // Allow React to update state before printing
    setTimeout(() => window.print(), 100);
  };

  // Certificate print (diploma)
  const printCertificate = () => {
    setIsPrintingCertificate(true);
    setTimeout(() => {
      window.print();
      // Reset after print dialog closes (approximate) or let user switch back manually
      const cleanup = () => setIsPrintingCertificate(false);
      window.addEventListener('afterprint', cleanup, { once: true });
      setTimeout(cleanup, 5000); 
    }, 100);
  };

  // Calculate stats
  const stats = useMemo(() => {
    let total = 0;
    let completed = 0;
    sections.forEach(section => {
      section.items.forEach(item => {
        total++;
        const s = tasks[item.id];
        if (s && s.traineeSigned && s.trainerSigned) {
          completed++;
        }
      });
    });
    return { total, completed, percentage: total === 0 ? 0 : Math.round((completed/total) * 100) };
  }, [tasks, sections]);

  // Check for completion
  useEffect(() => {
    if (stats.percentage === 100 && !hasCelebrated && stats.total > 0) {
      setShowCompletionModal(true);
      setHasCelebrated(true);
    }
  }, [stats.percentage, hasCelebrated, stats.total]);

  // Determine date to show on certificate (today)
  const todayDate = new Date().toLocaleDateString('fi-FI');

  return (
    <>
      {/* CERTIFICATE VIEW (Only visible when printing certificate) */}
      {isPrintingCertificate && (
         <CertificateView 
           traineeName={traineeName} 
           completionDate={todayDate}
           orgSettings={orgSettings} 
         />
      )}

      {/* MAIN APP VIEW (Hidden when printing certificate) */}
      <div className={`min-h-screen bg-gray-100 print:bg-white pb-12 ${isPrintingCertificate ? 'hidden' : 'block'}`}>

        {/* Header Bar */}
        <header className="bg-primary text-white shadow-md sticky top-0 z-20 print:static print:shadow-none print:bg-white print:text-black">
          <div className="max-w-4xl mx-auto px-4 py-3 flex flex-col sm:flex-row items-center justify-between gap-4">

            {/* Logo & Title */}
            <div className="flex items-center gap-3 w-full sm:w-auto">
              <div className="bg-orange-500 p-2 rounded-lg print:hidden">
                <Flame className="w-6 h-6 text-white" />
              </div>
              <div>
                <h1 className="text-lg font-bold leading-tight">Pelastajan Perehdytys</h1>
                <p className="text-xs text-slate-300 print:hidden">Sähköinen seurantalomake</p>
              </div>
            </div>

            {/* Controls */}
            <div className="flex items-center gap-2 w-full sm:w-auto justify-end no-print overflow-x-auto pb-1 sm:pb-0">

              <button
                onClick={() => setShowUserGuide(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-700 hover:bg-slate-600 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-600 whitespace-nowrap mr-2"
                title="Käyttöohjeet"
              >
                <CircleHelp className="w-4 h-4 text-sky-300" />
                <span className="hidden sm:inline">Ohjeet</span>
              </button>

              {stats.percentage === 100 && (
                <button
                  onClick={() => setShowCompletionModal(true)}
                  className="flex items-center gap-1.5 sm:gap-2 bg-yellow-500 hover:bg-yellow-600 text-white px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors shadow-lg animate-pulse font-bold whitespace-nowrap"
                >
                  <Trophy className="w-4 h-4" />
                  <span>Valmis!</span>
                </button>
              )}

              <button
                onClick={() => setShowTraineeBadge(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-800 hover:bg-slate-700 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-700 whitespace-nowrap"
              >
                <UserCheck className="w-4 h-4 text-accent" />
                <span className="sm:hidden">Passi</span>
                <span className="hidden sm:inline">Oma Passi</span>
              </button>

              <div className="w-px h-6 bg-slate-700 mx-0.5 sm:mx-1"></div>

              <button 
                onClick={() => setShowSupervisorBadge(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-800 hover:bg-slate-700 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-700 whitespace-nowrap"
              >
                <QrCode className="w-4 h-4 text-green-400" />
                <span className="sm:hidden">Esimies</span>
                <span className="hidden sm:inline">Esimiestyökalut</span>
              </button>

              <button 
                onClick={printForm}
                className="p-2 bg-slate-800 hover:bg-slate-700 rounded-lg transition-colors text-slate-200"
                title="Tulosta PDF (Lista)"
              >
                <Printer className="w-5 h-5" />
              </button>

              <button 
                onClick={() => setShowClearConfirm(true)}
                className="p-2 bg-red-900/50 hover:bg-red-900 rounded-lg transition-colors text-red-200 ml-1 sm:ml-2"
                title="Tyhjennä lomake (säilyttää rakenteen)"
              >
                <Trash2 className="w-5 h-5" />
              </button>
            </div>
          </div>
        </header>

        <main className="max-w-4xl mx-auto px-4 py-8 print:py-0 print:px-0">

          {/* Name Input & Intro */}
          <div className="bg-white rounded-lg p-6 shadow-sm border border-gray-200 mb-6 print:border-none print:shadow-none print:p-0">

            <div className="mb-6 no-print">
              <label className="block text-xs font-bold uppercase text-slate-500 mb-2">
                Pelastajan Nimi
              </label>
              <div className="relative">
                <input
                  type="text"
                  value={traineeName}
                  onChange={handleNameChange}
                  placeholder="Kirjoita nimesi tähän..."
                  className="w-full text-lg font-bold text-slate-800 border-b-2 border-slate-200 focus:border-accent outline-none py-2 pl-9 bg-transparent transition-colors placeholder:font-normal placeholder:text-gray-300"
                />
                <UserCheck className="w-6 h-6 text-gray-400 absolute left-0 top-2" />
              </div>
            </div>

            {/* Organization Settings Input for Trainee */}
            <div className="mt-4 p-4 bg-gray-50 rounded-lg border border-gray-200 no-print mb-6">
              <h3 className="text-sm font-bold text-gray-500 uppercase mb-3 flex items-center gap-2">
                <FileText className="w-4 h-4" />
                Tiedot
              </h3>
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                <div>
                   <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Organisaatio</label>
                   <div className="relative">
                     <input 
                       type="text" 
                       value={orgSettings.name}
                       onChange={(e) => handleOrgSettingChange('name', e.target.value)}
                       className="w-full pl-7 px-3 py-2 text-sm border border-gray-300 rounded focus:ring-1 focus:ring-accent outline-none bg-white"
                       placeholder="Esim. Hyvinvointialue"
                     />
                     <Building2 className="w-3.5 h-3.5 text-gray-400 absolute left-2.5 top-2.5" />
                   </div>
                </div>
                <div>
                   <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Yksikkö</label>
                   <input 
                     type="text" 
                     value={orgSettings.subtitle}
                     onChange={(e) => handleOrgSettingChange('subtitle', e.target.value)}
                     className="w-full px-3 py-2 text-sm border border-gray-300 rounded focus:ring-1 focus:ring-accent outline-none bg-white"
                     placeholder="Esim. Pelastustoimi"
                   />
                </div>
                <div>
                   <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Paikkakunta</label>
                   <div className="relative">
                     <input 
                       type="text" 
                       value={orgSettings.city}
                       onChange={(e) => handleOrgSettingChange('city', e.target.value)}
                       className="w-full pl-7 px-3 py-2 text-sm border border-gray-300 rounded focus:ring-1 focus:ring-accent outline-none bg-white"
                       placeholder="Esim. Helsinki"
                     />
                     <MapPin className="w-3.5 h-3.5 text-gray-400 absolute left-2.5 top-2.5" />
                   </div>
                </div>
              </div>
            </div>

            <div className="prose prose-sm max-w-none text-slate-600 mb-2 print:text-xs whitespace-pre-line">
              {introText}
            </div>

            {/* Print Header */}
            <div className="hidden print:block mb-8 border-b-2 border-black pb-4">
                <span className="text-sm text-gray-500 uppercase">Pelastaja</span>
                <div className="text-2xl font-bold">{traineeName}</div>
                <div className="mt-2 text-xs text-gray-500">
                  {orgSettings.name} - {orgSettings.subtitle}
                </div>
            </div>
          </div>

          {/* Sticky Progress Bar */}
          <div className="bg-white/95 backdrop-blur rounded-lg p-4 shadow-sm border border-gray-200 mb-8 flex items-center gap-4 no-print sticky top-20 z-10 transition-shadow">
            <div className={`p-2 rounded-full ${stats.percentage === 100 ? 'bg-green-100' : 'bg-gray-100'}`}>
              <CheckCircle className={`w-6 h-6 ${stats.percentage === 100 ? 'text-green-600' : 'text-gray-400'}`} />
            </div>
            <div className="flex-1">
              <div className="flex justify-between items-end mb-1">
                <span className="font-bold text-slate-700">Edistyminen</span>
                <span className="text-sm font-medium text-accent">{stats.completed} / {stats.total} ({stats.percentage}%)</span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2.5">
                <div 
                  className={`h-2.5 rounded-full transition-all duration-700 ${stats.percentage === 100 ? 'bg-green-500' : 'bg-accent'}`}
                  style={{ width: `${stats.percentage}%` }}
                ></div>
              </div>
            </div>
          </div>

          {/* Form Sections (Using state 'sections' instead of constant 'SECTIONS') */}
          <div className="space-y-4">
            {sections.map(section => (
              <SectionGroup 
                key={section.id} 
                section={section} 
                tasks={tasks} 
                traineeName={traineeName}
                onTaskChange={handleTaskChange}
                onScanRequest={handleScanRequest}
                onSectionScanRequest={handleSectionScanRequest}
              />
            ))}
          </div>

          {/* Print Signature Box (Only for list view) */}
          <div className="hidden print:block mt-8 pt-8 border-t-2 border-black page-break">
            {/* Signatures removed per request for the checklist printout, kept simple */}
            <div className="text-center text-xs text-gray-500">
              Tulostettu: {todayDate} - {orgSettings.city}
            </div>
          </div>

        </main>

        {/* Modals */}
        {showClearConfirm && (
          <ClearConfirmationModal 
            onConfirm={performClearAll} 
            onClose={() => setShowClearConfirm(false)} 
          />
        )}

        {showSupervisorBadge && (
          <SupervisorBadge 
            onClose={() => setShowSupervisorBadge(false)} 
            onScanRequest={handleSupervisorScanRequest}
            onEditContent={() => setShowEditor(true)}
            currentSections={sections}
            currentIntroText={introText}
          />
        )}

        {showEditor && (
          <ContentEditorModal 
            initialSections={sections}
            initialIntroText={introText}
            onSave={handleUpdateContent}
            onReset={handleResetContent}
            onClose={() => setShowEditor(false)}
          />
        )}

        {showUserGuide && (
          <UserGuideModal onClose={() => setShowUserGuide(false)} />
        )}

        {showTraineeBadge && (
          <TraineeBadge 
            traineeName={traineeName}
            tasks={tasks}
            onClose={() => setShowTraineeBadge(false)}
          />
        )}

        {scannedTraineeData && (
          <TraineeReportModal 
            data={scannedTraineeData}
            onClose={() => setScannedTraineeData(null)}
          />
        )}

        {showCompletionModal && (
          <CompletionModal
            traineeName={traineeName}
            onClose={() => setShowCompletionModal(false)}
            onPrint={printCertificate} 
          />
        )}

        {(scanningTaskId || scanningSectionId || isSupervisorScanning) && (
          <ScannerModal 
            onScanSuccess={handleScanSuccess} 
            onClose={closeScanner} 
          />
        )}

      </div>
    </>
  );
};

export default App;

import React, { useState } from 'react';
import { Section, TaskItem } from '../types';
import { X, Trash2, Plus, Save, RotateCcw, ChevronRight, ChevronDown, Pencil, Check, AlignLeft, Type } from 'lucide-react';
import { DEFAULT_INTRO_TEXT } from '../constants';

interface ContentEditorModalProps {
  initialSections: Section[];
  initialIntroText: string;
  onSave: (newSections: Section[], newIntroText: string) => void;
  onReset: () => void;
  onClose: () => void;
}

// Helper type to track what is being edited
type EditTarget = 
  | { type: 'section_title'; id: string }
  | { type: 'section_subtitle'; id: string }
  | { type: 'item_label'; sectionId: string; itemId: string }
  | null;

export const ContentEditorModal: React.FC<ContentEditorModalProps> = ({ initialSections, initialIntroText, onSave, onReset, onClose }) => {
  const [sections, setSections] = useState<Section[]>(JSON.parse(JSON.stringify(initialSections)));
  const [introText, setIntroText] = useState(initialIntroText);

  const [expandedSection, setExpandedSection] = useState<string | null>(null);

  // State for adding new items
  const [newItemText, setNewItemText] = useState<string>('');
  const [activeAddSectionId, setActiveAddSectionId] = useState<string | null>(null);

  // State for adding new sections
  const [isAddingSection, setIsAddingSection] = useState(false);
  const [newSectionTitle, setNewSectionTitle] = useState('');

  // State for editing existing text
  const [editTarget, setEditTarget] = useState<EditTarget>(null);
  const [editText, setEditText] = useState('');

  const toggleSection = (id: string) => {
    // Don't toggle if we are editing
    if (editTarget && (editTarget.type === 'section_title' || editTarget.type === 'section_subtitle') && editTarget.id === id) return;
    setExpandedSection(expandedSection === id ? null : id);
  };

  // --- DELETE LOGIC ---

  const handleDeleteSection = (sectionId: string) => {
    if (confirm("Haluatko varmasti poistaa koko kategorian ja kaikki sen sisältämät kohdat?")) {
      setSections(prev => prev.filter(s => s.id !== sectionId));
    }
  };

  const handleDeleteItem = (sectionId: string, itemId: string) => {
    if (!confirm("Haluatko varmasti poistaa tämän kohdan?")) return;

    setSections(prev => prev.map(sec => {
      if (sec.id !== sectionId) return sec;
      return {
        ...sec,
        items: sec.items.filter(item => item.id !== itemId)
      };
    }));
  };

  // --- ADD LOGIC ---

  const handleAddItem = (sectionId: string) => {
    if (!newItemText.trim()) return;

    const newItem: TaskItem = {
      id: `custom_item_${Date.now()}_${Math.floor(Math.random() * 1000)}`,
      label: newItemText.trim()
    };

    setSections(prev => prev.map(sec => {
      if (sec.id !== sectionId) return sec;
      return {
        ...sec,
        items: [...sec.items, newItem]
      };
    }));

    setNewItemText('');
    setActiveAddSectionId(null);
  };

  const handleAddSection = () => {
    if (!newSectionTitle.trim()) return;

    const newSection: Section = {
      id: `custom_section_${Date.now()}`,
      title: newSectionTitle.trim(),
      items: []
    };

    setSections(prev => [...prev, newSection]);
    setNewSectionTitle('');
    setIsAddingSection(false);
    // Automatically expand the new section
    setExpandedSection(newSection.id);
  };

  // --- EDIT LOGIC ---

  const startEdit = (target: EditTarget, currentText: string) => {
    setEditTarget(target);
    setEditText(currentText || '');
  };

  const saveEdit = () => {
    if (!editTarget) {
      setEditTarget(null);
      return;
    }

    if (editTarget.type === 'section_title') {
      if (!editText.trim()) return; // Don't allow empty titles
      setSections(prev => prev.map(sec => 
        sec.id === editTarget.id ? { ...sec, title: editText.trim() } : sec
      ));
    } else if (editTarget.type === 'section_subtitle') {
      // Allow empty subtitles (it just removes it)
      setSections(prev => prev.map(sec => 
        sec.id === editTarget.id ? { ...sec, subtitle: editText.trim() } : sec
      ));
    } else if (editTarget.type === 'item_label') {
      if (!editText.trim()) return; // Don't allow empty labels
      setSections(prev => prev.map(sec => {
        if (sec.id !== editTarget.sectionId) return sec;
        return {
          ...sec,
          items: sec.items.map(item => 
            item.id === editTarget.itemId ? { ...item, label: editText.trim() } : item
          )
        };
      }));
    }

    setEditTarget(null);
    setEditText('');
  };

  const cancelEdit = () => {
    setEditTarget(null);
    setEditText('');
  };

  // --- GENERAL ---

  const handleSave = () => {
    onSave(sections, introText);
    onClose();
  };

  const handleReset = () => {
    if (confirm("Tämä palauttaa lomakkeen alkuperäiseen tilaan (sisältö ja tekstit). Oletko varma?")) {
      setIntroText(DEFAULT_INTRO_TEXT);
      onReset();
      onClose();
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl w-full max-w-2xl overflow-hidden shadow-2xl flex flex-col max-h-[90vh] animate-in fade-in zoom-in duration-200">

        {/* Header */}
        <div className="bg-slate-800 p-4 flex justify-between items-center text-white shrink-0">
          <h3 className="font-bold text-lg">Muokkaa lomakkeen sisältöä</h3>
          <button onClick={onClose} className="p-1 hover:bg-slate-700 rounded-full transition-colors">
            <X className="w-6 h-6" />
          </button>
        </div>

        {/* Info Banner */}
        <div className="bg-yellow-50 p-4 border-b border-yellow-100 text-sm text-yellow-800 shrink-0">
          Voit muokata johdantotekstiä, otsikoita ja perehdytyskohtia. Muutokset tallentuvat tälle laitteelle.
        </div>

        {/* Content List */}
        <div className="flex-1 overflow-y-auto p-4 space-y-6 bg-gray-50">

          {/* Intro Text Editor */}
          <div className="bg-white rounded-lg border border-gray-200 shadow-sm p-4">
            <h4 className="flex items-center gap-2 font-bold text-slate-700 mb-2">
              <AlignLeft className="w-4 h-4" />
              Yleinen esittelyteksti (nimen alla)
            </h4>
            <textarea 
              value={introText}
              onChange={(e) => setIntroText(e.target.value)}
              className="w-full h-32 p-3 text-sm border border-gray-300 rounded focus:ring-2 focus:ring-accent outline-none resize-y"
              placeholder="Kirjoita ohjeistus tähän..."
            />
            <div className="text-xs text-gray-400 mt-1">Tämä teksti näkyy pelastajan nimen alla heti lomakkeen alussa.</div>
          </div>

          <hr className="border-gray-200" />

          <div>
            <h4 className="font-bold text-slate-700 mb-3 px-1">Lomakkeen osiot</h4>
            {sections.length === 0 && (
              <div className="text-center p-8 text-gray-400 italic border-2 border-dashed border-gray-200 rounded-lg">
                Ei kategorioita. Lisää uusi kategoria alta tai palauta oletukset.
              </div>
            )}

            <div className="space-y-3">
              {sections.map(section => (
                <div key={section.id} className="bg-white rounded-lg border border-gray-200 shadow-sm overflow-hidden">

                  {/* Section Header Row */}
                  <div className="flex items-stretch bg-white hover:bg-gray-50 transition-colors border-b border-gray-100 last:border-0 min-h-[60px]">

                    {/* Editing Title Mode */}
                    {editTarget?.type === 'section_title' && editTarget.id === section.id ? (
                      <div className="flex-1 px-4 py-3 flex flex-col justify-center bg-blue-50">
                        <label className="text-xs font-bold text-blue-600 mb-1">Muokkaa otsikkoa</label>
                        <div className="flex items-center gap-2">
                          <input 
                            type="text" 
                            value={editText}
                            onChange={(e) => setEditText(e.target.value)}
                            className="flex-1 px-2 py-1 text-sm border border-blue-300 rounded focus:outline-none focus:ring-2 focus:ring-blue-500"
                            autoFocus
                            onKeyDown={(e) => {
                              if (e.key === 'Enter') saveEdit();
                              if (e.key === 'Escape') cancelEdit();
                            }}
                          />
                          <button onClick={saveEdit} className="p-1 bg-green-500 text-white rounded hover:bg-green-600"><Check className="w-4 h-4" /></button>
                          <button onClick={cancelEdit} className="p-1 bg-gray-400 text-white rounded hover:bg-gray-500"><X className="w-4 h-4" /></button>
                        </div>
                      </div>
                    ) : editTarget?.type === 'section_subtitle' && editTarget.id === section.id ? (
                      /* Editing Subtitle Mode */
                      <div className="flex-1 px-4 py-3 flex flex-col justify-center bg-blue-50">
                        <label className="text-xs font-bold text-blue-600 mb-1">Muokkaa alaotsikkoa</label>
                        <div className="flex items-center gap-2">
                          <input 
                            type="text" 
                            value={editText}
                            onChange={(e) => setEditText(e.target.value)}
                            className="flex-1 px-2 py-1 text-sm border border-blue-300 rounded focus:outline-none focus:ring-2 focus:ring-blue-500"
                            autoFocus
                            placeholder="Esim. (vuoropäivinä)"
                            onKeyDown={(e) => {
                              if (e.key === 'Enter') saveEdit();
                              if (e.key === 'Escape') cancelEdit();
                            }}
                          />
                          <button onClick={saveEdit} className="p-1 bg-green-500 text-white rounded hover:bg-green-600"><Check className="w-4 h-4" /></button>
                          <button onClick={cancelEdit} className="p-1 bg-gray-400 text-white rounded hover:bg-gray-500"><X className="w-4 h-4" /></button>
                        </div>
                      </div>
                    ) : (
                      // Display Mode (Title + Subtitle)
                      <div 
                        onClick={() => toggleSection(section.id)}
                        className="flex-1 px-4 py-3 flex items-center justify-between text-left group cursor-pointer"
                      >
                        <div className="flex flex-col gap-1 w-full">
                          {/* Title Row */}
                          <div className="flex items-center gap-2">
                            <span className="font-bold text-slate-800">{section.title}</span>
                            <span className="text-xs text-gray-400 bg-gray-100 px-2 py-0.5 rounded-full">
                              {section.items.length}
                            </span>
                            <button 
                              onClick={(e) => {
                                e.stopPropagation();
                                startEdit({ type: 'section_title', id: section.id }, section.title);
                              }}
                              className="p-1 text-gray-300 hover:text-blue-500 hover:bg-blue-50 rounded opacity-0 group-hover:opacity-100 transition-all"
                              title="Muokkaa otsikkoa"
                            >
                              <Pencil className="w-3.5 h-3.5" />
                            </button>
                          </div>

                          {/* Subtitle Row */}
                          <div className="flex items-center gap-2">
                             <div 
                               className={`text-sm flex items-center gap-2 ${section.subtitle ? 'text-gray-500' : 'text-gray-300 italic'}`}
                             >
                               <span className="truncate max-w-[250px] sm:max-w-md">
                                 {section.subtitle || "Ei alaotsikkoa"}
                               </span>
                             </div>
                             <button
                               onClick={(e) => {
                                 e.stopPropagation();
                                 startEdit({ type: 'section_subtitle', id: section.id }, section.subtitle || '');
                               }}
                               className="p-1 text-gray-300 hover:text-blue-500 hover:bg-blue-50 rounded opacity-0 group-hover:opacity-100 transition-all flex items-center gap-1"
                               title="Muokkaa alaotsikkoa"
                             >
                               <Type className="w-3 h-3" />
                               {!section.subtitle && <span className="text-[10px]">Lisää</span>}
                             </button>
                          </div>
                        </div>
                        {expandedSection === section.id ? <ChevronDown className="w-5 h-5 text-gray-400 shrink-0 ml-2" /> : <ChevronRight className="w-5 h-5 text-gray-400 shrink-0 ml-2" />}
                      </div>
                    )}

                    {/* Delete Section Button */}
                    {(!editTarget || (editTarget.type !== 'section_title' && editTarget.type !== 'section_subtitle') || editTarget.id !== section.id) && (
                      <button 
                        onClick={() => handleDeleteSection(section.id)}
                        className="px-4 flex items-center justify-center text-gray-400 hover:text-red-600 hover:bg-red-50 border-l border-gray-100 transition-colors"
                        title="Poista koko kategoria"
                      >
                        <Trash2 className="w-5 h-5" />
                      </button>
                    )}
                  </div>

                  {/* Items List */}
                  {expandedSection === section.id && (
                    <div className="border-t border-gray-100 divide-y divide-gray-50 bg-gray-50/50">
                      {section.items.map(item => (
                        <div key={item.id} className="px-4 py-3 flex items-center justify-between group hover:bg-slate-50 pl-8 border-l-4 border-l-transparent hover:border-l-accent transition-all min-h-[44px]">

                          {/* Editing Item Mode */}
                          {editTarget?.type === 'item_label' && editTarget.itemId === item.id ? (
                            <div className="flex-1 flex items-center gap-2">
                              <input 
                                type="text" 
                                value={editText}
                                onChange={(e) => setEditText(e.target.value)}
                                className="flex-1 px-2 py-1 text-sm border border-blue-300 rounded focus:outline-none focus:ring-2 focus:ring-blue-500"
                                autoFocus
                                onKeyDown={(e) => {
                                  if (e.key === 'Enter') saveEdit();
                                  if (e.key === 'Escape') cancelEdit();
                                }}
                              />
                              <button onClick={saveEdit} className="p-1 bg-green-500 text-white rounded hover:bg-green-600"><Check className="w-4 h-4" /></button>
                              <button onClick={cancelEdit} className="p-1 bg-gray-400 text-white rounded hover:bg-gray-500"><X className="w-4 h-4" /></button>
                            </div>
                          ) : (
                            // Display Item Mode
                            <>
                              <div className="flex items-center gap-2 flex-1">
                                <span className="text-sm text-slate-700">{item.label}</span>
                                <button 
                                  onClick={() => startEdit({ type: 'item_label', sectionId: section.id, itemId: item.id }, item.label)}
                                  className="p-1 text-gray-300 hover:text-blue-500 hover:bg-blue-50 rounded opacity-0 group-hover:opacity-100 transition-all"
                                  title="Muokkaa tekstiä"
                                >
                                  <Pencil className="w-3 h-3" />
                                </button>
                              </div>

                              <button 
                                onClick={() => handleDeleteItem(section.id, item.id)}
                                className="p-1.5 text-red-300 hover:text-red-600 hover:bg-red-50 rounded transition-colors ml-2"
                                title="Poista kohta"
                              >
                                <Trash2 className="w-4 h-4" />
                              </button>
                            </>
                          )}
                        </div>
                      ))}

                      {/* Add New Item Input */}
                      <div className="p-3 bg-gray-50 pl-8">
                        {activeAddSectionId === section.id ? (
                          <div className="flex gap-2">
                            <input
                              type="text"
                              value={newItemText}
                              onChange={(e) => setNewItemText(e.target.value)}
                              placeholder="Kirjoita uuden kohdan nimi..."
                              className="flex-1 px-3 py-2 text-sm border rounded focus:ring-2 focus:ring-accent outline-none"
                              autoFocus
                              onKeyDown={(e) => e.key === 'Enter' && handleAddItem(section.id)}
                            />
                            <button 
                              onClick={() => handleAddItem(section.id)}
                              className="px-3 py-2 bg-green-600 text-white rounded text-sm font-bold hover:bg-green-700"
                            >
                              Lisää
                            </button>
                            <button 
                              onClick={() => setActiveAddSectionId(null)}
                              className="px-3 py-2 bg-gray-200 text-gray-600 rounded text-sm hover:bg-gray-300"
                            >
                              Peru
                            </button>
                          </div>
                        ) : (
                          <button 
                            onClick={() => {
                              setActiveAddSectionId(section.id);
                              setNewItemText('');
                            }}
                            className="w-full py-2 border-2 border-dashed border-gray-300 rounded text-gray-500 text-sm font-bold hover:border-accent hover:text-accent hover:bg-white transition-all flex items-center justify-center gap-2"
                          >
                            <Plus className="w-4 h-4" />
                            Lisää uusi kohta
                          </button>
                        )}
                      </div>
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>

          {/* ADD NEW SECTION BLOCK */}
          <div className="mt-6 border-t pt-4">
             {isAddingSection ? (
               <div className="bg-white p-4 rounded-lg border-2 border-accent shadow-sm">
                  <h4 className="text-sm font-bold text-slate-700 mb-2">Uusi Kategoria</h4>
                  <div className="flex gap-2">
                    <input
                      type="text"
                      value={newSectionTitle}
                      onChange={(e) => setNewSectionTitle(e.target.value)}
                      placeholder="Esim. Erikoiskalusto..."
                      className="flex-1 px-3 py-2 border rounded focus:ring-2 focus:ring-accent outline-none"
                      autoFocus
                      onKeyDown={(e) => e.key === 'Enter' && handleAddSection()}
                    />
                    <button 
                      onClick={handleAddSection}
                      className="px-4 py-2 bg-accent text-white rounded font-bold hover:bg-sky-600"
                    >
                      Luo
                    </button>
                    <button 
                      onClick={() => setIsAddingSection(false)}
                      className="px-4 py-2 bg-gray-200 text-gray-600 rounded font-bold hover:bg-gray-300"
                    >
                      Peru
                    </button>
                  </div>
               </div>
             ) : (
                <button
                  onClick={() => {
                    setIsAddingSection(true);
                    setNewSectionTitle('');
                  }}
                  className="w-full py-3 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-lg border border-slate-300 border-dashed font-bold flex items-center justify-center gap-2 transition-colors"
                >
                  <Plus className="w-5 h-5" />
                  Lisää uusi kategoria
                </button>
             )}
          </div>

        </div>

        {/* Footer Actions */}
        <div className="p-4 bg-white border-t border-gray-200 flex justify-between items-center shrink-0">
          <button 
            onClick={handleReset}
            className="flex items-center gap-2 text-red-600 hover:text-red-700 text-sm font-bold px-4 py-2 hover:bg-red-50 rounded-lg transition-colors"
          >
            <RotateCcw className="w-4 h-4" />
            Palauta oletukset
          </button>

          <div className="flex gap-3">
            <button 
              onClick={onClose}
              className="px-4 py-2 text-slate-600 hover:bg-gray-100 rounded-lg font-bold transition-colors"
            >
              Peruuta
            </button>
            <button 
              onClick={handleSave}
              className="px-6 py-2 bg-slate-800 text-white rounded-lg font-bold hover:bg-slate-700 shadow-lg flex items-center gap-2"
            >
              <Save className="w-4 h-4" />
              Tallenna muutokset
            </button>
          </div>
        </div>

      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import LZString from 'lz-string';
import { SECTIONS, DEFAULT_INTRO_TEXT, DEFAULT_ORG_SETTINGS } from './constants';
import { TaskState, TraineeQrData, Section, OrganizationSettings, TemplateQrData, TemplateRawData } from './types';
import { SectionGroup } from './components/SectionGroup';
import { storageService, AppData } from './storage';
import { SupervisorBadge } from './components/SupervisorBadge';
import { ScannerModal } from './components/ScannerModal';
import { TraineeBadge } from './components/TraineeBadge';
import { TraineeReportModal } from './components/TraineeReportModal';
import { CompletionModal } from './components/CompletionModal';
import { CertificateView } from './components/CertificateView';
import { ContentEditorModal } from './components/ContentEditorModal';
import { UserGuideModal } from './components/UserGuideModal';
import { ClearConfirmationModal } from './components/ClearConfirmationModal';
import { Printer, Flame, CheckCircle, QrCode, Trash2, UserCheck, Trophy, CircleHelp, Building2, MapPin, FileText, Download } from 'lucide-react';

const App: React.FC = () => {
  // Data State
  const [traineeName, setTraineeName] = useState('');
  const [tasks, setTasks] = useState<Record<string, TaskState>>({});
  const [sections, setSections] = useState<Section[]>(SECTIONS);
  const [introText, setIntroText] = useState(DEFAULT_INTRO_TEXT);
  const [orgSettings, setOrgSettings] = useState<OrganizationSettings>(DEFAULT_ORG_SETTINGS);

  // UI State
  const [showSupervisorBadge, setShowSupervisorBadge] = useState(false);
  const [showTraineeBadge, setShowTraineeBadge] = useState(false);
  const [showCompletionModal, setShowCompletionModal] = useState(false);
  const [showEditor, setShowEditor] = useState(false);
  const [showUserGuide, setShowUserGuide] = useState(false);
  const [showClearConfirm, setShowClearConfirm] = useState(false);
  const [isPrintingCertificate, setIsPrintingCertificate] = useState(false);

  // Keep track if we've already shown the celebration once per session to avoid annoyance
  const [hasCelebrated, setHasCelebrated] = useState(false);

  // Scan States
  const [scanningTaskId, setScanningTaskId] = useState<string | null>(null);
  const [scanningSectionId, setScanningSectionId] = useState<string | null>(null);
  const [isSupervisorScanning, setIsSupervisorScanning] = useState(false);
  const [isGenericScanning, setIsGenericScanning] = useState(false);

  const [scannedTraineeData, setScannedTraineeData] = useState<TraineeQrData | null>(null);

  // Load data on mount
  useEffect(() => {
    const data = storageService.load();
    setTraineeName(data.traineeName);
    setTasks(data.tasks);
    if (data.customSections && data.customSections.length > 0) {
      setSections(data.customSections);
    }
    if (data.introText) {
      setIntroText(data.introText);
    }
    if (data.organizationSettings) {
      setOrgSettings(data.organizationSettings);
    }
  }, []);

  // Save data on change
  const saveData = (
    newName: string, 
    newTasks: Record<string, TaskState>, 
    newSections?: Section[], 
    newIntroText?: string,
    newOrgSettings?: OrganizationSettings
  ) => {
    const data: AppData = {
      traineeName: newName,
      tasks: newTasks,
      customSections: newSections || sections,
      introText: newIntroText || introText,
      organizationSettings: newOrgSettings || orgSettings,
      lastUpdated: new Date().toISOString()
    };
    storageService.save(data);
  };

  const handleNameChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newName = e.target.value;
    setTraineeName(newName);
    saveData(newName, tasks);
  };

  const handleOrgSettingChange = (field: keyof OrganizationSettings, value: string) => {
    const newSettings = { ...orgSettings, [field]: value };
    setOrgSettings(newSettings);
    saveData(traineeName, tasks, sections, introText, newSettings);
  };

  const handleTaskChange = (taskId: string, updates: Partial<TaskState>) => {
    const newTasks = {
      ...tasks,
      [taskId]: {
        ...(tasks[taskId] || { date: '', traineeSigned: false, trainerSigned: false }),
        ...updates
      }
    };
    setTasks(newTasks);
    saveData(traineeName, newTasks);
  };

  const handleUpdateContent = (newSections: Section[], newIntroText: string) => {
    setSections(newSections);
    setIntroText(newIntroText);
    // Don't update orgSettings here, as they are now handled by the trainee in the main view
    saveData(traineeName, tasks, newSections, newIntroText, orgSettings);
  };

  const handleResetContent = () => {
    setSections(SECTIONS);
    setIntroText(DEFAULT_INTRO_TEXT);
    setOrgSettings(DEFAULT_ORG_SETTINGS);
    saveData(traineeName, tasks, SECTIONS, DEFAULT_INTRO_TEXT, DEFAULT_ORG_SETTINGS);
  };

  const handleScanRequest = (taskId: string) => {
    setScanningTaskId(taskId);
  };

  const handleSectionScanRequest = (sectionId: string) => {
    setScanningSectionId(sectionId);
  };

  const handleSupervisorScanRequest = () => {
    setIsSupervisorScanning(true);
  };

  const handleGenericScanRequest = () => {
    setIsGenericScanning(true);
  };

  // Helper to generate IDs for imported content
  const generateSlugId = (text: string, prefix: string) => {
    const slug = text.toLowerCase()
      .replace(/ä/g, 'a').replace(/ö/g, 'o').replace(/å/g, 'a')
      .replace(/[^a-z0-9]/g, '_')
      .replace(/_+/g, '_');
    return `${prefix}_${slug.substring(0, 15)}_${Math.floor(Math.random() * 1000)}`;
  };

  const handleScanSuccess = (data: any) => {
    const today = new Date().toISOString().split('T')[0];

    // Scenario 0: Template Config (Activation of new induction plan)
    // Handle both Compressed ('z' key) and Uncompressed (legacy 's' key) formats
    if ((data.z) || (data.type === 'TEMPLATE_CONFIG' && data.s)) {
       let rawData: TemplateRawData | null = null;

       // Attempt decompression if 'z' is present
       if (data.z) {
          try {
            // First try Base64 (new optimized format)
            let decompressed = LZString.decompressFromBase64(data.z);

            // Fallback to encodedURIComponent (old format) if base64 yields null
            if (!decompressed) {
              decompressed = LZString.decompressFromEncodedURIComponent(data.z);
            }

            if (decompressed) {
              rawData = JSON.parse(decompressed);
            }
          } catch (e) {
            console.error("Decompression failed", e);
            alert("Virhe luettaessa pakattua koodia.");
            return;
          }
       } else {
         // Fallback to uncompressed
         rawData = data as TemplateRawData;
       }

       if (rawData && rawData.s) {
          if (confirm('Haluatko ottaa käyttöön uuden perehdytysrungon ja -ohjeistuksen? Tämä päivittää nykyisen lomakkeen rakenteen.')) {
            // Un-minify sections and regenerate IDs if missing
            const newSections: Section[] = rawData.s.map((minSec, idx) => ({
              id: minSec.i || generateSlugId(minSec.t, `s${idx}`),
              title: minSec.t,
              subtitle: minSec.s,
              items: minSec.it.map((minItem, iIdx) => ({
                id: minItem.i || generateSlugId(minItem.l, `i${idx}_${iIdx}`),
                label: minItem.l
              }))
            }));

            handleUpdateContent(newSections, rawData.intro);
            alert('Uusi perehdytysrunko aktivoitu onnistuneesti!');
            closeScanner();
          }
       }
       return;
    }

    // Scenario 1: Trainee scanning Supervisor Signature for a SINGLE TASK
    if (scanningTaskId && data.type === 'SUPERVISOR_SIGNATURE' && data.name) {
       handleTaskChange(scanningTaskId, {
         trainerSigned: true,
         trainerName: data.name,
         date: today
       });
       setScanningTaskId(null);
    }
    // Scenario 2: Trainee scanning Supervisor Signature for a WHOLE SECTION
    else if (scanningSectionId && data.type === 'SUPERVISOR_SIGNATURE' && data.name) {
       const section = sections.find(s => s.id === scanningSectionId);
       if (section) {
         const newTasks = { ...tasks };
         section.items.forEach(item => {
           // Update each task in the section
           newTasks[item.id] = {
             ...(newTasks[item.id] || { date: '', traineeSigned: false, trainerSigned: false }),
             trainerSigned: true,
             trainerName: data.name,
             date: today
           };
         });
         setTasks(newTasks);
         saveData(traineeName, newTasks);
       }
       setScanningSectionId(null);
    }
    // Scenario 3: Supervisor scanning Trainee Progress
    else if (isSupervisorScanning && data.type === 'TRAINEE_PROGRESS') {
      setIsSupervisorScanning(false);
      setScannedTraineeData(data);
    }
    // Error / Mismatch handling
    else {
      if ((scanningTaskId || scanningSectionId) && data.type !== 'SUPERVISOR_SIGNATURE') {
         alert("Virhe: Skannasit pelastajan passin. Skannaa esimiehen kuittauskoodi.");
      }
      else if (isSupervisorScanning && data.type !== 'TRAINEE_PROGRESS') {
         alert("Virhe: Skannasit esimiehen koodin. Skannaa pelastajan passi.");
      }
      else if (isGenericScanning && data.type === 'SUPERVISOR_SIGNATURE') {
         alert("Tämä on kuittauskoodi. Skannaa tämä koodi kun olet valinnut tietyn tehtävän kuitattavaksi.");
      }
    }
  };

  const closeScanner = () => {
    setScanningTaskId(null);
    setScanningSectionId(null);
    setIsSupervisorScanning(false);
    setIsGenericScanning(false);
  };

  // Logic to actually wipe data (called by modal)
  const performClearAll = () => {
    const currentSections = sections;
    const currentIntro = introText;
    const currentOrg = orgSettings;

    storageService.clear();

    // Reset state
    setTraineeName('');
    setTasks({});
    setHasCelebrated(false);

    // Restore structure settings (user doesn't want to lose the layout, just the data)
    setSections(currentSections);
    setIntroText(currentIntro);
    setOrgSettings(currentOrg);

    // Immediately save the structure back so it persists
    const freshData: AppData = {
        traineeName: '',
        tasks: {},
        customSections: currentSections,
        introText: currentIntro,
        organizationSettings: currentOrg,
        lastUpdated: new Date().toISOString()
    };
    storageService.save(freshData);

    setShowClearConfirm(false);
  };

  // Standard print (checklist)
  const printForm = () => {
    setIsPrintingCertificate(false);
    // Allow React to update state before printing
    setTimeout(() => window.print(), 100);
  };

  // Certificate print (diploma)
  const printCertificate = () => {
    setIsPrintingCertificate(true);
    setTimeout(() => {
      window.print();
      // Reset after print dialog closes (approximate) or let user switch back manually
      const cleanup = () => setIsPrintingCertificate(false);
      window.addEventListener('afterprint', cleanup, { once: true });
      setTimeout(cleanup, 5000); 
    }, 100);
  };

  // Calculate stats
  const stats = useMemo(() => {
    let total = 0;
    let completed = 0;
    sections.forEach(section => {
      section.items.forEach(item => {
        total++;
        const s = tasks[item.id];
        if (s && s.traineeSigned && s.trainerSigned) {
          completed++;
        }
      });
    });
    return { total, completed, percentage: total === 0 ? 0 : Math.round((completed/total) * 100) };
  }, [tasks, sections]);

  // Check for completion
  useEffect(() => {
    if (stats.percentage === 100 && !hasCelebrated && stats.total > 0) {
      setShowCompletionModal(true);
      setHasCelebrated(true);
    }
  }, [stats.percentage, hasCelebrated, stats.total]);

  // Determine date to show on certificate (today)
  const todayDate = new Date().toLocaleDateString('fi-FI');

  return (
    <>
      {/* CERTIFICATE VIEW (Only visible when printing certificate) */}
      {isPrintingCertificate && (
         <CertificateView 
           traineeName={traineeName} 
           completionDate={todayDate}
           orgSettings={orgSettings} 
         />
      )}

      {/* MAIN APP VIEW (Hidden when printing certificate) */}
      <div className={`min-h-screen bg-gray-100 print:bg-white pb-12 ${isPrintingCertificate ? 'hidden' : 'block'}`}>

        {/* Header Bar */}
        <header className="bg-primary text-white shadow-md sticky top-0 z-20 print:static print:shadow-none print:bg-white print:text-black">
          <div className="max-w-4xl mx-auto px-4 py-3 flex flex-col sm:flex-row items-center justify-between gap-4">

            {/* Logo & Title */}
            <div className="flex items-center gap-3 w-full sm:w-auto">
              <div className="bg-orange-500 p-2 rounded-lg print:hidden">
                <Flame className="w-6 h-6 text-white" />
              </div>
              <div>
                <h1 className="text-lg font-bold leading-tight">Pelastajan Perehdytys</h1>
                <p className="text-xs text-slate-300 print:hidden">Sähköinen seurantalomake</p>
              </div>
            </div>

            {/* Controls */}
            <div className="flex items-center gap-2 w-full sm:w-auto justify-end no-print overflow-x-auto pb-1 sm:pb-0">

              <button
                onClick={() => setShowUserGuide(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-700 hover:bg-slate-600 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-600 whitespace-nowrap mr-2"
                title="Käyttöohjeet"
              >
                <CircleHelp className="w-4 h-4 text-sky-300" />
                <span className="hidden sm:inline">Ohjeet</span>
              </button>

              {stats.percentage === 100 && (
                <button
                  onClick={() => setShowCompletionModal(true)}
                  className="flex items-center gap-1.5 sm:gap-2 bg-yellow-500 hover:bg-yellow-600 text-white px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors shadow-lg animate-pulse font-bold whitespace-nowrap"
                >
                  <Trophy className="w-4 h-4" />
                  <span>Valmis!</span>
                </button>
              )}

              <button
                onClick={() => setShowTraineeBadge(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-800 hover:bg-slate-700 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-700 whitespace-nowrap"
              >
                <UserCheck className="w-4 h-4 text-accent" />
                <span className="sm:hidden">Passi</span>
                <span className="hidden sm:inline">Oma Passi</span>
              </button>

              <div className="w-px h-6 bg-slate-700 mx-0.5 sm:mx-1"></div>

              <button 
                onClick={() => setShowSupervisorBadge(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-800 hover:bg-slate-700 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-700 whitespace-nowrap"
              >
                <QrCode className="w-4 h-4 text-green-400" />
                <span className="sm:hidden">Esimies</span>
                <span className="hidden sm:inline">Esimiestyökalut</span>
              </button>

              <button 
                onClick={printForm}
                className="p-2 bg-slate-800 hover:bg-slate-700 rounded-lg transition-colors text-slate-200"
                title="Tulosta PDF (Lista)"
              >
                <Printer className="w-5 h-5" />
              </button>

              <button 
                onClick={handleGenericScanRequest}
                className="p-2 bg-slate-800 hover:bg-slate-700 rounded-lg transition-colors text-sky-200"
                title="Lue uusi perehdytysrunko (QR)"
              >
                <Download className="w-5 h-5" />
              </button>

              <button 
                onClick={() => setShowClearConfirm(true)}
                className="p-2 bg-red-900/50 hover:bg-red-900 rounded-lg transition-colors text-red-200 ml-1 sm:ml-2"
                title="Tyhjennä lomake (säilyttää rakenteen)"
              >
                <Trash2 className="w-5 h-5" />
              </button>
            </div>
          </div>
        </header>

        <main className="max-w-4xl mx-auto px-4 py-8 print:py-0 print:px-0">

          {/* Name Input & Intro */}
          <div className="bg-white rounded-lg p-6 shadow-sm border border-gray-200 mb-6 print:border-none print:shadow-none print:p-0">

            <div className="mb-6 no-print">
              <label className="block text-xs font-bold uppercase text-slate-500 mb-2">
                Pelastajan Nimi
              </label>
              <div className="relative">
                <input
                  type="text"
                  value={traineeName}
                  onChange={handleNameChange}
                  placeholder="Kirjoita nimesi tähän..."
                  className="w-full text-lg font-bold text-slate-800 border-b-2 border-slate-200 focus:border-accent outline-none py-2 pl-9 bg-transparent transition-colors placeholder:font-normal placeholder:text-gray-300"
                />
                <UserCheck className="w-6 h-6 text-gray-400 absolute left-0 top-2" />
              </div>
            </div>

            {/* Organization Settings Input for Trainee */}
            <div className="mt-4 p-4 bg-gray-50 rounded-lg border border-gray-200 no-print mb-6">
              <h3 className="text-sm font-bold text-gray-500 uppercase mb-3 flex items-center gap-2">
                <FileText className="w-4 h-4" />
                Tiedot
              </h3>
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                <div>
                   <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Organisaatio</label>
                   <div className="relative">
                     <input 
                       type="text" 
                       value={orgSettings.name}
                       onChange={(e) => handleOrgSettingChange('name', e.target.value)}
                       className="w-full pl-7 px-3 py-2 text-sm border border-gray-300 rounded focus:ring-1 focus:ring-accent outline-none bg-white"
                       placeholder="Esim. Hyvinvointialue"
                     />
                     <Building2 className="w-3.5 h-3.5 text-gray-400 absolute left-2.5 top-2.5" />
                   </div>
                </div>
                <div>
                   <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Yksikkö</label>
                   <input 
                     type="text" 
                     value={orgSettings.subtitle}
                     onChange={(e) => handleOrgSettingChange('subtitle', e.target.value)}
                     className="w-full px-3 py-2 text-sm border border-gray-300 rounded focus:ring-1 focus:ring-accent outline-none bg-white"
                     placeholder="Esim. Pelastustoimi"
                   />
                </div>
                <div>
                   <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Paikkakunta</label>
                   <div className="relative">
                     <input 
                       type="text" 
                       value={orgSettings.city}
                       onChange={(e) => handleOrgSettingChange('city', e.target.value)}
                       className="w-full pl-7 px-3 py-2 text-sm border border-gray-300 rounded focus:ring-1 focus:ring-accent outline-none bg-white"
                       placeholder="Esim. Helsinki"
                     />
                     <MapPin className="w-3.5 h-3.5 text-gray-400 absolute left-2.5 top-2.5" />
                   </div>
                </div>
              </div>
            </div>

            <div className="prose prose-sm max-w-none text-slate-600 mb-2 print:text-xs whitespace-pre-line">
              {introText}
            </div>

            {/* Print Header */}
            <div className="hidden print:block mb-8 border-b-2 border-black pb-4">
                <span className="text-sm text-gray-500 uppercase">Pelastaja</span>
                <div className="text-2xl font-bold">{traineeName}</div>
                <div className="mt-2 text-xs text-gray-500">
                  {orgSettings.name} - {orgSettings.subtitle}
                </div>
            </div>
          </div>

          {/* Sticky Progress Bar */}
          <div className="bg-white/95 backdrop-blur rounded-lg p-4 shadow-sm border border-gray-200 mb-8 flex items-center gap-4 no-print sticky top-20 z-10 transition-shadow">
            <div className={`p-2 rounded-full ${stats.percentage === 100 ? 'bg-green-100' : 'bg-gray-100'}`}>
              <CheckCircle className={`w-6 h-6 ${stats.percentage === 100 ? 'text-green-600' : 'text-gray-400'}`} />
            </div>
            <div className="flex-1">
              <div className="flex justify-between items-end mb-1">
                <span className="font-bold text-slate-700">Edistyminen</span>
                <span className="text-sm font-medium text-accent">{stats.completed} / {stats.total} ({stats.percentage}%)</span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2.5">
                <div 
                  className={`h-2.5 rounded-full transition-all duration-700 ${stats.percentage === 100 ? 'bg-green-500' : 'bg-accent'}`}
                  style={{ width: `${stats.percentage}%` }}
                ></div>
              </div>
            </div>
          </div>

          {/* Form Sections (Using state 'sections' instead of constant 'SECTIONS') */}
          <div className="space-y-4">
            {sections.map(section => (
              <SectionGroup 
                key={section.id} 
                section={section} 
                tasks={tasks} 
                traineeName={traineeName}
                onTaskChange={handleTaskChange}
                onScanRequest={handleScanRequest}
                onSectionScanRequest={handleSectionScanRequest}
              />
            ))}
          </div>

          {/* Print Signature Box (Only for list view) */}
          <div className="hidden print:block mt-8 pt-8 border-t-2 border-black page-break">
            {/* Signatures removed per request for the checklist printout, kept simple */}
            <div className="text-center text-xs text-gray-500">
              Tulostettu: {todayDate} - {orgSettings.city}
            </div>
          </div>

        </main>

        {/* Modals */}
        {showClearConfirm && (
          <ClearConfirmationModal 
            onConfirm={performClearAll} 
            onClose={() => setShowClearConfirm(false)} 
          />
        )}

        {showSupervisorBadge && (
          <SupervisorBadge 
            onClose={() => setShowSupervisorBadge(false)} 
            onScanRequest={handleSupervisorScanRequest}
            onEditContent={() => setShowEditor(true)}
            currentSections={sections}
            currentIntroText={introText}
          />
        )}

        {showEditor && (
          <ContentEditorModal 
            initialSections={sections}
            initialIntroText={introText}
            onSave={handleUpdateContent}
            onReset={handleResetContent}
            onClose={() => setShowEditor(false)}
          />
        )}

        {showUserGuide && (
          <UserGuideModal onClose={() => setShowUserGuide(false)} />
        )}

        {showTraineeBadge && (
          <TraineeBadge 
            traineeName={traineeName}
            tasks={tasks}
            onClose={() => setShowTraineeBadge(false)}
          />
        )}

        {scannedTraineeData && (
          <TraineeReportModal 
            data={scannedTraineeData}
            onClose={() => setScannedTraineeData(null)}
          />
        )}

        {showCompletionModal && (
          <CompletionModal
            traineeName={traineeName}
            onClose={() => setShowCompletionModal(false)}
            onPrint={printCertificate} 
          />
        )}

        {(scanningTaskId || scanningSectionId || isSupervisorScanning || isGenericScanning) && (
          <ScannerModal 
            onScanSuccess={handleScanSuccess} 
            onClose={closeScanner} 
          />
        )}

      </div>
    </>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import LZString from 'lz-string';
import { SECTIONS, DEFAULT_INTRO_TEXT, DEFAULT_ORG_SETTINGS } from './constants';
import { TaskState, TraineeQrData, Section, OrganizationSettings, TemplateQrData, TemplateRawData } from './types';
import { SectionGroup } from './components/SectionGroup';
import { storageService, AppData } from './storage';
import { SupervisorBadge } from './components/SupervisorBadge';
import { ScannerModal } from './components/ScannerModal';
import { TraineeBadge } from './components/TraineeBadge';
import { TraineeReportModal } from './components/TraineeReportModal';
import { CompletionModal } from './components/CompletionModal';
import { CertificateView } from './components/CertificateView';
import { ContentEditorModal } from './components/ContentEditorModal';
import { UserGuideModal } from './components/UserGuideModal';
import { ClearConfirmationModal } from './components/ClearConfirmationModal';
import { Printer, Flame, CheckCircle, QrCode, Trash2, UserCheck, Trophy, CircleHelp, Building2, MapPin, FileText, Download } from 'lucide-react';

const App: React.FC = () => {
  // Data State
  const [traineeName, setTraineeName] = useState('');
  const [tasks, setTasks] = useState<Record<string, TaskState>>({});
  const [sections, setSections] = useState<Section[]>(SECTIONS);
  const [introText, setIntroText] = useState(DEFAULT_INTRO_TEXT);
  const [orgSettings, setOrgSettings] = useState<OrganizationSettings>(DEFAULT_ORG_SETTINGS);

  // UI State
  const [showSupervisorBadge, setShowSupervisorBadge] = useState(false);
  const [showTraineeBadge, setShowTraineeBadge] = useState(false);
  const [showCompletionModal, setShowCompletionModal] = useState(false);
  const [showEditor, setShowEditor] = useState(false);
  const [showUserGuide, setShowUserGuide] = useState(false);
  const [showClearConfirm, setShowClearConfirm] = useState(false);
  const [isPrintingCertificate, setIsPrintingCertificate] = useState(false);

  // Keep track if we've already shown the celebration once per session to avoid annoyance
  const [hasCelebrated, setHasCelebrated] = useState(false);

  // Scan States
  const [scanningTaskId, setScanningTaskId] = useState<string | null>(null);
  const [scanningSectionId, setScanningSectionId] = useState<string | null>(null);
  const [isSupervisorScanning, setIsSupervisorScanning] = useState(false);
  const [isGenericScanning, setIsGenericScanning] = useState(false);

  const [scannedTraineeData, setScannedTraineeData] = useState<TraineeQrData | null>(null);

  // Load data on mount
  useEffect(() => {
    const data = storageService.load();
    setTraineeName(data.traineeName);
    setTasks(data.tasks);
    if (data.customSections && data.customSections.length > 0) {
      setSections(data.customSections);
    }
    if (data.introText) {
      setIntroText(data.introText);
    }
    if (data.organizationSettings) {
      setOrgSettings(data.organizationSettings);
    }
  }, []);

  // Save data on change
  const saveData = (
    newName: string, 
    newTasks: Record<string, TaskState>, 
    newSections?: Section[], 
    newIntroText?: string,
    newOrgSettings?: OrganizationSettings
  ) => {
    const data: AppData = {
      traineeName: newName,
      tasks: newTasks,
      customSections: newSections || sections,
      introText: newIntroText || introText,
      organizationSettings: newOrgSettings || orgSettings,
      lastUpdated: new Date().toISOString()
    };
    storageService.save(data);
  };

  const handleNameChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newName = e.target.value;
    setTraineeName(newName);
    saveData(newName, tasks);
  };

  const handleOrgSettingChange = (field: keyof OrganizationSettings, value: string) => {
    const newSettings = { ...orgSettings, [field]: value };
    setOrgSettings(newSettings);
    saveData(traineeName, tasks, sections, introText, newSettings);
  };

  const handleTaskChange = (taskId: string, updates: Partial<TaskState>) => {
    const newTasks = {
      ...tasks,
      [taskId]: {
        ...(tasks[taskId] || { date: '', traineeSigned: false, trainerSigned: false }),
        ...updates
      }
    };
    setTasks(newTasks);
    saveData(traineeName, newTasks);
  };

  const handleUpdateContent = (newSections: Section[], newIntroText: string) => {
    setSections(newSections);
    setIntroText(newIntroText);
    // Don't update orgSettings here, as they are now handled by the trainee in the main view
    saveData(traineeName, tasks, newSections, newIntroText, orgSettings);
  };

  const handleResetContent = () => {
    setSections(SECTIONS);
    setIntroText(DEFAULT_INTRO_TEXT);
    setOrgSettings(DEFAULT_ORG_SETTINGS);
    saveData(traineeName, tasks, SECTIONS, DEFAULT_INTRO_TEXT, DEFAULT_ORG_SETTINGS);
  };

  const handleScanRequest = (taskId: string) => {
    setScanningTaskId(taskId);
  };

  const handleSectionScanRequest = (sectionId: string) => {
    setScanningSectionId(sectionId);
  };

  const handleSupervisorScanRequest = () => {
    setIsSupervisorScanning(true);
  };

  const handleGenericScanRequest = () => {
    setIsGenericScanning(true);
  };

  // Helper to generate IDs for imported content
  const generateSlugId = (text: string, prefix: string) => {
    const slug = text.toLowerCase()
      .replace(/ä/g, 'a').replace(/ö/g, 'o').replace(/å/g, 'a')
      .replace(/[^a-z0-9]/g, '_')
      .replace(/_+/g, '_');
    return `${prefix}_${slug.substring(0, 15)}_${Math.floor(Math.random() * 1000)}`;
  };

  const handleScanSuccess = (data: any) => {
    const today = new Date().toISOString().split('T')[0];

    // Scenario 0: Template Config (Activation of new induction plan)
    // Handle both Compressed ('z' key) and Uncompressed (legacy 's' key) formats
    if ((data.z) || (data.type === 'TEMPLATE_CONFIG' && data.s)) {
       let rawData: TemplateRawData | null = null;

       // Attempt decompression if 'z' is present
       if (data.z) {
          try {
            // First try Base64 (new optimized format)
            let decompressed = LZString.decompressFromBase64(data.z);

            // Fallback to encodedURIComponent (old format) if base64 yields null
            if (!decompressed) {
              decompressed = LZString.decompressFromEncodedURIComponent(data.z);
            }

            if (decompressed) {
              rawData = JSON.parse(decompressed);
            }
          } catch (e) {
            console.error("Decompression failed", e);
            alert("Virhe luettaessa pakattua koodia.");
            return;
          }
       } else {
         // Fallback to uncompressed
         rawData = data as TemplateRawData;
       }

       if (rawData && rawData.s) {
          if (confirm('Haluatko ottaa käyttöön uuden perehdytysrungon ja -ohjeistuksen? Tämä päivittää nykyisen lomakkeen rakenteen.')) {
            // Un-minify sections and regenerate IDs if missing
            const newSections: Section[] = rawData.s.map((minSec, idx) => ({
              id: minSec.i || generateSlugId(minSec.t, `s${idx}`),
              title: minSec.t,
              subtitle: minSec.s,
              items: minSec.it.map((minItem, iIdx) => ({
                id: minItem.i || generateSlugId(minItem.l, `i${idx}_${iIdx}`),
                label: minItem.l
              }))
            }));

            handleUpdateContent(newSections, rawData.intro);
            alert('Uusi perehdytysrunko aktivoitu onnistuneesti!');
            closeScanner();
          }
       }
       return;
    }

    // Scenario 1: Trainee scanning Supervisor Signature for a SINGLE TASK
    if (scanningTaskId && data.type === 'SUPERVISOR_SIGNATURE' && data.name) {
       handleTaskChange(scanningTaskId, {
         trainerSigned: true,
         trainerName: data.name,
         date: today
       });
       setScanningTaskId(null);
    }
    // Scenario 2: Trainee scanning Supervisor Signature for a WHOLE SECTION
    else if (scanningSectionId && data.type === 'SUPERVISOR_SIGNATURE' && data.name) {
       const section = sections.find(s => s.id === scanningSectionId);
       if (section) {
         const newTasks = { ...tasks };
         section.items.forEach(item => {
           // Update each task in the section
           newTasks[item.id] = {
             ...(newTasks[item.id] || { date: '', traineeSigned: false, trainerSigned: false }),
             trainerSigned: true,
             trainerName: data.name,
             date: today
           };
         });
         setTasks(newTasks);
         saveData(traineeName, newTasks);
       }
       setScanningSectionId(null);
    }
    // Scenario 3: Supervisor scanning Trainee Progress
    else if (isSupervisorScanning && data.type === 'TRAINEE_PROGRESS') {
      setIsSupervisorScanning(false);
      setScannedTraineeData(data);
    }
    // Error / Mismatch handling
    else {
      if ((scanningTaskId || scanningSectionId) && data.type !== 'SUPERVISOR_SIGNATURE') {
         alert("Virhe: Skannasit pelastajan passin. Skannaa esimiehen kuittauskoodi.");
      }
      else if (isSupervisorScanning && data.type !== 'TRAINEE_PROGRESS') {
         alert("Virhe: Skannasit esimiehen koodin. Skannaa pelastajan passi.");
      }
      else if (isGenericScanning && data.type === 'SUPERVISOR_SIGNATURE') {
         alert("Tämä on kuittauskoodi. Skannaa tämä koodi kun olet valinnut tietyn tehtävän kuitattavaksi.");
      }
    }
  };

  const closeScanner = () => {
    setScanningTaskId(null);
    setScanningSectionId(null);
    setIsSupervisorScanning(false);
    setIsGenericScanning(false);
  };

  // Logic to actually wipe data (called by modal)
  const performClearAll = () => {
    const currentSections = sections;
    const currentIntro = introText;
    const currentOrg = orgSettings;

    storageService.clear();

    // Reset state
    setTraineeName('');
    setTasks({});
    setHasCelebrated(false);

    // Restore structure settings (user doesn't want to lose the layout, just the data)
    setSections(currentSections);
    setIntroText(currentIntro);
    setOrgSettings(currentOrg);

    // Immediately save the structure back so it persists
    const freshData: AppData = {
        traineeName: '',
        tasks: {},
        customSections: currentSections,
        introText: currentIntro,
        organizationSettings: currentOrg,
        lastUpdated: new Date().toISOString()
    };
    storageService.save(freshData);

    setShowClearConfirm(false);
  };

  // Standard print (checklist)
  const printForm = () => {
    setIsPrintingCertificate(false);
    // Allow React to update state before printing
    setTimeout(() => window.print(), 100);
  };

  // Certificate print (diploma)
  const printCertificate = () => {
    setIsPrintingCertificate(true);
    setTimeout(() => {
      window.print();
      // Reset after print dialog closes (approximate) or let user switch back manually
      const cleanup = () => setIsPrintingCertificate(false);
      window.addEventListener('afterprint', cleanup, { once: true });
      setTimeout(cleanup, 5000); 
    }, 100);
  };

  // Calculate stats
  const stats = useMemo(() => {
    let total = 0;
    let completed = 0;
    sections.forEach(section => {
      section.items.forEach(item => {
        total++;
        const s = tasks[item.id];
        if (s && s.traineeSigned && s.trainerSigned) {
          completed++;
        }
      });
    });
    return { total, completed, percentage: total === 0 ? 0 : Math.round((completed/total) * 100) };
  }, [tasks, sections]);

  // Check for completion
  useEffect(() => {
    if (stats.percentage === 100 && !hasCelebrated && stats.total > 0) {
      setShowCompletionModal(true);
      setHasCelebrated(true);
    }
  }, [stats.percentage, hasCelebrated, stats.total]);

  // Determine date to show on certificate (today)
  const todayDate = new Date().toLocaleDateString('fi-FI');

  return (
    <>
      {/* CERTIFICATE VIEW (Only visible when printing certificate) */}
      {isPrintingCertificate && (
         <CertificateView 
           traineeName={traineeName} 
           completionDate={todayDate}
           orgSettings={orgSettings} 
         />
      )}

      {/* MAIN APP VIEW (Hidden when printing certificate) */}
      <div className={`min-h-screen bg-gray-100 print:bg-white pb-12 ${isPrintingCertificate ? 'hidden' : 'block'}`}>

        {/* Header Bar */}
        <header className="bg-primary text-white shadow-md sticky top-0 z-20 print:static print:shadow-none print:bg-white print:text-black">
          <div className="max-w-4xl mx-auto px-4 py-3 flex flex-col sm:flex-row items-center justify-between gap-4">

            {/* Logo & Title */}
            <div className="flex items-center gap-3 w-full sm:w-auto">
              <div className="bg-orange-500 p-2 rounded-lg print:hidden">
                <Flame className="w-6 h-6 text-white" />
              </div>
              <div>
                <h1 className="text-lg font-bold leading-tight">Pelastajan Perehdytys</h1>
                <p className="text-xs text-slate-300 print:hidden">Sähköinen seurantalomake</p>
              </div>
            </div>

            {/* Controls */}
            <div className="flex items-center gap-2 w-full sm:w-auto justify-end no-print overflow-x-auto pb-1 sm:pb-0">

              <button
                onClick={() => setShowUserGuide(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-700 hover:bg-slate-600 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-600 whitespace-nowrap mr-2"
                title="Käyttöohjeet"
              >
                <CircleHelp className="w-4 h-4 text-sky-300" />
                <span className="hidden sm:inline">Ohjeet</span>
              </button>

              {stats.percentage === 100 && (
                <button
                  onClick={() => setShowCompletionModal(true)}
                  className="flex items-center gap-1.5 sm:gap-2 bg-yellow-500 hover:bg-yellow-600 text-white px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors shadow-lg animate-pulse font-bold whitespace-nowrap"
                >
                  <Trophy className="w-4 h-4" />
                  <span>Valmis!</span>
                </button>
              )}

              <button
                onClick={() => setShowTraineeBadge(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-800 hover:bg-slate-700 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-700 whitespace-nowrap"
              >
                <UserCheck className="w-4 h-4 text-accent" />
                <span className="sm:hidden">Passi</span>
                <span className="hidden sm:inline">Oma Passi</span>
              </button>

              <div className="w-px h-6 bg-slate-700 mx-0.5 sm:mx-1"></div>

              <button 
                onClick={() => setShowSupervisorBadge(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-800 hover:bg-slate-700 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-700 whitespace-nowrap"
              >
                <QrCode className="w-4 h-4 text-green-400" />
                <span className="sm:hidden">Esimies</span>
                <span className="hidden sm:inline">Esimiestyökalut</span>
              </button>

              <button 
                onClick={printForm}
                className="p-2 bg-slate-800 hover:bg-slate-700 rounded-lg transition-colors text-slate-200"
                title="Tulosta PDF (Lista)"
              >
                <Printer className="w-5 h-5" />
              </button>

              <button 
                onClick={handleGenericScanRequest}
                className="p-2 bg-slate-800 hover:bg-slate-700 rounded-lg transition-colors text-sky-200"
                title="Lue uusi perehdytysrunko (QR)"
              >
                <Download className="w-5 h-5" />
              </button>

              <button 
                onClick={() => setShowClearConfirm(true)}
                className="p-2 bg-red-900/50 hover:bg-red-900 rounded-lg transition-colors text-red-200 ml-1 sm:ml-2"
                title="Tyhjennä lomake (säilyttää rakenteen)"
              >
                <Trash2 className="w-5 h-5" />
              </button>
            </div>
          </div>
        </header>

        <main className="max-w-4xl mx-auto px-4 py-8 print:py-0 print:px-0">

          {/* Name Input & Intro */}
          <div className="bg-white rounded-lg p-6 shadow-sm border border-gray-200 mb-6 print:border-none print:shadow-none print:p-0">

            <div className="mb-6 no-print">
              <label className="block text-xs font-bold uppercase text-slate-500 mb-2">
                Pelastajan Nimi
              </label>
              <div className="relative">
                <input
                  type="text"
                  value={traineeName}
                  onChange={handleNameChange}
                  placeholder="Kirjoita nimesi tähän..."
                  className="w-full text-lg font-bold text-slate-800 border-b-2 border-slate-200 focus:border-accent outline-none py-2 pl-9 bg-transparent transition-colors placeholder:font-normal placeholder:text-gray-300"
                />
                <UserCheck className="w-6 h-6 text-gray-400 absolute left-0 top-2" />
              </div>
            </div>

            {/* Organization Settings Input for Trainee */}
            <div className="mt-4 p-4 bg-gray-50 rounded-lg border border-gray-200 no-print mb-6">
              <h3 className="text-sm font-bold text-gray-500 uppercase mb-3 flex items-center gap-2">
                <FileText className="w-4 h-4" />
                Tiedot
              </h3>
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                <div>
                   <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Organisaatio</label>
                   <div className="relative">
                     <input 
                       type="text" 
                       value={orgSettings.name}
                       onChange={(e) => handleOrgSettingChange('name', e.target.value)}
                       className="w-full pl-7 px-3 py-2 text-sm border border-gray-300 rounded focus:ring-1 focus:ring-accent outline-none bg-white"
                       placeholder="Esim. Hyvinvointialue"
                     />
                     <Building2 className="w-3.5 h-3.5 text-gray-400 absolute left-2.5 top-2.5" />
                   </div>
                </div>
                <div>
                   <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Yksikkö</label>
                   <input 
                     type="text" 
                     value={orgSettings.subtitle}
                     onChange={(e) => handleOrgSettingChange('subtitle', e.target.value)}
                     className="w-full px-3 py-2 text-sm border border-gray-300 rounded focus:ring-1 focus:ring-accent outline-none bg-white"
                     placeholder="Esim. Pelastustoimi"
                   />
                </div>
                <div>
                   <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Paikkakunta</label>
                   <div className="relative">
                     <input 
                       type="text" 
                       value={orgSettings.city}
                       onChange={(e) => handleOrgSettingChange('city', e.target.value)}
                       className="w-full pl-7 px-3 py-2 text-sm border border-gray-300 rounded focus:ring-1 focus:ring-accent outline-none bg-white"
                       placeholder="Esim. Helsinki"
                     />
                     <MapPin className="w-3.5 h-3.5 text-gray-400 absolute left-2.5 top-2.5" />
                   </div>
                </div>
              </div>
            </div>

            <div className="prose prose-sm max-w-none text-slate-600 mb-2 print:text-xs whitespace-pre-line">
              {introText}
            </div>

            {/* Print Header */}
            <div className="hidden print:block mb-8 border-b-2 border-black pb-4">
                <span className="text-sm text-gray-500 uppercase">Pelastaja</span>
                <div className="text-2xl font-bold">{traineeName}</div>
                <div className="mt-2 text-xs text-gray-500">
                  {orgSettings.name} - {orgSettings.subtitle}
                </div>
            </div>
          </div>

          {/* Sticky Progress Bar */}
          <div className="bg-white/95 backdrop-blur rounded-lg p-4 shadow-sm border border-gray-200 mb-8 flex items-center gap-4 no-print sticky top-20 z-10 transition-shadow">
            <div className={`p-2 rounded-full ${stats.percentage === 100 ? 'bg-green-100' : 'bg-gray-100'}`}>
              <CheckCircle className={`w-6 h-6 ${stats.percentage === 100 ? 'text-green-600' : 'text-gray-400'}`} />
            </div>
            <div className="flex-1">
              <div className="flex justify-between items-end mb-1">
                <span className="font-bold text-slate-700">Edistyminen</span>
                <span className="text-sm font-medium text-accent">{stats.completed} / {stats.total} ({stats.percentage}%)</span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2.5">
                <div 
                  className={`h-2.5 rounded-full transition-all duration-700 ${stats.percentage === 100 ? 'bg-green-500' : 'bg-accent'}`}
                  style={{ width: `${stats.percentage}%` }}
                ></div>
              </div>
            </div>
          </div>

          {/* Form Sections (Using state 'sections' instead of constant 'SECTIONS') */}
          <div className="space-y-4">
            {sections.map(section => (
              <SectionGroup 
                key={section.id} 
                section={section} 
                tasks={tasks} 
                traineeName={traineeName}
                onTaskChange={handleTaskChange}
                onScanRequest={handleScanRequest}
                onSectionScanRequest={handleSectionScanRequest}
              />
            ))}
          </div>

          {/* Print Signature Box (Only for list view) */}
          <div className="hidden print:block mt-8 pt-8 border-t-2 border-black page-break">
            {/* Signatures removed per request for the checklist printout, kept simple */}
            <div className="text-center text-xs text-gray-500">
              Tulostettu: {todayDate} - {orgSettings.city}
            </div>
          </div>

        </main>

        {/* Modals */}
        {showClearConfirm && (
          <ClearConfirmationModal 
            onConfirm={performClearAll} 
            onClose={() => setShowClearConfirm(false)} 
          />
        )}

        {showSupervisorBadge && (
          <SupervisorBadge 
            onClose={() => setShowSupervisorBadge(false)} 
            onScanRequest={handleSupervisorScanRequest}
            onEditContent={() => setShowEditor(true)}
            currentSections={sections}
            currentIntroText={introText}
          />
        )}

        {showEditor && (
          <ContentEditorModal 
            initialSections={sections}
            initialIntroText={introText}
            onSave={handleUpdateContent}
            onReset={handleResetContent}
            onClose={() => setShowEditor(false)}
          />
        )}

        {showUserGuide && (
          <UserGuideModal onClose={() => setShowUserGuide(false)} />
        )}

        {showTraineeBadge && (
          <TraineeBadge 
            traineeName={traineeName}
            tasks={tasks}
            onClose={() => setShowTraineeBadge(false)}
          />
        )}

        {scannedTraineeData && (
          <TraineeReportModal 
            data={scannedTraineeData}
            onClose={() => setScannedTraineeData(null)}
          />
        )}

        {showCompletionModal && (
          <CompletionModal
            traineeName={traineeName}
            onClose={() => setShowCompletionModal(false)}
            onPrint={printCertificate} 
          />
        )}

        {(scanningTaskId || scanningSectionId || isSupervisorScanning || isGenericScanning) && (
          <ScannerModal 
            onScanSuccess={handleScanSuccess} 
            onClose={closeScanner} 
          />
        )}

      </div>
    </>
  );
};

export default App;

export interface TaskItem {
  id: string;
  label: string;
}

export interface Section {
  id: string;
  title: string;
  subtitle?: string;
  items: TaskItem[];
}

export interface TaskState {
  date: string;
  traineeSigned: boolean;
  trainerSigned: boolean;
  traineeName?: string;
  trainerName?: string;
}

export type UserRole = 'trainee' | 'supervisor';

export interface UserProgress {
  userId: string;
  userName: string;
  tasks: Record<string, TaskState>;
  lastUpdated: string;
}

export interface TraineeQrData {
  type: 'TRAINEE_PROGRESS';
  name: string;
  completedTaskIds: string[];
  timestamp: number;
}

// Internal structure for minified template data
export interface TemplateRawData {
  intro: string;
  s: {
    i?: string; // id (optional to save space)
    t: string; // title
    s?: string; // subtitle
    it: {      // items
      i?: string; // id (optional to save space)
      l: string; // label
    }[];
  }[];
}

export interface OrganizationSettings {
  name: string;      // e.g. "Satakunnan hyvinvointialue"
  subtitle: string;  // e.g. "Pelastustoimi"
  city: string;      // e.g. "Porissa" (used in signature line)
}

// Global declaration for the loaded script
declare global {
  class Html5QrcodeScanner {
    constructor(elementId: string, config: any, verbose?: boolean);
    render(onSuccess: (decodedText: string, decodedResult: any) => void, onError?: (errorMessage: string) => void): void;
    clear(): Promise<void>;
  }

  class Html5Qrcode {
    constructor(elementId: string, verbose?: boolean);
    start(
      cameraIdOrConfig: string | { facingMode: string } | { deviceId: string }, 
      config: { fps: number; qrbox?: number | { width: number; height: number }; aspectRatio?: number }, 
      onSuccess: (decodedText: string, decodedResult: any) => void, 
      onError?: (errorMessage: string) => void
    ): Promise<void>;
    stop(): Promise<void>;
    clear(): Promise<void>;
  }
}

import React, { useEffect, useState } from 'react';
import QRCode from 'qrcode';
import LZString from 'lz-string';
import { X, ShieldCheck, UserPen, Lock, KeyRound, Download, ScanLine, FilePenLine, Share2, Copy, Check, Link } from 'lucide-react';
import { Section, TemplateRawData } from '../types';

interface SupervisorBadgeProps {
  onClose: () => void;
  onScanRequest: () => void;
  onEditContent: () => void;
  currentSections: Section[];
  currentIntroText: string;
}

export const SupervisorBadge: React.FC<SupervisorBadgeProps> = ({ 
  onClose, 
  onScanRequest, 
  onEditContent,
  currentSections,
  currentIntroText 
}) => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [error, setError] = useState(false);

  const [name, setName] = useState('');
  const [qrUrl, setQrUrl] = useState<string>('');

  // State for Template Sharing
  const [showShareModal, setShowShareModal] = useState(false);
  const [shareUrl, setShareUrl] = useState<string>('');
  const [copied, setCopied] = useState(false);

  // Effect for Supervisor Signature QR
  useEffect(() => {
    if (!name.trim()) {
      setQrUrl('');
      return;
    }

    const signaturePayload = JSON.stringify({
      type: 'SUPERVISOR_SIGNATURE',
      name: name.trim(),
      timestamp: Date.now()
    });

    QRCode.toDataURL(signaturePayload, { width: 400, margin: 2 })
      .then((url) => {
        setQrUrl(url);
      })
      .catch((err) => {
        console.error("QR Generation failed", err);
      });
  }, [name]);

  // Generate Share URL when modal opens
  useEffect(() => {
    if (showShareModal) {
      try {
        // 1. Minify data structure
        const minifiedSections = currentSections.map(sec => {
          const sObj: any = {
            t: sec.title,
            it: sec.items.map(item => ({
              l: item.label
            }))
          };
          if (sec.subtitle) sObj.s = sec.subtitle;
          return sObj;
        });

        const rawData: TemplateRawData = {
          intro: currentIntroText,
          s: minifiedSections
        };

        const jsonString = JSON.stringify(rawData);

        // 2. Compress using compressToEncodedURIComponent for safe URL usage
        const compressed = LZString.compressToEncodedURIComponent(jsonString);

        // 3. Construct URL
        const baseUrl = window.location.href.split('?')[0];
        const fullUrl = `${baseUrl}?template=${compressed}`;

        setShareUrl(fullUrl);
      } catch (e) {
        console.error("Compression failed", e);
        setShareUrl("Virhe linkin luonnissa.");
      }
    }
  }, [showShareModal, currentSections, currentIntroText]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === '112') {
        setIsAuthenticated(true);
        setError(false);
    } else {
        setError(true);
        setPasswordInput('');
    }
  };

  const handleDownload = (url: string, filenamePrefix: string) => {
    if (!url) return;
    const link = document.createElement('a');
    link.href = url;
    const safeName = name.replace(/[^a-z0-9]/gi, '_').toLowerCase() || 'template';
    link.download = `perehdytys-${filenamePrefix}-${safeName}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleStartScan = () => {
    onClose();
    onScanRequest();
  };

  const handleStartEdit = () => {
    onClose();
    onEditContent();
  };

  const copyToClipboard = async () => {
    try {
      await navigator.clipboard.writeText(shareUrl);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch (err) {
      console.error('Failed to copy', err);
    }
  };

  const shareNative = async () => {
    if (navigator.share) {
      try {
        await navigator.share({
          title: 'Perehdytysrunko',
          text: 'Tässä on päivitetty perehdytysrunko.',
          url: shareUrl,
        });
      } catch (err) {
        console.log('Share canceled');
      }
    } else {
      copyToClipboard();
    }
  };

  if (!isAuthenticated) {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
        <div className="bg-white rounded-2xl w-full max-w-sm overflow-hidden shadow-2xl animate-in fade-in zoom-in duration-200">
          <div className="bg-slate-800 p-4 flex justify-between items-center text-white">
            <div className="flex items-center gap-2">
              <Lock className="w-5 h-5 text-orange-400" />
              <h3 className="font-bold">Esimieskirjautuminen</h3>
            </div>
            <button onClick={onClose} className="p-1 hover:bg-slate-700 rounded-full transition-colors">
              <X className="w-5 h-5" />
            </button>
          </div>

          <form onSubmit={handleLogin} className="p-6 space-y-4">
            <div>
              <label className="block text-xs font-bold uppercase text-gray-500 mb-2">
                Salasana
              </label>
              <div className="relative">
                <input 
                  type="password" 
                  value={passwordInput}
                  onChange={(e) => setPasswordInput(e.target.value)}
                  className={`w-full pl-10 pr-4 py-2 border-2 rounded-lg outline-none transition-colors ${error ? 'border-red-300 focus:border-red-500' : 'border-slate-200 focus:border-slate-800'}`}
                  autoFocus
                  placeholder="Syötä salasana"
                />
                <KeyRound className="w-5 h-5 text-gray-400 absolute left-3 top-2.5" />
              </div>
              {error && (
                <p className="text-red-500 text-xs mt-2 font-medium">
                  Väärä salasana. Yritä uudelleen.
                </p>
              )}
            </div>

            <button 
              type="submit"
              className="w-full py-3 bg-slate-800 text-white rounded-lg font-bold hover:bg-slate-700 transition-colors shadow-lg shadow-slate-900/20"
            >
              Kirjaudu
            </button>
          </form>
        </div>
      </div>
    );
  }

  // --- SHARE URL VIEW ---
  if (showShareModal) {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
        <div className="bg-white rounded-2xl w-full max-w-lg overflow-hidden shadow-2xl animate-in fade-in zoom-in duration-200 flex flex-col max-h-[90vh]">
          <div className="bg-slate-800 p-4 flex justify-between items-center text-white shrink-0">
            <div className="flex items-center gap-2">
              <Link className="w-5 h-5 text-accent" />
              <h3 className="font-bold">Jaa perehdytysrunko linkillä</h3>
            </div>
            <button onClick={() => setShowShareModal(false)} className="p-1 hover:bg-slate-700 rounded-full transition-colors">
              <X className="w-5 h-5" />
            </button>
          </div>

          <div className="p-6 space-y-6">
             <div className="bg-blue-50 border border-blue-100 p-4 rounded-lg text-sm text-blue-900">
               Lähetä tämä linkki pelastajalle (esim. WhatsApp tai sähköposti). Kun pelastaja avaa linkin omalla laitteellaan, sovellus päivittää perehdytysrungon automaattisesti.
             </div>

             <div>
               <label className="block text-xs font-bold uppercase text-gray-500 mb-2">
                 Jako-linkki
               </label>
               <div className="flex gap-2">
                 <input 
                   type="text" 
                   readOnly 
                   value={shareUrl} 
                   className="flex-1 px-3 py-2 border rounded-lg bg-gray-50 text-gray-600 text-sm focus:outline-none"
                 />
                 <button 
                   onClick={copyToClipboard}
                   className={`px-4 py-2 rounded-lg font-bold transition-all flex items-center gap-2 ${copied ? 'bg-green-500 text-white' : 'bg-gray-200 text-gray-700 hover:bg-gray-300'}`}
                 >
                   {copied ? <Check className="w-4 h-4" /> : <Copy className="w-4 h-4" />}
                   {copied ? 'Kopioitu' : 'Kopioi'}
                 </button>
               </div>
             </div>

             <button 
               onClick={shareNative}
               className="w-full py-4 bg-accent text-white rounded-xl font-bold hover:bg-sky-600 flex items-center justify-center gap-2 shadow-lg shadow-sky-500/20"
             >
               <Share2 className="w-5 h-5" />
               Jaa sovellukseen...
             </button>
          </div>

          <div className="p-4 border-t border-gray-100 bg-gray-50">
            <button 
              onClick={() => setShowShareModal(false)}
              className="w-full py-3 bg-white border border-gray-300 text-slate-700 rounded-lg font-bold hover:bg-gray-100"
            >
              Sulje
            </button>
          </div>
        </div>
      </div>
    );
  }

  // --- MAIN MENU VIEW ---
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl w-full max-w-sm overflow-hidden shadow-2xl animate-in fade-in zoom-in duration-200">

        <div className="bg-slate-800 p-4 flex justify-between items-center text-white">
          <div className="flex items-center gap-2">
            <ShieldCheck className="w-5 h-5 text-green-400" />
            <h3 className="font-bold">Esimiehen Työkalut</h3>
          </div>
          <button onClick={onClose} className="p-1 hover:bg-slate-700 rounded-full transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="p-6 space-y-8 max-h-[80vh] overflow-y-auto">

          {/* Section 1: Generate Supervisor ID */}
          <div className="space-y-4">
            <h4 className="text-sm font-bold uppercase text-slate-500 border-b pb-1">1. Esimiehen Tunniste</h4>

            <div className="w-full">
              <label className="block text-xs font-bold text-gray-400 mb-2">
                Esimiehen Nimi
              </label>
              <div className="relative">
                <input 
                  type="text" 
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  placeholder="Esim. Matti Meikäläinen"
                  className="w-full pl-10 pr-4 py-2 border-2 border-slate-200 rounded-lg focus:border-slate-800 outline-none transition-colors"
                />
                <UserPen className="w-5 h-5 text-gray-400 absolute left-3 top-2.5" />
              </div>
            </div>

            <div className={`p-4 bg-white border-2 rounded-xl flex items-center justify-center transition-all duration-300 ${qrUrl ? 'border-green-500 shadow-sm' : 'border-gray-100 bg-gray-50'}`}>
              {qrUrl ? (
                <div className="text-center space-y-2">
                    <img src={qrUrl} alt="Esimiehen QR-koodi" className="w-32 h-32 mx-auto" />
                    <button 
                        onClick={() => handleDownload(qrUrl, 'esimies')}
                        className="text-xs flex items-center justify-center gap-1 text-slate-500 hover:text-slate-800 mx-auto"
                    >
                        <Download className="w-3 h-3" /> Tallenna kuva
                    </button>
                </div>
              ) : (
                <div className="w-32 h-32 flex items-center justify-center text-gray-300 text-xs italic">
                  Kirjoita nimi...
                </div>
              )}
            </div>
          </div>

          {/* Section 2: Scan Trainee */}
          <div className="space-y-4">
             <h4 className="text-sm font-bold uppercase text-slate-500 border-b pb-1">2. Tarkista Pelastaja</h4>
             <button
               onClick={handleStartScan}
               className="w-full py-3 bg-accent hover:bg-sky-600 text-white rounded-xl font-bold transition-colors flex items-center justify-center gap-3 shadow-lg shadow-sky-500/20"
             >
                <ScanLine className="w-5 h-5" />
                Tarkista Pelastajan Passi
             </button>
          </div>

          {/* Section 3: Edit Form */}
          <div className="space-y-4">
             <h4 className="text-sm font-bold uppercase text-slate-500 border-b pb-1">3. Hallinta</h4>
             <div className="bg-gray-50 rounded-xl p-4 border border-gray-100 space-y-3">
               <p className="text-xs text-gray-500 text-center">
                 Muokkaa lomakkeen rakennetta ja jaa se pelastajalle.
               </p>

               <button
                 onClick={handleStartEdit}
                 className="w-full py-3 bg-white border-2 border-slate-200 hover:border-slate-400 text-slate-700 rounded-xl font-bold transition-colors flex items-center justify-center gap-3"
               >
                  <FilePenLine className="w-5 h-5" />
                  Muokkaa runkoa
               </button>

               <button
                 onClick={() => setShowShareModal(true)}
                 className="w-full py-3 bg-white border-2 border-slate-200 hover:border-slate-400 text-slate-700 rounded-xl font-bold transition-colors flex items-center justify-center gap-3"
               >
                  <Share2 className="w-5 h-5" />
                  Jaa linkki
               </button>
             </div>
          </div>

        </div>

        <button 
          onClick={onClose}
          className="w-full py-4 bg-gray-50 border-t border-gray-100 font-semibold text-slate-600 hover:bg-gray-100 transition-colors"
        >
          Sulje
        </button>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import LZString from 'lz-string';
import { SECTIONS, DEFAULT_INTRO_TEXT, DEFAULT_ORG_SETTINGS } from './constants';
import { TaskState, TraineeQrData, Section, OrganizationSettings, TemplateRawData } from './types';
import { SectionGroup } from './components/SectionGroup';
import { storageService, AppData } from './storage';
import { SupervisorBadge } from './components/SupervisorBadge';
import { ScannerModal } from './components/ScannerModal';
import { TraineeBadge } from './components/TraineeBadge';
import { TraineeReportModal } from './components/TraineeReportModal';
import { CompletionModal } from './components/CompletionModal';
import { CertificateView } from './components/CertificateView';
import { ContentEditorModal } from './components/ContentEditorModal';
import { UserGuideModal } from './components/UserGuideModal';
import { ClearConfirmationModal } from './components/ClearConfirmationModal';
import { Printer, Flame, CheckCircle, QrCode, Trash2, UserCheck, Trophy, CircleHelp, Building2, MapPin, FileText } from 'lucide-react';

const App: React.FC = () => {
  // Data State
  const [traineeName, setTraineeName] = useState('');
  const [tasks, setTasks] = useState<Record<string, TaskState>>({});
  const [sections, setSections] = useState<Section[]>(SECTIONS);
  const [introText, setIntroText] = useState(DEFAULT_INTRO_TEXT);
  const [orgSettings, setOrgSettings] = useState<OrganizationSettings>(DEFAULT_ORG_SETTINGS);

  // UI State
  const [showSupervisorBadge, setShowSupervisorBadge] = useState(false);
  const [showTraineeBadge, setShowTraineeBadge] = useState(false);
  const [showCompletionModal, setShowCompletionModal] = useState(false);
  const [showEditor, setShowEditor] = useState(false);
  const [showUserGuide, setShowUserGuide] = useState(false);
  const [showClearConfirm, setShowClearConfirm] = useState(false);
  const [isPrintingCertificate, setIsPrintingCertificate] = useState(false);

  // Keep track if we've already shown the celebration once per session to avoid annoyance
  const [hasCelebrated, setHasCelebrated] = useState(false);

  // Scan States
  const [scanningTaskId, setScanningTaskId] = useState<string | null>(null);
  const [scanningSectionId, setScanningSectionId] = useState<string | null>(null);
  const [isSupervisorScanning, setIsSupervisorScanning] = useState(false);

  const [scannedTraineeData, setScannedTraineeData] = useState<TraineeQrData | null>(null);

  // Helper to generate IDs for imported content
  const generateSlugId = (text: string, prefix: string) => {
    const slug = text.toLowerCase()
      .replace(/ä/g, 'a').replace(/ö/g, 'o').replace(/å/g, 'a')
      .replace(/[^a-z0-9]/g, '_')
      .replace(/_+/g, '_');
    return `${prefix}_${slug.substring(0, 15)}_${Math.floor(Math.random() * 1000)}`;
  };

  // Helper to Apply Template Data
  const applyTemplate = (rawData: TemplateRawData) => {
    // Un-minify sections and regenerate IDs if missing
    const newSections: Section[] = rawData.s.map((minSec, idx) => ({
      id: minSec.i || generateSlugId(minSec.t, `s${idx}`),
      title: minSec.t,
      subtitle: minSec.s,
      items: minSec.it.map((minItem, iIdx) => ({
        id: minItem.i || generateSlugId(minItem.l, `i${idx}_${iIdx}`),
        label: minItem.l
      }))
    }));

    // Save locally
    setSections(newSections);
    setIntroText(rawData.intro);

    // Persist to storage
    const currentData = storageService.load();
    const newData: AppData = {
        ...currentData,
        customSections: newSections,
        introText: rawData.intro,
        lastUpdated: new Date().toISOString()
    };
    storageService.save(newData);

    alert('Uusi perehdytysrunko aktivoitu onnistuneesti!');
  };

  // Load data on mount & Check for URL Template Params
  useEffect(() => {
    // 1. Load LocalStorage
    const data = storageService.load();
    setTraineeName(data.traineeName);
    setTasks(data.tasks);
    if (data.customSections && data.customSections.length > 0) {
      setSections(data.customSections);
    }
    if (data.introText) {
      setIntroText(data.introText);
    }
    if (data.organizationSettings) {
      setOrgSettings(data.organizationSettings);
    }

    // 2. Check for Template in URL
    const params = new URLSearchParams(window.location.search);
    const templateString = params.get('template');

    if (templateString) {
      try {
        const decompressed = LZString.decompressFromEncodedURIComponent(templateString);
        if (decompressed) {
          const rawData = JSON.parse(decompressed) as TemplateRawData;

          if (rawData && rawData.s && confirm('Linkistä löytyi uusi perehdytysrunko. Haluatko ottaa sen käyttöön? Tämä päivittää lomakkeen rakenteen.')) {
             applyTemplate(rawData);

             // Clean URL without refresh
             const newUrl = window.location.pathname;
             window.history.replaceState({}, '', newUrl);
          }
        }
      } catch (e) {
        console.error("Template load failed", e);
      }
    }
  }, []);

  // Save data on change
  const saveData = (
    newName: string, 
    newTasks: Record<string, TaskState>, 
    newSections?: Section[], 
    newIntroText?: string,
    newOrgSettings?: OrganizationSettings
  ) => {
    const data: AppData = {
      traineeName: newName,
      tasks: newTasks,
      customSections: newSections || sections,
      introText: newIntroText || introText,
      organizationSettings: newOrgSettings || orgSettings,
      lastUpdated: new Date().toISOString()
    };
    storageService.save(data);
  };

  const handleNameChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newName = e.target.value;
    setTraineeName(newName);
    saveData(newName, tasks);
  };

  const handleOrgSettingChange = (field: keyof OrganizationSettings, value: string) => {
    const newSettings = { ...orgSettings, [field]: value };
    setOrgSettings(newSettings);
    saveData(traineeName, tasks, sections, introText, newSettings);
  };

  const handleTaskChange = (taskId: string, updates: Partial<TaskState>) => {
    const newTasks = {
      ...tasks,
      [taskId]: {
        ...(tasks[taskId] || { date: '', traineeSigned: false, trainerSigned: false }),
        ...updates
      }
    };
    setTasks(newTasks);
    saveData(traineeName, newTasks);
  };

  const handleUpdateContent = (newSections: Section[], newIntroText: string) => {
    setSections(newSections);
    setIntroText(newIntroText);
    // Don't update orgSettings here, as they are now handled by the trainee in the main view
    saveData(traineeName, tasks, newSections, newIntroText, orgSettings);
  };

  const handleResetContent = () => {
    setSections(SECTIONS);
    setIntroText(DEFAULT_INTRO_TEXT);
    setOrgSettings(DEFAULT_ORG_SETTINGS);
    saveData(traineeName, tasks, SECTIONS, DEFAULT_INTRO_TEXT, DEFAULT_ORG_SETTINGS);
  };

  const handleScanRequest = (taskId: string) => {
    setScanningTaskId(taskId);
  };

  const handleSectionScanRequest = (sectionId: string) => {
    setScanningSectionId(sectionId);
  };

  const handleSupervisorScanRequest = () => {
    setIsSupervisorScanning(true);
  };

  const handleScanSuccess = (data: any) => {
    const today = new Date().toISOString().split('T')[0];

    // Scenario 1: Trainee scanning Supervisor Signature for a SINGLE TASK
    if (scanningTaskId && data.type === 'SUPERVISOR_SIGNATURE' && data.name) {
       handleTaskChange(scanningTaskId, {
         trainerSigned: true,
         trainerName: data.name,
         date: today
       });
       setScanningTaskId(null);
    }
    // Scenario 2: Trainee scanning Supervisor Signature for a WHOLE SECTION
    else if (scanningSectionId && data.type === 'SUPERVISOR_SIGNATURE' && data.name) {
       const section = sections.find(s => s.id === scanningSectionId);
       if (section) {
         const newTasks = { ...tasks };
         section.items.forEach(item => {
           // Update each task in the section
           newTasks[item.id] = {
             ...(newTasks[item.id] || { date: '', traineeSigned: false, trainerSigned: false }),
             trainerSigned: true,
             trainerName: data.name,
             date: today
           };
         });
         setTasks(newTasks);
         saveData(traineeName, newTasks);
       }
       setScanningSectionId(null);
    }
    // Scenario 3: Supervisor scanning Trainee Progress
    else if (isSupervisorScanning && data.type === 'TRAINEE_PROGRESS') {
      setIsSupervisorScanning(false);
      setScannedTraineeData(data);
    }
    // Error / Mismatch handling
    else {
      if ((scanningTaskId || scanningSectionId) && data.type !== 'SUPERVISOR_SIGNATURE') {
         alert("Virhe: Skannasit pelastajan passin. Skannaa esimiehen kuittauskoodi.");
      }
      else if (isSupervisorScanning && data.type !== 'TRAINEE_PROGRESS') {
         alert("Virhe: Skannasit esimiehen koodin. Skannaa pelastajan passi.");
      }
    }
  };

  const closeScanner = () => {
    setScanningTaskId(null);
    setScanningSectionId(null);
    setIsSupervisorScanning(false);
  };

  // Logic to actually wipe data (called by modal)
  const performClearAll = () => {
    const currentSections = sections;
    const currentIntro = introText;
    const currentOrg = orgSettings;

    storageService.clear();

    // Reset state
    setTraineeName('');
    setTasks({});
    setHasCelebrated(false);

    // Restore structure settings (user doesn't want to lose the layout, just the data)
    setSections(currentSections);
    setIntroText(currentIntro);
    setOrgSettings(currentOrg);

    // Immediately save the structure back so it persists
    const freshData: AppData = {
        traineeName: '',
        tasks: {},
        customSections: currentSections,
        introText: currentIntro,
        organizationSettings: currentOrg,
        lastUpdated: new Date().toISOString()
    };
    storageService.save(freshData);

    setShowClearConfirm(false);
  };

  // Standard print (checklist)
  const printForm = () => {
    setIsPrintingCertificate(false);
    // Allow React to update state before printing
    setTimeout(() => window.print(), 100);
  };

  // Certificate print (diploma)
  const printCertificate = () => {
    setIsPrintingCertificate(true);
    setTimeout(() => {
      window.print();
      // Reset after print dialog closes (approximate) or let user switch back manually
      const cleanup = () => setIsPrintingCertificate(false);
      window.addEventListener('afterprint', cleanup, { once: true });
      setTimeout(cleanup, 5000); 
    }, 100);
  };

  // Calculate stats
  const stats = useMemo(() => {
    let total = 0;
    let completed = 0;
    sections.forEach(section => {
      section.items.forEach(item => {
        total++;
        const s = tasks[item.id];
        if (s && s.traineeSigned && s.trainerSigned) {
          completed++;
        }
      });
    });
    return { total, completed, percentage: total === 0 ? 0 : Math.round((completed/total) * 100) };
  }, [tasks, sections]);

  // Check for completion
  useEffect(() => {
    if (stats.percentage === 100 && !hasCelebrated && stats.total > 0) {
      setShowCompletionModal(true);
      setHasCelebrated(true);
    }
  }, [stats.percentage, hasCelebrated, stats.total]);

  // Determine date to show on certificate (today)
  const todayDate = new Date().toLocaleDateString('fi-FI');

  return (
    <>
      {/* CERTIFICATE VIEW (Only visible when printing certificate) */}
      {isPrintingCertificate && (
         <CertificateView 
           traineeName={traineeName} 
           completionDate={todayDate}
           orgSettings={orgSettings} 
         />
      )}

      {/* MAIN APP VIEW (Hidden when printing certificate) */}
      <div className={`min-h-screen bg-gray-100 print:bg-white pb-12 ${isPrintingCertificate ? 'hidden' : 'block'}`}>

        {/* Header Bar */}
        <header className="bg-primary text-white shadow-md sticky top-0 z-20 print:static print:shadow-none print:bg-white print:text-black">
          <div className="max-w-4xl mx-auto px-4 py-3 flex flex-col sm:flex-row items-center justify-between gap-4">

            {/* Logo & Title */}
            <div className="flex items-center gap-3 w-full sm:w-auto">
              <div className="bg-orange-500 p-2 rounded-lg print:hidden">
                <Flame className="w-6 h-6 text-white" />
              </div>
              <div>
                <h1 className="text-lg font-bold leading-tight">Pelastajan Perehdytys</h1>
                <p className="text-xs text-slate-300 print:hidden">Sähköinen seurantalomake</p>
              </div>
            </div>

            {/* Controls */}
            <div className="flex items-center gap-2 w-full sm:w-auto justify-end no-print overflow-x-auto pb-1 sm:pb-0">

              <button
                onClick={() => setShowUserGuide(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-700 hover:bg-slate-600 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-600 whitespace-nowrap mr-2"
                title="Käyttöohjeet"
              >
                <CircleHelp className="w-4 h-4 text-sky-300" />
                <span className="hidden sm:inline">Ohjeet</span>
              </button>

              {stats.percentage === 100 && (
                <button
                  onClick={() => setShowCompletionModal(true)}
                  className="flex items-center gap-1.5 sm:gap-2 bg-yellow-500 hover:bg-yellow-600 text-white px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors shadow-lg animate-pulse font-bold whitespace-nowrap"
                >
                  <Trophy className="w-4 h-4" />
                  <span>Valmis!</span>
                </button>
              )}

              <button
                onClick={() => setShowTraineeBadge(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-800 hover:bg-slate-700 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-700 whitespace-nowrap"
              >
                <UserCheck className="w-4 h-4 text-accent" />
                <span className="sm:hidden">Passi</span>
                <span className="hidden sm:inline">Oma Passi</span>
              </button>

              <div className="w-px h-6 bg-slate-700 mx-0.5 sm:mx-1"></div>

              <button 
                onClick={() => setShowSupervisorBadge(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-800 hover:bg-slate-700 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-700 whitespace-nowrap"
              >
                <QrCode className="w-4 h-4 text-green-400" />
                <span className="sm:hidden">Esimies</span>
                <span className="hidden sm:inline">Esimiestyökalut</span>
              </button>

              <button 
                onClick={printForm}
                className="p-2 bg-slate-800 hover:bg-slate-700 rounded-lg transition-colors text-slate-200"
                title="Tulosta PDF (Lista)"
              >
                <Printer className="w-5 h-5" />
              </button>

              <button 
                onClick={() => setShowClearConfirm(true)}
                className="p-2 bg-red-900/50 hover:bg-red-900 rounded-lg transition-colors text-red-200 ml-1 sm:ml-2"
                title="Tyhjennä lomake (säilyttää rakenteen)"
              >
                <Trash2 className="w-5 h-5" />
              </button>
            </div>
          </div>
        </header>

        <main className="max-w-4xl mx-auto px-4 py-8 print:py-0 print:px-0">

          {/* Name Input & Intro */}
          <div className="bg-white rounded-lg p-6 shadow-sm border border-gray-200 mb-6 print:border-none print:shadow-none print:p-0">

            <div className="mb-6 no-print">
              <label className="block text-xs font-bold uppercase text-slate-500 mb-2">
                Pelastajan Nimi
              </label>
              <div className="relative">
                <input
                  type="text"
                  value={traineeName}
                  onChange={handleNameChange}
                  placeholder="Kirjoita nimesi tähän..."
                  className="w-full text-lg font-bold text-slate-800 border-b-2 border-slate-200 focus:border-accent outline-none py-2 pl-9 bg-transparent transition-colors placeholder:font-normal placeholder:text-gray-300"
                />
                <UserCheck className="w-6 h-6 text-gray-400 absolute left-0 top-2" />
              </div>
            </div>

            {/* Organization Settings Input for Trainee */}
            <div className="mt-4 p-4 bg-gray-50 rounded-lg border border-gray-200 no-print mb-6">
              <h3 className="text-sm font-bold text-gray-500 uppercase mb-3 flex items-center gap-2">
                <FileText className="w-4 h-4" />
                Tiedot
              </h3>
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                <div>
                   <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Organisaatio</label>
                   <div className="relative">
                     <input 
                       type="text" 
                       value={orgSettings.name}
                       onChange={(e) => handleOrgSettingChange('name', e.target.value)}
                       className="w-full pl-7 px-3 py-2 text-sm border border-gray-300 rounded focus:ring-1 focus:ring-accent outline-none bg-white"
                       placeholder="Esim. Hyvinvointialue"
                     />
                     <Building2 className="w-3.5 h-3.5 text-gray-400 absolute left-2.5 top-2.5" />
                   </div>
                </div>
                <div>
                   <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Yksikkö</label>
                   <input 
                     type="text" 
                     value={orgSettings.subtitle}
                     onChange={(e) => handleOrgSettingChange('subtitle', e.target.value)}
                     className="w-full px-3 py-2 text-sm border border-gray-300 rounded focus:ring-1 focus:ring-accent outline-none bg-white"
                     placeholder="Esim. Pelastustoimi"
                   />
                </div>
                <div>
                   <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Paikkakunta</label>
                   <div className="relative">
                     <input 
                       type="text" 
                       value={orgSettings.city}
                       onChange={(e) => handleOrgSettingChange('city', e.target.value)}
                       className="w-full pl-7 px-3 py-2 text-sm border border-gray-300 rounded focus:ring-1 focus:ring-accent outline-none bg-white"
                       placeholder="Esim. Helsinki"
                     />
                     <MapPin className="w-3.5 h-3.5 text-gray-400 absolute left-2.5 top-2.5" />
                   </div>
                </div>
              </div>
            </div>

            <div className="prose prose-sm max-w-none text-slate-600 mb-2 print:text-xs whitespace-pre-line">
              {introText}
            </div>

            {/* Print Header */}
            <div className="hidden print:block mb-8 border-b-2 border-black pb-4">
                <span className="text-sm text-gray-500 uppercase">Pelastaja</span>
                <div className="text-2xl font-bold">{traineeName}</div>
                <div className="mt-2 text-xs text-gray-500">
                  {orgSettings.name} - {orgSettings.subtitle}
                </div>
            </div>
          </div>

          {/* Sticky Progress Bar */}
          <div className="bg-white/95 backdrop-blur rounded-lg p-4 shadow-sm border border-gray-200 mb-8 flex items-center gap-4 no-print sticky top-20 z-10 transition-shadow">
            <div className={`p-2 rounded-full ${stats.percentage === 100 ? 'bg-green-100' : 'bg-gray-100'}`}>
              <CheckCircle className={`w-6 h-6 ${stats.percentage === 100 ? 'text-green-600' : 'text-gray-400'}`} />
            </div>
            <div className="flex-1">
              <div className="flex justify-between items-end mb-1">
                <span className="font-bold text-slate-700">Edistyminen</span>
                <span className="text-sm font-medium text-accent">{stats.completed} / {stats.total} ({stats.percentage}%)</span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2.5">
                <div 
                  className={`h-2.5 rounded-full transition-all duration-700 ${stats.percentage === 100 ? 'bg-green-500' : 'bg-accent'}`}
                  style={{ width: `${stats.percentage}%` }}
                ></div>
              </div>
            </div>
          </div>

          {/* Form Sections (Using state 'sections' instead of constant 'SECTIONS') */}
          <div className="space-y-4">
            {sections.map(section => (
              <SectionGroup 
                key={section.id} 
                section={section} 
                tasks={tasks} 
                traineeName={traineeName}
                onTaskChange={handleTaskChange}
                onScanRequest={handleScanRequest}
                onSectionScanRequest={handleSectionScanRequest}
              />
            ))}
          </div>

          {/* Print Signature Box (Only for list view) */}
          <div className="hidden print:block mt-8 pt-8 border-t-2 border-black page-break">
            {/* Signatures removed per request for the checklist printout, kept simple */}
            <div className="text-center text-xs text-gray-500">
              Tulostettu: {todayDate} - {orgSettings.city}
            </div>
          </div>

        </main>

        {/* Modals */}
        {showClearConfirm && (
          <ClearConfirmationModal 
            onConfirm={performClearAll} 
            onClose={() => setShowClearConfirm(false)} 
          />
        )}

        {showSupervisorBadge && (
          <SupervisorBadge 
            onClose={() => setShowSupervisorBadge(false)} 
            onScanRequest={handleSupervisorScanRequest}
            onEditContent={() => setShowEditor(true)}
            currentSections={sections}
            currentIntroText={introText}
          />
        )}

        {showEditor && (
          <ContentEditorModal 
            initialSections={sections}
            initialIntroText={introText}
            onSave={handleUpdateContent}
            onReset={handleResetContent}
            onClose={() => setShowEditor(false)}
          />
        )}

        {showUserGuide && (
          <UserGuideModal onClose={() => setShowUserGuide(false)} />
        )}

        {showTraineeBadge && (
          <TraineeBadge 
            traineeName={traineeName}
            tasks={tasks}
            onClose={() => setShowTraineeBadge(false)}
          />
        )}

        {scannedTraineeData && (
          <TraineeReportModal 
            data={scannedTraineeData}
            onClose={() => setScannedTraineeData(null)}
          />
        )}

        {showCompletionModal && (
          <CompletionModal
            traineeName={traineeName}
            onClose={() => setShowCompletionModal(false)}
            onPrint={printCertificate} 
          />
        )}

        {(scanningTaskId || scanningSectionId || isSupervisorScanning) && (
          <ScannerModal 
            onScanSuccess={handleScanSuccess} 
            onClose={closeScanner} 
          />
        )}

      </div>
    </>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import LZString from 'lz-string';
import { SECTIONS, DEFAULT_INTRO_TEXT, DEFAULT_ORG_SETTINGS } from './constants';
import { TaskState, TraineeQrData, Section, OrganizationSettings, TemplateRawData } from './types';
import { SectionGroup } from './components/SectionGroup';
import { storageService, AppData } from './storage';
import { SupervisorBadge } from './components/SupervisorBadge';
import { ScannerModal } from './components/ScannerModal';
import { TraineeBadge } from './components/TraineeBadge';
import { TraineeReportModal } from './components/TraineeReportModal';
import { CompletionModal } from './components/CompletionModal';
import { CertificateView } from './components/CertificateView';
import { ContentEditorModal } from './components/ContentEditorModal';
import { UserGuideModal } from './components/UserGuideModal';
import { ClearConfirmationModal } from './components/ClearConfirmationModal';
import { Printer, Flame, CheckCircle, QrCode, Trash2, UserCheck, Trophy, CircleHelp, Building2, MapPin, FileText } from 'lucide-react';

const App: React.FC = () => {
  // Data State
  const [traineeName, setTraineeName] = useState('');
  const [tasks, setTasks] = useState<Record<string, TaskState>>({});
  const [sections, setSections] = useState<Section[]>(SECTIONS);
  const [introText, setIntroText] = useState(DEFAULT_INTRO_TEXT);
  const [orgSettings, setOrgSettings] = useState<OrganizationSettings>(DEFAULT_ORG_SETTINGS);

  // UI State
  const [showSupervisorBadge, setShowSupervisorBadge] = useState(false);
  const [isSupervisorAuthenticated, setIsSupervisorAuthenticated] = useState(false); // New: Persist auth state
  const [showTraineeBadge, setShowTraineeBadge] = useState(false);
  const [showCompletionModal, setShowCompletionModal] = useState(false);
  const [showEditor, setShowEditor] = useState(false);
  const [showUserGuide, setShowUserGuide] = useState(false);
  const [showClearConfirm, setShowClearConfirm] = useState(false);
  const [isPrintingCertificate, setIsPrintingCertificate] = useState(false);

  // Keep track if we've already shown the celebration once per session to avoid annoyance
  const [hasCelebrated, setHasCelebrated] = useState(false);

  // Scan States
  const [scanningTaskId, setScanningTaskId] = useState<string | null>(null);
  const [scanningSectionId, setScanningSectionId] = useState<string | null>(null);
  const [isSupervisorScanning, setIsSupervisorScanning] = useState(false);

  const [scannedTraineeData, setScannedTraineeData] = useState<TraineeQrData | null>(null);

  // Helper to generate IDs for imported content
  const generateSlugId = (text: string, prefix: string) => {
    const slug = text.toLowerCase()
      .replace(/ä/g, 'a').replace(/ö/g, 'o').replace(/å/g, 'a')
      .replace(/[^a-z0-9]/g, '_')
      .replace(/_+/g, '_');
    return `${prefix}_${slug.substring(0, 15)}_${Math.floor(Math.random() * 1000)}`;
  };

  // Helper to Apply Template Data
  const applyTemplate = (rawData: TemplateRawData) => {
    // Un-minify sections and regenerate IDs if missing
    const newSections: Section[] = rawData.s.map((minSec, idx) => ({
      id: minSec.i || generateSlugId(minSec.t, `s${idx}`),
      title: minSec.t,
      subtitle: minSec.s,
      items: minSec.it.map((minItem, iIdx) => ({
        id: minItem.i || generateSlugId(minItem.l, `i${idx}_${iIdx}`),
        label: minItem.l
      }))
    }));

    // Save locally
    setSections(newSections);
    setIntroText(rawData.intro);

    // Persist to storage
    const currentData = storageService.load();
    const newData: AppData = {
        ...currentData,
        customSections: newSections,
        introText: rawData.intro,
        lastUpdated: new Date().toISOString()
    };
    storageService.save(newData);

    alert('Uusi perehdytysrunko aktivoitu onnistuneesti!');
  };

  // Load data on mount & Check for URL Template Params
  useEffect(() => {
    // 1. Load LocalStorage
    const data = storageService.load();
    setTraineeName(data.traineeName);
    setTasks(data.tasks);
    if (data.customSections && data.customSections.length > 0) {
      setSections(data.customSections);
    }
    if (data.introText) {
      setIntroText(data.introText);
    }
    if (data.organizationSettings) {
      setOrgSettings(data.organizationSettings);
    }

    // 2. Check for Template in URL
    const params = new URLSearchParams(window.location.search);
    const templateString = params.get('template');

    if (templateString) {
      try {
        const decompressed = LZString.decompressFromEncodedURIComponent(templateString);
        if (decompressed) {
          const rawData = JSON.parse(decompressed) as TemplateRawData;

          if (rawData && rawData.s && confirm('Linkistä löytyi uusi perehdytysrunko. Haluatko ottaa sen käyttöön? Tämä päivittää lomakkeen rakenteen.')) {
             applyTemplate(rawData);

             // Clean URL without refresh
             const newUrl = window.location.pathname;
             window.history.replaceState({}, '', newUrl);
          }
        }
      } catch (e) {
        console.error("Template load failed", e);
      }
    }
  }, []);

  // Save data on change
  const saveData = (
    newName: string, 
    newTasks: Record<string, TaskState>, 
    newSections?: Section[], 
    newIntroText?: string,
    newOrgSettings?: OrganizationSettings
  ) => {
    const data: AppData = {
      traineeName: newName,
      tasks: newTasks,
      customSections: newSections || sections,
      introText: newIntroText || introText,
      organizationSettings: newOrgSettings || orgSettings,
      lastUpdated: new Date().toISOString()
    };
    storageService.save(data);
  };

  const handleNameChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newName = e.target.value;
    setTraineeName(newName);
    saveData(newName, tasks);
  };

  const handleOrgSettingChange = (field: keyof OrganizationSettings, value: string) => {
    const newSettings = { ...orgSettings, [field]: value };
    setOrgSettings(newSettings);
    saveData(traineeName, tasks, sections, introText, newSettings);
  };

  const handleTaskChange = (taskId: string, updates: Partial<TaskState>) => {
    const newTasks = {
      ...tasks,
      [taskId]: {
        ...(tasks[taskId] || { date: '', traineeSigned: false, trainerSigned: false }),
        ...updates
      }
    };
    setTasks(newTasks);
    saveData(traineeName, newTasks);
  };

  const handleUpdateContent = (newSections: Section[], newIntroText: string) => {
    setSections(newSections);
    setIntroText(newIntroText);
    // Don't update orgSettings here, as they are now handled by the trainee in the main view
    saveData(traineeName, tasks, newSections, newIntroText, orgSettings);
  };

  // Wrapper for editor save to redirect back to supervisor menu
  const handleEditorSave = (newSections: Section[], newIntroText: string) => {
    handleUpdateContent(newSections, newIntroText);
    // Re-open supervisor menu automatically
    setShowSupervisorBadge(true);
  };

  const handleResetContent = () => {
    setSections(SECTIONS);
    setIntroText(DEFAULT_INTRO_TEXT);
    setOrgSettings(DEFAULT_ORG_SETTINGS);
    saveData(traineeName, tasks, SECTIONS, DEFAULT_INTRO_TEXT, DEFAULT_ORG_SETTINGS);
  };

  // Wrapper for editor reset to redirect back to supervisor menu
  const handleEditorReset = () => {
    handleResetContent();
    setShowSupervisorBadge(true);
  };

  const handleScanRequest = (taskId: string) => {
    setScanningTaskId(taskId);
  };

  const handleSectionScanRequest = (sectionId: string) => {
    setScanningSectionId(sectionId);
  };

  const handleSupervisorScanRequest = () => {
    setIsSupervisorScanning(true);
  };

  const handleScanSuccess = (data: any) => {
    const today = new Date().toISOString().split('T')[0];

    // Scenario 1: Trainee scanning Supervisor Signature for a SINGLE TASK
    if (scanningTaskId && data.type === 'SUPERVISOR_SIGNATURE' && data.name) {
       handleTaskChange(scanningTaskId, {
         trainerSigned: true,
         trainerName: data.name,
         date: today
       });
       setScanningTaskId(null);
    }
    // Scenario 2: Trainee scanning Supervisor Signature for a WHOLE SECTION
    else if (scanningSectionId && data.type === 'SUPERVISOR_SIGNATURE' && data.name) {
       const section = sections.find(s => s.id === scanningSectionId);
       if (section) {
         const newTasks = { ...tasks };
         section.items.forEach(item => {
           // Update each task in the section
           newTasks[item.id] = {
             ...(newTasks[item.id] || { date: '', traineeSigned: false, trainerSigned: false }),
             trainerSigned: true,
             trainerName: data.name,
             date: today
           };
         });
         setTasks(newTasks);
         saveData(traineeName, newTasks);
       }
       setScanningSectionId(null);
    }
    // Scenario 3: Supervisor scanning Trainee Progress
    else if (isSupervisorScanning && data.type === 'TRAINEE_PROGRESS') {
      setIsSupervisorScanning(false);
      setScannedTraineeData(data);
    }
    // Error / Mismatch handling
    else {
      if ((scanningTaskId || scanningSectionId) && data.type !== 'SUPERVISOR_SIGNATURE') {
         alert("Virhe: Skannasit pelastajan passin. Skannaa esimiehen kuittauskoodi.");
      }
      else if (isSupervisorScanning && data.type !== 'TRAINEE_PROGRESS') {
         alert("Virhe: Skannasit esimiehen koodin. Skannaa pelastajan passi.");
      }
    }
  };

  const closeScanner = () => {
    setScanningTaskId(null);
    setScanningSectionId(null);
    setIsSupervisorScanning(false);
  };

  // Logic to actually wipe data (called by modal)
  const performClearAll = () => {
    const currentSections = sections;
    const currentIntro = introText;
    const currentOrg = orgSettings;

    storageService.clear();

    // Reset state
    setTraineeName('');
    setTasks({});
    setHasCelebrated(false);

    // Restore structure settings (user doesn't want to lose the layout, just the data)
    setSections(currentSections);
    setIntroText(currentIntro);
    setOrgSettings(currentOrg);

    // Immediately save the structure back so it persists
    const freshData: AppData = {
        traineeName: '',
        tasks: {},
        customSections: currentSections,
        introText: currentIntro,
        organizationSettings: currentOrg,
        lastUpdated: new Date().toISOString()
    };
    storageService.save(freshData);

    setShowClearConfirm(false);
  };

  // Standard print (checklist)
  const printForm = () => {
    setIsPrintingCertificate(false);
    // Allow React to update state before printing
    setTimeout(() => window.print(), 100);
  };

  // Certificate print (diploma)
  const printCertificate = () => {
    setIsPrintingCertificate(true);
    setTimeout(() => {
      window.print();
      // Reset after print dialog closes (approximate) or let user switch back manually
      const cleanup = () => setIsPrintingCertificate(false);
      window.addEventListener('afterprint', cleanup, { once: true });
      setTimeout(cleanup, 5000); 
    }, 100);
  };

  // Calculate stats
  const stats = useMemo(() => {
    let total = 0;
    let completed = 0;
    sections.forEach(section => {
      section.items.forEach(item => {
        total++;
        const s = tasks[item.id];
        if (s && s.traineeSigned && s.trainerSigned) {
          completed++;
        }
      });
    });
    return { total, completed, percentage: total === 0 ? 0 : Math.round((completed/total) * 100) };
  }, [tasks, sections]);

  // Check for completion
  useEffect(() => {
    if (stats.percentage === 100 && !hasCelebrated && stats.total > 0) {
      setShowCompletionModal(true);
      setHasCelebrated(true);
    }
  }, [stats.percentage, hasCelebrated, stats.total]);

  // Determine date to show on certificate (today)
  const todayDate = new Date().toLocaleDateString('fi-FI');

  return (
    <>
      {/* CERTIFICATE VIEW (Only visible when printing certificate) */}
      {isPrintingCertificate && (
         <CertificateView 
           traineeName={traineeName} 
           completionDate={todayDate}
           orgSettings={orgSettings} 
         />
      )}

      {/* MAIN APP VIEW (Hidden when printing certificate) */}
      <div className={`min-h-screen bg-gray-100 print:bg-white pb-12 ${isPrintingCertificate ? 'hidden' : 'block'}`}>

        {/* Header Bar */}
        <header className="bg-primary text-white shadow-md sticky top-0 z-20 print:static print:shadow-none print:bg-white print:text-black">
          <div className="max-w-4xl mx-auto px-4 py-3 flex flex-col sm:flex-row items-center justify-between gap-4">

            {/* Logo & Title */}
            <div className="flex items-center gap-3 w-full sm:w-auto">
              <div className="bg-orange-500 p-2 rounded-lg print:hidden">
                <Flame className="w-6 h-6 text-white" />
              </div>
              <div>
                <h1 className="text-lg font-bold leading-tight">Pelastajan Perehdytys</h1>
                <p className="text-xs text-slate-300 print:hidden">Sähköinen seurantalomake</p>
              </div>
            </div>

            {/* Controls */}
            <div className="flex items-center gap-2 w-full sm:w-auto justify-end no-print overflow-x-auto pb-1 sm:pb-0">

              <button
                onClick={() => setShowUserGuide(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-700 hover:bg-slate-600 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-600 whitespace-nowrap mr-2"
                title="Käyttöohjeet"
              >
                <CircleHelp className="w-4 h-4 text-sky-300" />
                <span className="hidden sm:inline">Ohjeet</span>
              </button>

              {stats.percentage === 100 && (
                <button
                  onClick={() => setShowCompletionModal(true)}
                  className="flex items-center gap-1.5 sm:gap-2 bg-yellow-500 hover:bg-yellow-600 text-white px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors shadow-lg animate-pulse font-bold whitespace-nowrap"
                >
                  <Trophy className="w-4 h-4" />
                  <span>Valmis!</span>
                </button>
              )}

              <button
                onClick={() => setShowTraineeBadge(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-800 hover:bg-slate-700 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-700 whitespace-nowrap"
              >
                <UserCheck className="w-4 h-4 text-accent" />
                <span className="sm:hidden">Passi</span>
                <span className="hidden sm:inline">Oma Passi</span>
              </button>

              <div className="w-px h-6 bg-slate-700 mx-0.5 sm:mx-1"></div>

              <button 
                onClick={() => setShowSupervisorBadge(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-800 hover:bg-slate-700 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-700 whitespace-nowrap"
              >
                <QrCode className="w-4 h-4 text-green-400" />
                <span className="sm:hidden">Esimies</span>
                <span className="hidden sm:inline">Esimiestyökalut</span>
              </button>

              <button 
                onClick={printForm}
                className="p-2 bg-slate-800 hover:bg-slate-700 rounded-lg transition-colors text-slate-200"
                title="Tulosta PDF (Lista)"
              >
                <Printer className="w-5 h-5" />
              </button>

              <button 
                onClick={() => setShowClearConfirm(true)}
                className="p-2 bg-red-900/50 hover:bg-red-900 rounded-lg transition-colors text-red-200 ml-1 sm:ml-2"
                title="Tyhjennä lomake (säilyttää rakenteen)"
              >
                <Trash2 className="w-5 h-5" />
              </button>
            </div>
          </div>
        </header>

        <main className="max-w-4xl mx-auto px-4 py-8 print:py-0 print:px-0">

          {/* Name Input & Intro */}
          <div className="bg-white rounded-lg p-6 shadow-sm border border-gray-200 mb-6 print:border-none print:shadow-none print:p-0">

            <div className="mb-6 no-print">
              <label className="block text-xs font-bold uppercase text-slate-500 mb-2">
                Pelastajan Nimi
              </label>
              <div className="relative">
                <input
                  type="text"
                  value={traineeName}
                  onChange={handleNameChange}
                  placeholder="Kirjoita nimesi tähän..."
                  className="w-full text-lg font-bold text-slate-800 border-b-2 border-slate-200 focus:border-accent outline-none py-2 pl-9 bg-transparent transition-colors placeholder:font-normal placeholder:text-gray-300"
                />
                <UserCheck className="w-6 h-6 text-gray-400 absolute left-0 top-2" />
              </div>
            </div>

            {/* Organization Settings Input for Trainee */}
            <div className="mt-4 p-4 bg-gray-50 rounded-lg border border-gray-200 no-print mb-6">
              <h3 className="text-sm font-bold text-gray-500 uppercase mb-3 flex items-center gap-2">
                <FileText className="w-4 h-4" />
                Tiedot
              </h3>
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                <div>
                   <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Organisaatio</label>
                   <div className="relative">
                     <input 
                       type="text" 
                       value={orgSettings.name}
                       onChange={(e) => handleOrgSettingChange('name', e.target.value)}
                       className="w-full pl-7 px-3 py-2 text-sm border border-gray-300 rounded focus:ring-1 focus:ring-accent outline-none bg-white"
                       placeholder="Esim. Hyvinvointialue"
                     />
                     <Building2 className="w-3.5 h-3.5 text-gray-400 absolute left-2.5 top-2.5" />
                   </div>
                </div>
                <div>
                   <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Yksikkö</label>
                   <input 
                     type="text" 
                     value={orgSettings.subtitle}
                     onChange={(e) => handleOrgSettingChange('subtitle', e.target.value)}
                     className="w-full px-3 py-2 text-sm border border-gray-300 rounded focus:ring-1 focus:ring-accent outline-none bg-white"
                     placeholder="Esim. Pelastustoimi"
                   />
                </div>
                <div>
                   <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Paikkakunta</label>
                   <div className="relative">
                     <input 
                       type="text" 
                       value={orgSettings.city}
                       onChange={(e) => handleOrgSettingChange('city', e.target.value)}
                       className="w-full pl-7 px-3 py-2 text-sm border border-gray-300 rounded focus:ring-1 focus:ring-accent outline-none bg-white"
                       placeholder="Esim. Helsinki"
                     />
                     <MapPin className="w-3.5 h-3.5 text-gray-400 absolute left-2.5 top-2.5" />
                   </div>
                </div>
              </div>
            </div>

            <div className="prose prose-sm max-w-none text-slate-600 mb-2 print:text-xs whitespace-pre-line">
              {introText}
            </div>

            {/* Print Header */}
            <div className="hidden print:block mb-8 border-b-2 border-black pb-4">
                <span className="text-sm text-gray-500 uppercase">Pelastaja</span>
                <div className="text-2xl font-bold">{traineeName}</div>
                <div className="mt-2 text-xs text-gray-500">
                  {orgSettings.name} - {orgSettings.subtitle}
                </div>
            </div>
          </div>

          {/* Sticky Progress Bar */}
          <div className="bg-white/95 backdrop-blur rounded-lg p-4 shadow-sm border border-gray-200 mb-8 flex items-center gap-4 no-print sticky top-20 z-10 transition-shadow">
            <div className={`p-2 rounded-full ${stats.percentage === 100 ? 'bg-green-100' : 'bg-gray-100'}`}>
              <CheckCircle className={`w-6 h-6 ${stats.percentage === 100 ? 'text-green-600' : 'text-gray-400'}`} />
            </div>
            <div className="flex-1">
              <div className="flex justify-between items-end mb-1">
                <span className="font-bold text-slate-700">Edistyminen</span>
                <span className="text-sm font-medium text-accent">{stats.completed} / {stats.total} ({stats.percentage}%)</span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2.5">
                <div 
                  className={`h-2.5 rounded-full transition-all duration-700 ${stats.percentage === 100 ? 'bg-green-500' : 'bg-accent'}`}
                  style={{ width: `${stats.percentage}%` }}
                ></div>
              </div>
            </div>
          </div>

          {/* Form Sections (Using state 'sections' instead of constant 'SECTIONS') */}
          <div className="space-y-4">
            {sections.map(section => (
              <SectionGroup 
                key={section.id} 
                section={section} 
                tasks={tasks} 
                traineeName={traineeName}
                onTaskChange={handleTaskChange}
                onScanRequest={handleScanRequest}
                onSectionScanRequest={handleSectionScanRequest}
              />
            ))}
          </div>

          {/* Print Signature Box (Only for list view) */}
          <div className="hidden print:block mt-8 pt-8 border-t-2 border-black page-break">
            {/* Signatures removed per request for the checklist printout, kept simple */}
            <div className="text-center text-xs text-gray-500">
              Tulostettu: {todayDate} - {orgSettings.city}
            </div>
          </div>

        </main>

        {/* Modals */}
        {showClearConfirm && (
          <ClearConfirmationModal 
            onConfirm={performClearAll} 
            onClose={() => setShowClearConfirm(false)} 
          />
        )}

        {showSupervisorBadge && (
          <SupervisorBadge 
            onClose={() => setShowSupervisorBadge(false)} 
            onScanRequest={handleSupervisorScanRequest}
            onEditContent={() => setShowEditor(true)}
            currentSections={sections}
            currentIntroText={introText}
            isAuthenticated={isSupervisorAuthenticated} // Pass auth state
            onLogin={() => setIsSupervisorAuthenticated(true)} // Handle login
          />
        )}

        {showEditor && (
          <ContentEditorModal 
            initialSections={sections}
            initialIntroText={introText}
            onSave={handleEditorSave} // Use wrapper
            onReset={handleEditorReset} // Use wrapper
            onClose={() => setShowEditor(false)}
          />
        )}

        {showUserGuide && (
          <UserGuideModal onClose={() => setShowUserGuide(false)} />
        )}

        {showTraineeBadge && (
          <TraineeBadge 
            traineeName={traineeName}
            tasks={tasks}
            onClose={() => setShowTraineeBadge(false)}
          />
        )}

        {scannedTraineeData && (
          <TraineeReportModal 
            data={scannedTraineeData}
            onClose={() => setScannedTraineeData(null)}
          />
        )}

        {showCompletionModal && (
          <CompletionModal
            traineeName={traineeName}
            onClose={() => setShowCompletionModal(false)}
            onPrint={printCertificate} 
          />
        )}

        {(scanningTaskId || scanningSectionId || isSupervisorScanning) && (
          <ScannerModal 
            onScanSuccess={handleScanSuccess} 
            onClose={closeScanner} 
          />
        )}

      </div>
    </>
  );
};

export default App;

import React, { useEffect, useState } from 'react';
import QRCode from 'qrcode';
import LZString from 'lz-string';
import { X, ShieldCheck, UserPen, Lock, KeyRound, Download, ScanLine, FilePenLine, Share2, Copy, Check, Link } from 'lucide-react';
import { Section, TemplateRawData } from '../types';

interface SupervisorBadgeProps {
  onClose: () => void;
  onScanRequest: () => void;
  onEditContent: () => void;
  currentSections: Section[];
  currentIntroText: string;
  isAuthenticated: boolean;
  onLogin: () => void;
}

export const SupervisorBadge: React.FC<SupervisorBadgeProps> = ({ 
  onClose, 
  onScanRequest, 
  onEditContent,
  currentSections,
  currentIntroText,
  isAuthenticated,
  onLogin
}) => {
  const [passwordInput, setPasswordInput] = useState('');
  const [error, setError] = useState(false);

  const [name, setName] = useState('');
  const [qrUrl, setQrUrl] = useState<string>('');

  // State for Template Sharing
  const [showShareModal, setShowShareModal] = useState(false);
  const [shareUrl, setShareUrl] = useState<string>('');
  const [copied, setCopied] = useState(false);

  // Effect for Supervisor Signature QR
  useEffect(() => {
    if (!name.trim()) {
      setQrUrl('');
      return;
    }

    const signaturePayload = JSON.stringify({
      type: 'SUPERVISOR_SIGNATURE',
      name: name.trim(),
      timestamp: Date.now()
    });

    QRCode.toDataURL(signaturePayload, { width: 400, margin: 2 })
      .then((url) => {
        setQrUrl(url);
      })
      .catch((err) => {
        console.error("QR Generation failed", err);
      });
  }, [name]);

  // Generate Share URL when modal opens
  useEffect(() => {
    if (showShareModal) {
      try {
        // 1. Minify data structure
        const minifiedSections = currentSections.map(sec => {
          const sObj: any = {
            t: sec.title,
            it: sec.items.map(item => ({
              l: item.label
            }))
          };
          if (sec.subtitle) sObj.s = sec.subtitle;
          return sObj;
        });

        const rawData: TemplateRawData = {
          intro: currentIntroText,
          s: minifiedSections
        };

        const jsonString = JSON.stringify(rawData);

        // 2. Compress using compressToEncodedURIComponent for safe URL usage
        const compressed = LZString.compressToEncodedURIComponent(jsonString);

        // 3. Construct URL
        const baseUrl = window.location.href.split('?')[0];
        const fullUrl = `${baseUrl}?template=${compressed}`;

        setShareUrl(fullUrl);
      } catch (e) {
        console.error("Compression failed", e);
        setShareUrl("Virhe linkin luonnissa.");
      }
    }
  }, [showShareModal, currentSections, currentIntroText]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === '112') {
        onLogin();
        setError(false);
    } else {
        setError(true);
        setPasswordInput('');
    }
  };

  const handleDownload = (url: string, filenamePrefix: string) => {
    if (!url) return;
    const link = document.createElement('a');
    link.href = url;
    const safeName = name.replace(/[^a-z0-9]/gi, '_').toLowerCase() || 'template';
    link.download = `perehdytys-${filenamePrefix}-${safeName}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleStartScan = () => {
    onClose();
    onScanRequest();
  };

  const handleStartEdit = () => {
    onClose();
    onEditContent();
  };

  const copyToClipboard = async () => {
    try {
      await navigator.clipboard.writeText(shareUrl);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch (err) {
      console.error('Failed to copy', err);
    }
  };

  const shareNative = async () => {
    if (navigator.share) {
      try {
        await navigator.share({
          title: 'Perehdytysrunko',
          text: 'Tässä on päivitetty perehdytysrunko.',
          url: shareUrl,
        });
      } catch (err) {
        console.log('Share canceled');
      }
    } else {
      copyToClipboard();
    }
  };

  if (!isAuthenticated) {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
        <div className="bg-white rounded-2xl w-full max-w-sm overflow-hidden shadow-2xl animate-in fade-in zoom-in duration-200">
          <div className="bg-slate-800 p-4 flex justify-between items-center text-white">
            <div className="flex items-center gap-2">
              <Lock className="w-5 h-5 text-orange-400" />
              <h3 className="font-bold">Esimieskirjautuminen</h3>
            </div>
            <button onClick={onClose} className="p-1 hover:bg-slate-700 rounded-full transition-colors">
              <X className="w-5 h-5" />
            </button>
          </div>

          <form onSubmit={handleLogin} className="p-6 space-y-4">
            <div>
              <label className="block text-xs font-bold uppercase text-gray-500 mb-2">
                Salasana
              </label>
              <div className="relative">
                <input 
                  type="password" 
                  value={passwordInput}
                  onChange={(e) => setPasswordInput(e.target.value)}
                  className={`w-full pl-10 pr-4 py-2 border-2 rounded-lg outline-none transition-colors ${error ? 'border-red-300 focus:border-red-500' : 'border-slate-200 focus:border-slate-800'}`}
                  autoFocus
                  placeholder="Syötä salasana"
                />
                <KeyRound className="w-5 h-5 text-gray-400 absolute left-3 top-2.5" />
              </div>
              {error && (
                <p className="text-red-500 text-xs mt-2 font-medium">
                  Väärä salasana. Yritä uudelleen.
                </p>
              )}
            </div>

            <button 
              type="submit"
              className="w-full py-3 bg-slate-800 text-white rounded-lg font-bold hover:bg-slate-700 transition-colors shadow-lg shadow-slate-900/20"
            >
              Kirjaudu
            </button>
          </form>
        </div>
      </div>
    );
  }

  // --- SHARE URL VIEW ---
  if (showShareModal) {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
        <div className="bg-white rounded-2xl w-full max-w-lg overflow-hidden shadow-2xl animate-in fade-in zoom-in duration-200 flex flex-col max-h-[90vh]">
          <div className="bg-slate-800 p-4 flex justify-between items-center text-white shrink-0">
            <div className="flex items-center gap-2">
              <Link className="w-5 h-5 text-accent" />
              <h3 className="font-bold">Jaa perehdytysrunko linkillä</h3>
            </div>
            <button onClick={() => setShowShareModal(false)} className="p-1 hover:bg-slate-700 rounded-full transition-colors">
              <X className="w-5 h-5" />
            </button>
          </div>

          <div className="p-6 space-y-6">
             <div className="bg-blue-50 border border-blue-100 p-4 rounded-lg text-sm text-blue-900">
               Lähetä tämä linkki pelastajalle (esim. WhatsApp tai sähköposti). Kun pelastaja avaa linkin omalla laitteellaan, sovellus päivittää perehdytysrungon automaattisesti.
             </div>

             <div>
               <label className="block text-xs font-bold uppercase text-gray-500 mb-2">
                 Jako-linkki
               </label>
               <div className="flex gap-2">
                 <input 
                   type="text" 
                   readOnly 
                   value={shareUrl} 
                   className="flex-1 px-3 py-2 border rounded-lg bg-gray-50 text-gray-600 text-sm focus:outline-none"
                 />
                 <button 
                   onClick={copyToClipboard}
                   className={`px-4 py-2 rounded-lg font-bold transition-all flex items-center gap-2 ${copied ? 'bg-green-500 text-white' : 'bg-gray-200 text-gray-700 hover:bg-gray-300'}`}
                 >
                   {copied ? <Check className="w-4 h-4" /> : <Copy className="w-4 h-4" />}
                   {copied ? 'Kopioitu' : 'Kopioi'}
                 </button>
               </div>
             </div>

             <button 
               onClick={shareNative}
               className="w-full py-4 bg-accent text-white rounded-xl font-bold hover:bg-sky-600 flex items-center justify-center gap-2 shadow-lg shadow-sky-500/20"
             >
               <Share2 className="w-5 h-5" />
               Jaa sovellukseen...
             </button>
          </div>

          <div className="p-4 border-t border-gray-100 bg-gray-50">
            <button 
              onClick={() => setShowShareModal(false)}
              className="w-full py-3 bg-white border border-gray-300 text-slate-700 rounded-lg font-bold hover:bg-gray-100"
            >
              Sulje
            </button>
          </div>
        </div>
      </div>
    );
  }

  // --- MAIN MENU VIEW ---
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl w-full max-w-sm overflow-hidden shadow-2xl animate-in fade-in zoom-in duration-200">

        <div className="bg-slate-800 p-4 flex justify-between items-center text-white">
          <div className="flex items-center gap-2">
            <ShieldCheck className="w-5 h-5 text-green-400" />
            <h3 className="font-bold">Esimiehen Työkalut</h3>
          </div>
          <button onClick={onClose} className="p-1 hover:bg-slate-700 rounded-full transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="p-6 space-y-8 max-h-[80vh] overflow-y-auto">

          {/* Section 1: Generate Supervisor ID */}
          <div className="space-y-4">
            <h4 className="text-sm font-bold uppercase text-slate-500 border-b pb-1">1. Esimiehen Tunniste</h4>

            <div className="w-full">
              <label className="block text-xs font-bold text-gray-400 mb-2">
                Esimiehen Nimi
              </label>
              <div className="relative">
                <input 
                  type="text" 
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  placeholder="Esim. Matti Meikäläinen"
                  className="w-full pl-10 pr-4 py-2 border-2 border-slate-200 rounded-lg focus:border-slate-800 outline-none transition-colors"
                />
                <UserPen className="w-5 h-5 text-gray-400 absolute left-3 top-2.5" />
              </div>
            </div>

            <div className={`p-4 bg-white border-2 rounded-xl flex items-center justify-center transition-all duration-300 ${qrUrl ? 'border-green-500 shadow-sm' : 'border-gray-100 bg-gray-50'}`}>
              {qrUrl ? (
                <div className="text-center space-y-2">
                    <img src={qrUrl} alt="Esimiehen QR-koodi" className="w-32 h-32 mx-auto" />
                    <button 
                        onClick={() => handleDownload(qrUrl, 'esimies')}
                        className="text-xs flex items-center justify-center gap-1 text-slate-500 hover:text-slate-800 mx-auto"
                    >
                        <Download className="w-3 h-3" /> Tallenna kuva
                    </button>
                </div>
              ) : (
                <div className="w-32 h-32 flex items-center justify-center text-gray-300 text-xs italic">
                  Kirjoita nimi...
                </div>
              )}
            </div>
          </div>

          {/* Section 2: Scan Trainee */}
          <div className="space-y-4">
             <h4 className="text-sm font-bold uppercase text-slate-500 border-b pb-1">2. Tarkista Pelastaja</h4>
             <button
               onClick={handleStartScan}
               className="w-full py-3 bg-accent hover:bg-sky-600 text-white rounded-xl font-bold transition-colors flex items-center justify-center gap-3 shadow-lg shadow-sky-500/20"
             >
                <ScanLine className="w-5 h-5" />
                Tarkista Pelastajan Passi
             </button>
          </div>

          {/* Section 3: Edit Form */}
          <div className="space-y-4">
             <h4 className="text-sm font-bold uppercase text-slate-500 border-b pb-1">3. Hallinta</h4>
             <div className="bg-gray-50 rounded-xl p-4 border border-gray-100 space-y-3">
               <p className="text-xs text-gray-500 text-center">
                 Muokkaa lomakkeen rakennetta ja jaa se pelastajalle.
               </p>

               <button
                 onClick={handleStartEdit}
                 className="w-full py-3 bg-white border-2 border-slate-200 hover:border-slate-400 text-slate-700 rounded-xl font-bold transition-colors flex items-center justify-center gap-3"
               >
                  <FilePenLine className="w-5 h-5" />
                  Muokkaa runkoa
               </button>

               <button
                 onClick={() => setShowShareModal(true)}
                 className="w-full py-3 bg-white border-2 border-slate-200 hover:border-slate-400 text-slate-700 rounded-xl font-bold transition-colors flex items-center justify-center gap-3"
               >
                  <Share2 className="w-5 h-5" />
                  Jaa linkki
               </button>
             </div>
          </div>

        </div>

        <button 
          onClick={onClose}
          className="w-full py-4 bg-gray-50 border-t border-gray-100 font-semibold text-slate-600 hover:bg-gray-100 transition-colors"
        >
          Sulje
        </button>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import LZString from 'lz-string';
import { SECTIONS, DEFAULT_INTRO_TEXT, DEFAULT_ORG_SETTINGS } from './constants';
import { TaskState, TraineeQrData, Section, OrganizationSettings, TemplateRawData } from './types';
import { SectionGroup } from './components/SectionGroup';
import { storageService, AppData } from './storage';
import { SupervisorBadge } from './components/SupervisorBadge';
import { ScannerModal } from './components/ScannerModal';
import { TraineeBadge } from './components/TraineeBadge';
import { TraineeReportModal } from './components/TraineeReportModal';
import { CompletionModal } from './components/CompletionModal';
import { CertificateView } from './components/CertificateView';
import { ContentEditorModal } from './components/ContentEditorModal';
import { UserGuideModal } from './components/UserGuideModal';
import { ClearConfirmationModal } from './components/ClearConfirmationModal';
import { Printer, Flame, CheckCircle, QrCode, Trash2, UserCheck, Trophy, CircleHelp, Building2, MapPin, FileText } from 'lucide-react';

const App: React.FC = () => {
  // Data State
  const [traineeName, setTraineeName] = useState('');
  const [tasks, setTasks] = useState<Record<string, TaskState>>({});
  const [sections, setSections] = useState<Section[]>(SECTIONS);
  const [introText, setIntroText] = useState(DEFAULT_INTRO_TEXT);
  const [orgSettings, setOrgSettings] = useState<OrganizationSettings>(DEFAULT_ORG_SETTINGS);

  // UI State
  const [showSupervisorBadge, setShowSupervisorBadge] = useState(false);
  const [isSupervisorAuthenticated, setIsSupervisorAuthenticated] = useState(false); // New: Persist auth state
  const [showTraineeBadge, setShowTraineeBadge] = useState(false);
  const [showCompletionModal, setShowCompletionModal] = useState(false);
  const [showEditor, setShowEditor] = useState(false);
  const [showUserGuide, setShowUserGuide] = useState(false);
  const [showClearConfirm, setShowClearConfirm] = useState(false);
  const [isPrintingCertificate, setIsPrintingCertificate] = useState(false);

  // Keep track if we've already shown the celebration once per session to avoid annoyance
  const [hasCelebrated, setHasCelebrated] = useState(false);

  // Scan States
  const [scanningTaskId, setScanningTaskId] = useState<string | null>(null);
  const [scanningSectionId, setScanningSectionId] = useState<string | null>(null);
  const [isSupervisorScanning, setIsSupervisorScanning] = useState(false);

  const [scannedTraineeData, setScannedTraineeData] = useState<TraineeQrData | null>(null);

  // Helper to generate IDs for imported content
  const generateSlugId = (text: string, prefix: string) => {
    const slug = text.toLowerCase()
      .replace(/ä/g, 'a').replace(/ö/g, 'o').replace(/å/g, 'a')
      .replace(/[^a-z0-9]/g, '_')
      .replace(/_+/g, '_');
    return `${prefix}_${slug.substring(0, 15)}_${Math.floor(Math.random() * 1000)}`;
  };

  // Helper to Apply Template Data
  const applyTemplate = (rawData: TemplateRawData) => {
    // Un-minify sections and regenerate IDs if missing
    const newSections: Section[] = rawData.s.map((minSec, idx) => ({
      id: minSec.i || generateSlugId(minSec.t, `s${idx}`),
      title: minSec.t,
      subtitle: minSec.s,
      items: minSec.it.map((minItem, iIdx) => ({
        id: minItem.i || generateSlugId(minItem.l, `i${idx}_${iIdx}`),
        label: minItem.l
      }))
    }));

    // Save locally
    setSections(newSections);
    setIntroText(rawData.intro);

    // Persist to storage
    const currentData = storageService.load();
    const newData: AppData = {
        ...currentData,
        customSections: newSections,
        introText: rawData.intro,
        lastUpdated: new Date().toISOString()
    };
    storageService.save(newData);

    alert('Uusi perehdytysrunko aktivoitu onnistuneesti!');
  };

  // Load data on mount & Check for URL Template Params
  useEffect(() => {
    // 1. Load LocalStorage
    const data = storageService.load();
    setTraineeName(data.traineeName);
    setTasks(data.tasks);
    if (data.customSections && data.customSections.length > 0) {
      setSections(data.customSections);
    }
    if (data.introText) {
      setIntroText(data.introText);
    }
    if (data.organizationSettings) {
      setOrgSettings(data.organizationSettings);
    }

    // 2. Check for Template in URL
    const params = new URLSearchParams(window.location.search);
    const templateString = params.get('template');

    if (templateString) {
      try {
        const decompressed = LZString.decompressFromEncodedURIComponent(templateString);
        if (decompressed) {
          const rawData = JSON.parse(decompressed) as TemplateRawData;

          if (rawData && rawData.s && confirm('Linkistä löytyi uusi perehdytysrunko. Haluatko ottaa sen käyttöön? Tämä päivittää lomakkeen rakenteen.')) {
             applyTemplate(rawData);

             // Clean URL without refresh
             const newUrl = window.location.pathname;
             window.history.replaceState({}, '', newUrl);
          }
        }
      } catch (e) {
        console.error("Template load failed", e);
      }
    }
  }, []);

  // Save data on change
  const saveData = (
    newName: string, 
    newTasks: Record<string, TaskState>, 
    newSections?: Section[], 
    newIntroText?: string,
    newOrgSettings?: OrganizationSettings
  ) => {
    const data: AppData = {
      traineeName: newName,
      tasks: newTasks,
      customSections: newSections || sections,
      introText: newIntroText || introText,
      organizationSettings: newOrgSettings || orgSettings,
      lastUpdated: new Date().toISOString()
    };
    storageService.save(data);
  };

  const handleNameChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newName = e.target.value;
    setTraineeName(newName);
    saveData(newName, tasks);
  };

  const handleOrgSettingChange = (field: keyof OrganizationSettings, value: string) => {
    const newSettings = { ...orgSettings, [field]: value };
    setOrgSettings(newSettings);
    saveData(traineeName, tasks, sections, introText, newSettings);
  };

  const handleTaskChange = (taskId: string, updates: Partial<TaskState>) => {
    const newTasks = {
      ...tasks,
      [taskId]: {
        ...(tasks[taskId] || { date: '', traineeSigned: false, trainerSigned: false }),
        ...updates
      }
    };
    setTasks(newTasks);
    saveData(traineeName, newTasks);
  };

  const handleUpdateContent = (newSections: Section[], newIntroText: string) => {
    setSections(newSections);
    setIntroText(newIntroText);
    // Don't update orgSettings here, as they are now handled by the trainee in the main view
    saveData(traineeName, tasks, newSections, newIntroText, orgSettings);
  };

  // Wrapper for editor save to redirect back to supervisor menu
  const handleEditorSave = (newSections: Section[], newIntroText: string) => {
    handleUpdateContent(newSections, newIntroText);
    // Re-open supervisor menu automatically
    setShowSupervisorBadge(true);
  };

  const handleResetContent = () => {
    setSections(SECTIONS);
    setIntroText(DEFAULT_INTRO_TEXT);
    setOrgSettings(DEFAULT_ORG_SETTINGS);
    saveData(traineeName, tasks, SECTIONS, DEFAULT_INTRO_TEXT, DEFAULT_ORG_SETTINGS);
  };

  // Wrapper for editor reset to redirect back to supervisor menu
  const handleEditorReset = () => {
    handleResetContent();
    setShowSupervisorBadge(true);
  };

  const handleScanRequest = (taskId: string) => {
    setScanningTaskId(taskId);
  };

  const handleSectionScanRequest = (sectionId: string) => {
    setScanningSectionId(sectionId);
  };

  const handleSupervisorScanRequest = () => {
    setIsSupervisorScanning(true);
  };

  const handleScanSuccess = (data: any) => {
    const today = new Date().toISOString().split('T')[0];

    // Scenario 1: Trainee scanning Supervisor Signature for a SINGLE TASK
    if (scanningTaskId && data.type === 'SUPERVISOR_SIGNATURE' && data.name) {
       handleTaskChange(scanningTaskId, {
         trainerSigned: true,
         trainerName: data.name,
         date: today
       });
       setScanningTaskId(null);
    }
    // Scenario 2: Trainee scanning Supervisor Signature for a WHOLE SECTION
    else if (scanningSectionId && data.type === 'SUPERVISOR_SIGNATURE' && data.name) {
       const section = sections.find(s => s.id === scanningSectionId);
       if (section) {
         const newTasks = { ...tasks };
         section.items.forEach(item => {
           // Update each task in the section
           newTasks[item.id] = {
             ...(newTasks[item.id] || { date: '', traineeSigned: false, trainerSigned: false }),
             trainerSigned: true,
             trainerName: data.name,
             date: today
           };
         });
         setTasks(newTasks);
         saveData(traineeName, newTasks);
       }
       setScanningSectionId(null);
    }
    // Scenario 3: Supervisor scanning Trainee Progress
    else if (isSupervisorScanning && data.type === 'TRAINEE_PROGRESS') {
      setIsSupervisorScanning(false);
      setScannedTraineeData(data);
    }
    // Error / Mismatch handling
    else {
      if ((scanningTaskId || scanningSectionId) && data.type !== 'SUPERVISOR_SIGNATURE') {
         alert("Virhe: Skannasit pelastajan passin. Skannaa esimiehen kuittauskoodi.");
      }
      else if (isSupervisorScanning && data.type !== 'TRAINEE_PROGRESS') {
         alert("Virhe: Skannasit esimiehen koodin. Skannaa pelastajan passi.");
      }
    }
  };

  const closeScanner = () => {
    setScanningTaskId(null);
    setScanningSectionId(null);
    setIsSupervisorScanning(false);
  };

  // Logic to actually wipe data (called by modal)
  const performClearAll = () => {
    const currentSections = sections;
    const currentIntro = introText;
    const currentOrg = orgSettings;

    storageService.clear();

    // Reset state
    setTraineeName('');
    setTasks({});
    setHasCelebrated(false);

    // Restore structure settings (user doesn't want to lose the layout, just the data)
    setSections(currentSections);
    setIntroText(currentIntro);
    setOrgSettings(currentOrg);

    // Immediately save the structure back so it persists
    const freshData: AppData = {
        traineeName: '',
        tasks: {},
        customSections: currentSections,
        introText: currentIntro,
        organizationSettings: currentOrg,
        lastUpdated: new Date().toISOString()
    };
    storageService.save(freshData);

    setShowClearConfirm(false);
  };

  // Standard print (checklist)
  const printForm = () => {
    setIsPrintingCertificate(false);
    // Allow React to update state before printing
    setTimeout(() => window.print(), 100);
  };

  // Certificate print (diploma)
  const printCertificate = () => {
    setIsPrintingCertificate(true);
    setTimeout(() => {
      window.print();
      // Reset after print dialog closes (approximate) or let user switch back manually
      const cleanup = () => setIsPrintingCertificate(false);
      window.addEventListener('afterprint', cleanup, { once: true });
      setTimeout(cleanup, 5000); 
    }, 100);
  };

  // Calculate stats
  const stats = useMemo(() => {
    let total = 0;
    let completed = 0;
    sections.forEach(section => {
      section.items.forEach(item => {
        total++;
        const s = tasks[item.id];
        if (s && s.traineeSigned && s.trainerSigned) {
          completed++;
        }
      });
    });
    return { total, completed, percentage: total === 0 ? 0 : Math.round((completed/total) * 100) };
  }, [tasks, sections]);

  // Check for completion
  useEffect(() => {
    if (stats.percentage === 100 && !hasCelebrated && stats.total > 0) {
      setShowCompletionModal(true);
      setHasCelebrated(true);
    }
  }, [stats.percentage, hasCelebrated, stats.total]);

  // Determine date to show on certificate (today)
  const todayDate = new Date().toLocaleDateString('fi-FI');

  return (
    <>
      {/* CERTIFICATE VIEW (Only visible when printing certificate) */}
      {isPrintingCertificate && (
         <CertificateView 
           traineeName={traineeName} 
           completionDate={todayDate}
           orgSettings={orgSettings} 
         />
      )}

      {/* MAIN APP VIEW (Hidden when printing certificate) */}
      <div className={`min-h-screen bg-gray-100 print:bg-white pb-12 ${isPrintingCertificate ? 'hidden' : 'block'}`}>

        {/* Header Bar */}
        <header className="bg-primary text-white shadow-md sticky top-0 z-20 print:static print:shadow-none print:bg-white print:text-black">
          <div className="max-w-4xl mx-auto px-4 py-3 flex flex-col sm:flex-row items-center justify-between gap-4">

            {/* Logo & Title */}
            <div className="flex items-center gap-3 w-full sm:w-auto">
              <div className="bg-orange-500 p-2 rounded-lg print:hidden">
                <Flame className="w-6 h-6 text-white" />
              </div>
              <div>
                <h1 className="text-lg font-bold leading-tight">Pelastajan Perehdytys</h1>
                <p className="text-xs text-slate-300 print:hidden">Sähköinen seurantalomake</p>
              </div>
            </div>

            {/* Controls */}
            <div className="flex items-center gap-2 w-full sm:w-auto justify-end no-print overflow-x-auto pb-1 sm:pb-0">

              <button
                onClick={() => setShowUserGuide(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-700 hover:bg-slate-600 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-600 whitespace-nowrap mr-2"
                title="Käyttöohjeet"
              >
                <CircleHelp className="w-4 h-4 text-sky-300" />
                <span className="hidden sm:inline">Ohjeet</span>
              </button>

              {stats.percentage === 100 && (
                <button
                  onClick={() => setShowCompletionModal(true)}
                  className="flex items-center gap-1.5 sm:gap-2 bg-yellow-500 hover:bg-yellow-600 text-white px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors shadow-lg animate-pulse font-bold whitespace-nowrap"
                >
                  <Trophy className="w-4 h-4" />
                  <span>Valmis!</span>
                </button>
              )}

              <button
                onClick={() => setShowTraineeBadge(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-800 hover:bg-slate-700 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-700 whitespace-nowrap"
              >
                <UserCheck className="w-4 h-4 text-accent" />
                <span className="sm:hidden">Passi</span>
                <span className="hidden sm:inline">Oma Passi</span>
              </button>

              <div className="w-px h-6 bg-slate-700 mx-0.5 sm:mx-1"></div>

              <button 
                onClick={() => setShowSupervisorBadge(true)}
                className="flex items-center gap-1.5 sm:gap-2 bg-slate-800 hover:bg-slate-700 px-2 sm:px-3 py-2 rounded-lg text-xs sm:text-sm transition-colors border border-slate-700 whitespace-nowrap"
              >
                <QrCode className="w-4 h-4 text-green-400" />
                <span className="sm:hidden">Esimies</span>
                <span className="hidden sm:inline">Esimiestyökalut</span>
              </button>

              <button 
                onClick={printForm}
                className="p-2 bg-slate-800 hover:bg-slate-700 rounded-lg transition-colors text-slate-200"
                title="Tulosta PDF (Lista)"
              >
                <Printer className="w-5 h-5" />
              </button>

              <button 
                onClick={() => setShowClearConfirm(true)}
                className="p-2 bg-red-900/50 hover:bg-red-900 rounded-lg transition-colors text-red-200 ml-1 sm:ml-2"
                title="Tyhjennä lomake (säilyttää rakenteen)"
              >
                <Trash2 className="w-5 h-5" />
              </button>
            </div>
          </div>
        </header>

        <main className="max-w-4xl mx-auto px-4 py-8 print:py-0 print:px-0">

          {/* Name Input & Intro */}
          <div className="bg-white rounded-lg p-6 shadow-sm border border-gray-200 mb-6 print:border-none print:shadow-none print:p-0">

            <div className="mb-6 no-print">
              <label className="block text-xs font-bold uppercase text-slate-500 mb-2">
                Pelastajan Nimi
              </label>
              <div className="relative">
                <input
                  type="text"
                  value={traineeName}
                  onChange={handleNameChange}
                  placeholder="Kirjoita nimesi tähän..."
                  className="w-full text-lg font-bold text-slate-800 border-b-2 border-slate-200 focus:border-accent outline-none py-2 pl-9 bg-transparent transition-colors placeholder:font-normal placeholder:text-gray-300"
                />
                <UserCheck className="w-6 h-6 text-gray-400 absolute left-0 top-2" />
              </div>
            </div>

            {/* Organization Settings Input for Trainee */}
            <div className="mt-4 p-4 bg-gray-50 rounded-lg border border-gray-200 no-print mb-6">
              <h3 className="text-sm font-bold text-gray-500 uppercase mb-3 flex items-center gap-2">
                <FileText className="w-4 h-4" />
                Tiedot
              </h3>
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                <div>
                   <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Organisaatio</label>
                   <div className="relative">
                     <input 
                       type="text" 
                       value={orgSettings.name}
                       onChange={(e) => handleOrgSettingChange('name', e.target.value)}
                       className="w-full pl-7 px-3 py-2 text-sm border border-gray-300 rounded focus:ring-1 focus:ring-accent outline-none bg-white"
                       placeholder="Esim. Hyvinvointialue"
                     />
                     <Building2 className="w-3.5 h-3.5 text-gray-400 absolute left-2.5 top-2.5" />
                   </div>
                </div>
                <div>
                   <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Yksikkö</label>
                   <input 
                     type="text" 
                     value={orgSettings.subtitle}
                     onChange={(e) => handleOrgSettingChange('subtitle', e.target.value)}
                     className="w-full px-3 py-2 text-sm border border-gray-300 rounded focus:ring-1 focus:ring-accent outline-none bg-white"
                     placeholder="Esim. Pelastustoimi"
                   />
                </div>
                <div>
                   <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Paikkakunta</label>
                   <div className="relative">
                     <input 
                       type="text" 
                       value={orgSettings.city}
                       onChange={(e) => handleOrgSettingChange('city', e.target.value)}
                       className="w-full pl-7 px-3 py-2 text-sm border border-gray-300 rounded focus:ring-1 focus:ring-accent outline-none bg-white"
                       placeholder="Esim. Helsinki"
                     />
                     <MapPin className="w-3.5 h-3.5 text-gray-400 absolute left-2.5 top-2.5" />
                   </div>
                </div>
              </div>
            </div>

            <div className="prose prose-sm max-w-none text-slate-600 mb-2 print:text-xs whitespace-pre-line">
              {introText}
            </div>

            {/* Print Header */}
            <div className="hidden print:block mb-8 border-b-2 border-black pb-4">
                <span className="text-sm text-gray-500 uppercase">Pelastaja</span>
                <div className="text-2xl font-bold">{traineeName}</div>
                <div className="mt-2 text-xs text-gray-500">
                  {orgSettings.name} - {orgSettings.subtitle}
                </div>
            </div>
          </div>

          {/* Sticky Progress Bar */}
          <div className="bg-white/95 backdrop-blur rounded-lg p-4 shadow-sm border border-gray-200 mb-8 flex items-center gap-4 no-print sticky top-20 z-10 transition-shadow">
            <div className={`p-2 rounded-full ${stats.percentage === 100 ? 'bg-green-100' : 'bg-gray-100'}`}>
              <CheckCircle className={`w-6 h-6 ${stats.percentage === 100 ? 'text-green-600' : 'text-gray-400'}`} />
            </div>
            <div className="flex-1">
              <div className="flex justify-between items-end mb-1">
                <span className="font-bold text-slate-700">Edistyminen</span>
                <span className="text-sm font-medium text-accent">{stats.completed} / {stats.total} ({stats.percentage}%)</span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2.5">
                <div 
                  className={`h-2.5 rounded-full transition-all duration-700 ${stats.percentage === 100 ? 'bg-green-500' : 'bg-accent'}`}
                  style={{ width: `${stats.percentage}%` }}
                ></div>
              </div>
            </div>
          </div>

          {/* Form Sections (Using state 'sections' instead of constant 'SECTIONS') */}
          <div className="space-y-4">
            {sections.map(section => (
              <SectionGroup 
                key={section.id} 
                section={section} 
                tasks={tasks} 
                traineeName={traineeName}
                onTaskChange={handleTaskChange}
                onScanRequest={handleScanRequest}
                onSectionScanRequest={handleSectionScanRequest}
              />
            ))}
          </div>

          {/* Print Signature Box (Only for list view) */}
          <div className="hidden print:block mt-8 pt-8 border-t-2 border-black page-break">
            {/* Signatures removed per request for the checklist printout, kept simple */}
            <div className="text-center text-xs text-gray-500">
              Tulostettu: {todayDate} - {orgSettings.city}
            </div>
          </div>

        </main>

        {/* Modals */}
        {showClearConfirm && (
          <ClearConfirmationModal 
            onConfirm={performClearAll} 
            onClose={() => setShowClearConfirm(false)} 
          />
        )}

        {showSupervisorBadge && (
          <SupervisorBadge 
            onClose={() => {
              setShowSupervisorBadge(false);
              setIsSupervisorAuthenticated(false);
            }} 
            onScanRequest={() => {
              setShowSupervisorBadge(false);
              handleSupervisorScanRequest();
            }}
            onEditContent={() => {
              setShowSupervisorBadge(false);
              setShowEditor(true);
            }}
            currentSections={sections}
            currentIntroText={introText}
            isAuthenticated={isSupervisorAuthenticated} // Pass auth state
            onLogin={() => setIsSupervisorAuthenticated(true)} // Handle login
          />
        )}

        {showEditor && (
          <ContentEditorModal 
            initialSections={sections}
            initialIntroText={introText}
            onSave={handleEditorSave} // Use wrapper
            onReset={handleEditorReset} // Use wrapper
            onClose={() => setShowEditor(false)}
          />
        )}

        {showUserGuide && (
          <UserGuideModal onClose={() => setShowUserGuide(false)} />
        )}

        {showTraineeBadge && (
          <TraineeBadge 
            traineeName={traineeName}
            tasks={tasks}
            onClose={() => setShowTraineeBadge(false)}
          />
        )}

        {scannedTraineeData && (
          <TraineeReportModal 
            data={scannedTraineeData}
            onClose={() => setScannedTraineeData(null)}
          />
        )}

        {showCompletionModal && (
          <CompletionModal
            traineeName={traineeName}
            onClose={() => setShowCompletionModal(false)}
            onPrint={printCertificate} 
          />
        )}

        {(scanningTaskId || scanningSectionId || isSupervisorScanning) && (
          <ScannerModal 
            onScanSuccess={handleScanSuccess} 
            onClose={closeScanner} 
          />
        )}

      </div>
    </>
  );
};

export default App;

import React, { useEffect, useState } from 'react';
import QRCode from 'qrcode';
import LZString from 'lz-string';
import { X, ShieldCheck, UserPen, Lock, KeyRound, Download, ScanLine, FilePenLine, Share2, Copy, Check, Link } from 'lucide-react';
import { Section, TemplateRawData } from '../types';

interface SupervisorBadgeProps {
  onClose: () => void;
  onScanRequest: () => void;
  onEditContent: () => void;
  currentSections: Section[];
  currentIntroText: string;
  isAuthenticated: boolean;
  onLogin: () => void;
}

export const SupervisorBadge: React.FC<SupervisorBadgeProps> = ({ 
  onClose, 
  onScanRequest, 
  onEditContent,
  currentSections,
  currentIntroText,
  isAuthenticated,
  onLogin
}) => {
  const [passwordInput, setPasswordInput] = useState('');
  const [error, setError] = useState(false);

  const [name, setName] = useState('');
  const [qrUrl, setQrUrl] = useState<string>('');

  // State for Template Sharing
  const [showShareModal, setShowShareModal] = useState(false);
  const [shareUrl, setShareUrl] = useState<string>('');
  const [copied, setCopied] = useState(false);

  // Effect for Supervisor Signature QR
  useEffect(() => {
    if (!name.trim()) {
      setQrUrl('');
      return;
    }

    const signaturePayload = JSON.stringify({
      type: 'SUPERVISOR_SIGNATURE',
      name: name.trim(),
      timestamp: Date.now()
    });

    QRCode.toDataURL(signaturePayload, { width: 400, margin: 2 })
      .then((url) => {
        setQrUrl(url);
      })
      .catch((err) => {
        console.error("QR Generation failed", err);
      });
  }, [name]);

  // Generate Share URL when modal opens
  useEffect(() => {
    if (showShareModal) {
      try {
        // 1. Minify data structure
        const minifiedSections = currentSections.map(sec => {
          const sObj: any = {
            t: sec.title,
            it: sec.items.map(item => ({
              l: item.label
            }))
          };
          if (sec.subtitle) sObj.s = sec.subtitle;
          return sObj;
        });

        const rawData: TemplateRawData = {
          intro: currentIntroText,
          s: minifiedSections
        };

        const jsonString = JSON.stringify(rawData);

        // 2. Compress using compressToEncodedURIComponent for safe URL usage
        const compressed = LZString.compressToEncodedURIComponent(jsonString);

        // 3. Construct URL
        const baseUrl = window.location.href.split('?')[0];
        const fullUrl = `${baseUrl}?template=${compressed}`;

        setShareUrl(fullUrl);
      } catch (e) {
        console.error("Compression failed", e);
        setShareUrl("Virhe linkin luonnissa.");
      }
    }
  }, [showShareModal, currentSections, currentIntroText]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === '112') {
        onLogin();
        setError(false);
    } else {
        setError(true);
        setPasswordInput('');
    }
  };

  const handleDownload = (url: string, filenamePrefix: string) => {
    if (!url) return;
    const link = document.createElement('a');
    link.href = url;
    const safeName = name.replace(/[^a-z0-9]/gi, '_').toLowerCase() || 'template';
    link.download = `perehdytys-${filenamePrefix}-${safeName}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleStartScan = () => {
    onScanRequest();
  };

  const handleStartEdit = () => {
    onEditContent();
  };

  const copyToClipboard = async () => {
    try {
      await navigator.clipboard.writeText(shareUrl);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch (err) {
      console.error('Failed to copy', err);
    }
  };

  const shareNative = async () => {
    if (navigator.share) {
      try {
        await navigator.share({
          title: 'Perehdytysrunko',
          text: 'Tässä on päivitetty perehdytysrunko.',
          url: shareUrl,
        });
      } catch (err) {
        console.log('Share canceled');
      }
    } else {
      copyToClipboard();
    }
  };

  if (!isAuthenticated) {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
        <div className="bg-white rounded-2xl w-full max-w-sm overflow-hidden shadow-2xl animate-in fade-in zoom-in duration-200">
          <div className="bg-slate-800 p-4 flex justify-between items-center text-white">
            <div className="flex items-center gap-2">
              <Lock className="w-5 h-5 text-orange-400" />
              <h3 className="font-bold">Esimieskirjautuminen</h3>
            </div>
            <button onClick={onClose} className="p-1 hover:bg-slate-700 rounded-full transition-colors">
              <X className="w-5 h-5" />
            </button>
          </div>

          <form onSubmit={handleLogin} className="p-6 space-y-4">
            <div>
              <label className="block text-xs font-bold uppercase text-gray-500 mb-2">
                Salasana
              </label>
              <div className="relative">
                <input 
                  type="password" 
                  value={passwordInput}
                  onChange={(e) => setPasswordInput(e.target.value)}
                  className={`w-full pl-10 pr-4 py-2 border-2 rounded-lg outline-none transition-colors ${error ? 'border-red-300 focus:border-red-500' : 'border-slate-200 focus:border-slate-800'}`}
                  autoFocus
                  placeholder="Syötä salasana"
                />
                <KeyRound className="w-5 h-5 text-gray-400 absolute left-3 top-2.5" />
              </div>
              {error && (
                <p className="text-red-500 text-xs mt-2 font-medium">
                  Väärä salasana. Yritä uudelleen.
                </p>
              )}
            </div>

            <button 
              type="submit"
              className="w-full py-3 bg-slate-800 text-white rounded-lg font-bold hover:bg-slate-700 transition-colors shadow-lg shadow-slate-900/20"
            >
              Kirjaudu
            </button>
          </form>
        </div>
      </div>
    );
  }

  // --- SHARE URL VIEW ---
  if (showShareModal) {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
        <div className="bg-white rounded-2xl w-full max-w-lg overflow-hidden shadow-2xl animate-in fade-in zoom-in duration-200 flex flex-col max-h-[90vh]">
          <div className="bg-slate-800 p-4 flex justify-between items-center text-white shrink-0">
            <div className="flex items-center gap-2">
              <Link className="w-5 h-5 text-accent" />
              <h3 className="font-bold">Jaa perehdytysrunko linkillä</h3>
            </div>
            <button onClick={() => setShowShareModal(false)} className="p-1 hover:bg-slate-700 rounded-full transition-colors">
              <X className="w-5 h-5" />
            </button>
          </div>

          <div className="p-6 space-y-6">
             <div className="bg-blue-50 border border-blue-100 p-4 rounded-lg text-sm text-blue-900">
               Lähetä tämä linkki pelastajalle (esim. WhatsApp tai sähköposti). Kun pelastaja avaa linkin omalla laitteellaan, sovellus päivittää perehdytysrungon automaattisesti.
             </div>

             <div>
               <label className="block text-xs font-bold uppercase text-gray-500 mb-2">
                 Jako-linkki
               </label>
               <div className="flex gap-2">
                 <input 
                   type="text" 
                   readOnly 
                   value={shareUrl} 
                   className="flex-1 px-3 py-2 border rounded-lg bg-gray-50 text-gray-600 text-sm focus:outline-none"
                 />
                 <button 
                   onClick={copyToClipboard}
                   className={`px-4 py-2 rounded-lg font-bold transition-all flex items-center gap-2 ${copied ? 'bg-green-500 text-white' : 'bg-gray-200 text-gray-700 hover:bg-gray-300'}`}
                 >
                   {copied ? <Check className="w-4 h-4" /> : <Copy className="w-4 h-4" />}
                   {copied ? 'Kopioitu' : 'Kopioi'}
                 </button>
               </div>
             </div>

             <button 
               onClick={shareNative}
               className="w-full py-4 bg-accent text-white rounded-xl font-bold hover:bg-sky-600 flex items-center justify-center gap-2 shadow-lg shadow-sky-500/20"
             >
               <Share2 className="w-5 h-5" />
               Jaa sovellukseen...
             </button>
          </div>

          <div className="p-4 border-t border-gray-100 bg-gray-50">
            <button 
              onClick={() => setShowShareModal(false)}
              className="w-full py-3 bg-white border border-gray-300 text-slate-700 rounded-lg font-bold hover:bg-gray-100"
            >
              Sulje
            </button>
          </div>
        </div>
      </div>
    );
  }

  // --- MAIN MENU VIEW ---
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl w-full max-w-sm overflow-hidden shadow-2xl animate-in fade-in zoom-in duration-200">

        <div className="bg-slate-800 p-4 flex justify-between items-center text-white">
          <div className="flex items-center gap-2">
            <ShieldCheck className="w-5 h-5 text-green-400" />
            <h3 className="font-bold">Esimiehen Työkalut</h3>
          </div>
          <button onClick={onClose} className="p-1 hover:bg-slate-700 rounded-full transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="p-6 space-y-8 max-h-[80vh] overflow-y-auto">

          {/* Section 1: Generate Supervisor ID */}
          <div className="space-y-4">
            <h4 className="text-sm font-bold uppercase text-slate-500 border-b pb-1">1. Esimiehen Tunniste</h4>

            <div className="w-full">
              <label className="block text-xs font-bold text-gray-400 mb-2">
                Esimiehen Nimi
              </label>
              <div className="relative">
                <input 
                  type="text" 
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  placeholder="Esim. Matti Meikäläinen"
                  className="w-full pl-10 pr-4 py-2 border-2 border-slate-200 rounded-lg focus:border-slate-800 outline-none transition-colors"
                />
                <UserPen className="w-5 h-5 text-gray-400 absolute left-3 top-2.5" />
              </div>
            </div>

            <div className={`p-4 bg-white border-2 rounded-xl flex items-center justify-center transition-all duration-300 ${qrUrl ? 'border-green-500 shadow-sm' : 'border-gray-100 bg-gray-50'}`}>
              {qrUrl ? (
                <div className="text-center space-y-2">
                    <img src={qrUrl} alt="Esimiehen QR-koodi" className="w-32 h-32 mx-auto" />
                    <button 
                        onClick={() => handleDownload(qrUrl, 'esimies')}
                        className="text-xs flex items-center justify-center gap-1 text-slate-500 hover:text-slate-800 mx-auto"
                    >
                        <Download className="w-3 h-3" /> Tallenna kuva
                    </button>
                </div>
              ) : (
                <div className="w-32 h-32 flex items-center justify-center text-gray-300 text-xs italic">
                  Kirjoita nimi...
                </div>
              )}
            </div>
          </div>

          {/* Section 2: Scan Trainee */}
          <div className="space-y-4">
             <h4 className="text-sm font-bold uppercase text-slate-500 border-b pb-1">2. Tarkista Pelastaja</h4>
             <button
               onClick={handleStartScan}
               className="w-full py-3 bg-accent hover:bg-sky-600 text-white rounded-xl font-bold transition-colors flex items-center justify-center gap-3 shadow-lg shadow-sky-500/20"
             >
                <ScanLine className="w-5 h-5" />
                Tarkista Pelastajan Passi
             </button>
          </div>

          {/* Section 3: Edit Form */}
          <div className="space-y-4">
             <h4 className="text-sm font-bold uppercase text-slate-500 border-b pb-1">3. Hallinta</h4>
             <div className="bg-gray-50 rounded-xl p-4 border border-gray-100 space-y-3">
               <p className="text-xs text-gray-500 text-center">
                 Muokkaa lomakkeen rakennetta ja jaa se pelastajalle.
               </p>

               <button
                 onClick={handleStartEdit}
                 className="w-full py-3 bg-white border-2 border-slate-200 hover:border-slate-400 text-slate-700 rounded-xl font-bold transition-colors flex items-center justify-center gap-3"
               >
                  <FilePenLine className="w-5 h-5" />
                  Muokkaa runkoa
               </button>

               <button
                 onClick={() => setShowShareModal(true)}
                 className="w-full py-3 bg-white border-2 border-slate-200 hover:border-slate-400 text-slate-700 rounded-xl font-bold transition-colors flex items-center justify-center gap-3"
               >
                  <Share2 className="w-5 h-5" />
                  Jaa linkki
               </button>
             </div>
          </div>

        </div>

        <button 
          onClick={onClose}
          className="w-full py-4 bg-gray-50 border-t border-gray-100 font-semibold text-slate-600 hover:bg-gray-100 transition-colors"
        >
          Sulje
        </button>
      </div>
    </div>
